/// A manuscript-only Markdown export detached from the live editor so Save a
/// Copy can finish after the asynchronous path prompt. Embedded assets travel
/// with it; destination-specific relative links are written in `write_to`.
struct MarkdownExport {
    markdown: String,
    assets: Vec<ExportAsset>,
}

struct ExportAsset {
    source_id: String,
    file_name: String,
    bytes: Vec<u8>,
}

const RICH_CLIPBOARD_VERSION: u8 = 1;

/// Metadata on the clipboard's plain String entry. `text_len` is the guard
/// against clipboard managers that rewrite the visible flavor but retain our
/// private metadata. Asset ids map, in order, to sibling bitmap entries.
#[derive(Debug, Clone, Serialize, Deserialize)]
struct RichClipboardEnvelope {
    v: u8,
    text_len: usize,
    rich: RichPaste,
    image_asset_ids: Vec<String>,
}

/// Read the plain flavor and, unless explicitly bypassed, its still-matching
/// private operation. Validate against the untouched clipboard bytes before
/// normalizing CRLF for insertion: a clipboard manager rewrite must make the
/// rich half ineligible, never accidentally repair its guard.
fn clipboard_text_and_rich(
    item: &ClipboardItem,
    plain: bool,
) -> Option<(String, Option<RichPaste>)> {
    let text = item.entries.iter().find_map(|entry| match entry {
        ClipboardEntry::String(text) => Some(text),
        _ => None,
    })?;
    let rich = (!plain).then(|| {
        text.metadata.as_deref().and_then(|metadata| {
            serde_json::from_str::<RichClipboardEnvelope>(metadata).ok().filter(|payload| {
                payload.v == RICH_CLIPBOARD_VERSION && payload.text_len == text.text().len()
            }).map(|payload| payload.rich)
        })
    }).flatten();
    Some((text.text().replace("\r\n", "\n"), rich))
}

impl ExportAsset {
    fn from_untrusted_id(source_id: &str, bytes: Vec<u8>, index: usize) -> Self {
        Self {
            source_id: source_id.to_owned(),
            file_name: format!(
                "asset-{}.{}",
                index + 1,
                safe_asset_extension(source_id).to_ascii_lowercase()
            ),
            bytes,
        }
    }
}

#[derive(Clone, Copy, Eq, PartialEq)]
struct SaveRevision(u64);

struct PendingSave {
    generation: SaveGeneration,
    revision: SaveRevision,
}

struct LatestSave<T> {
    pending: Option<T>,
}

impl<T> Default for LatestSave<T> {
    fn default() -> Self {
        Self { pending: None }
    }
}

impl<T> LatestSave<T> {
    fn queued(&mut self, pending: T) {
        self.pending = Some(pending);
    }

    fn preparation_failed(&mut self) {
        // A completion for an older snapshot must not be allowed to clear the
        // newest attempt's error or cancel its retry.
        self.pending = None;
    }

    fn is_none(&self) -> bool {
        self.pending.is_none()
    }

    fn is_some(&self) -> bool {
        self.pending.is_some()
    }

    fn as_ref(&self) -> Option<&T> {
        self.pending.as_ref()
    }

    fn take(&mut self) -> Option<T> {
        self.pending.take()
    }
}

/// A std-only async doorbell between the strop-save worker thread and the
/// GPUI foreground: the worker rings it after posting each completion
/// (`SaveWorker::with_notify`), and a foreground task parked on `wait`
/// wakes to drain — so a finished final write closes the quit-guarded
/// window in milliseconds instead of idling until the next 1s heartbeat
/// tick. The flag latches, so a ring before anyone listens is never lost.
#[derive(Default)]
struct SaveWake {
    rung: std::sync::atomic::AtomicBool,
    waker: std::sync::Mutex<Option<std::task::Waker>>,
}

impl SaveWake {
    fn ring(&self) {
        self.rung.store(true, std::sync::atomic::Ordering::SeqCst);
        if let Some(waker) = self.waker.lock().unwrap().take() {
            waker.wake();
        }
    }

    fn wait(self: &Arc<Self>) -> SaveWakeWait {
        SaveWakeWait(self.clone())
    }
}

struct SaveWakeWait(Arc<SaveWake>);

impl std::future::Future for SaveWakeWait {
    type Output = ();

    fn poll(
        self: std::pin::Pin<&mut Self>,
        cx: &mut std::task::Context<'_>,
    ) -> std::task::Poll<()> {
        use std::sync::atomic::Ordering;
        if self.0.rung.swap(false, Ordering::SeqCst) {
            return std::task::Poll::Ready(());
        }
        *self.0.waker.lock().unwrap() = Some(cx.waker().clone());
        // Re-check AFTER parking the waker: a ring that raced the store
        // above sees no waker to wake, and would otherwise sleep forever.
        if self.0.rung.swap(false, Ordering::SeqCst) {
            std::task::Poll::Ready(())
        } else {
            std::task::Poll::Pending
        }
    }
}

fn safe_asset_extension(id: &str) -> &str {
    id.rsplit_once('.')
        .map(|(_, ext)| ext)
        .filter(|ext| {
            !ext.is_empty() && ext.len() <= 10 && ext.bytes().all(|b| b.is_ascii_alphanumeric())
        })
        .unwrap_or("bin")
}

#[derive(Default)]
enum QuitGuard {
    #[default]
    Idle,
    Saving,
    Failed(String),
    SavingCopy,
    Bypass,
}

impl MarkdownExport {
    fn prepare(doc: &Document, store: &Store) -> Self {
        let (text, spans, blocks) = doc.manuscript_slice();
        let markdown = strop_core::markdown::to_markdown(&text, &spans, &blocks);
        let mut seen = HashSet::new();
        let mut assets = Vec::new();
        for id in blocks.asset_refs() {
            if !seen.insert(id.to_owned()) {
                continue;
            }
            let Some(bytes) = store.get_asset(id) else { continue };
            // The source id belongs to the document and is untrusted. Only a
            // generated basename reaches `Path::join`; the id is retained
            // solely for exact Markdown-link replacement.
            assets.push(ExportAsset::from_untrusted_id(id, bytes, assets.len()));
        }
        Self { markdown, assets }
    }

    fn write_to(mut self, path: &std::path::Path) -> std::io::Result<()> {
        if !self.assets.is_empty() {
            let stem = path
                .file_stem()
                .and_then(|s| s.to_str())
                .unwrap_or("doc")
                .to_owned();
            let dir = path.with_file_name(format!("{stem}.assets"));
            std::fs::create_dir_all(&dir)?;
            for asset in self.assets {
                std::fs::write(dir.join(&asset.file_name), asset.bytes)?;
                let rel = format!("{stem}.assets/{}", asset.file_name);
                self.markdown = self
                    .markdown
                    .replace(&format!("]({})", asset.source_id), &format!("]({rel})"));
            }
        }
        std::fs::write(path, self.markdown)
    }
}

