    /// Attach the durable store and start the idle-save heartbeat: edits
    /// mirror into Loro immediately, the snapshot hits disk once typing
    /// pauses for a second (and on quit, via `save_now`).
    pub fn attach_store(&mut self, store: Store, cx: &mut Context<Self>) {
        let legacy = !store.checkpoints_materialized();
        self.store = Some(store);
        // Completions drain the moment they arrive (quit guard b): the
        // worker thread rings the doorbell, the task below wakes on the
        // foreground and drains — a fast final write closes a quit-guarded
        // window in milliseconds. The 1s heartbeat keeps draining too, as
        // the belt under this suspender.
        let wake = Arc::new(SaveWake::default());
        let bell = wake.clone();
        self.save_worker = Some(SaveWorker::with_notify(move || bell.ring()));
        cx.spawn(async move |this, cx| {
            loop {
                wake.wait().await;
                let alive = this.update(cx, |editor: &mut Editor, cx| {
                    let error_before = editor.save_error.clone();
                    editor.drain_save_completions();
                    editor.finish_quit_if_ready(cx);
                    // Repaint only when the drain changed something the
                    // writer can see; routine autosaves stay invisible.
                    if editor.save_error != error_before
                        || !matches!(editor.quit_guard, QuitGuard::Idle)
                    {
                        cx.notify();
                    }
                });
                if alive.is_err() {
                    break;
                }
            }
        })
        .detach();
        // Heal a legacy file without waiting for the writer to open history:
        // materialize its checkpoint states in the background now, so the
        // sidebar is instant whenever it IS opened — and the next open of
        // the file can compact the oplog (Store::open) it no longer needs.
        if legacy {
            self.backfill_checkpoint_states(cx);
        }
        cx.spawn(async move |this, cx| {
            loop {
                cx.background_executor()
                    .timer(Duration::from_millis(1000))
                    .await;
                let alive = this.update(cx, |editor: &mut Editor, cx| {
                    editor.drain_save_completions();
                    editor.finish_quit_if_ready(cx);
                    // Keystroke-durability for the open note composer: mirror
                    // its live draft onto the note every tick so a crash never
                    // loses what's been typed. Every other field in the app is
                    // already keystroke-durable; the composer was the lone
                    // RAM-only one (it wrote to the doc only on Enter-commit).
                    editor.sync_active_note_draft(cx);
                    if editor.store_dirty
                        && editor.latest_save.is_none()
                        && editor.last_input.elapsed() >= Duration::from_secs(1)
                        && editor.save_retry_at.is_none_or(|at| Instant::now() >= at)
                    {
                        let _ = editor.save_now();
                    }
                    // Idle gap seals a writing session — checkpoints are
                    // navigation markers for "a sitting", not safety.
                    if editor.dirty_since_checkpoint
                        && editor.last_input.elapsed() >= Duration::from_secs(900)
                        && let Some(store) = &editor.store
                    {
                        store.add_checkpoint_if_changed("Session", false);
                        editor.dirty_since_checkpoint = false;
                    }
                });
                if alive.is_err() {
                    break;
                }
            }
        })
        .detach();
    }

    /// Lazy birth, staged (main.rs, the .md import path): the store stays
    /// an empty doc over a missing file, and this holds what the import
    /// read. Must be called before the writer can act — main stages it in
    /// the same closure that attaches the store.
    pub fn stage_import_birth(&mut self, text: String, spans: SpanSet, blocks: BlockMap) {
        self.pending_birth = Some((text, spans, blocks));
    }

    /// The moment of birth: the first persistent mutation seeds the store
    /// with the IMPORTED state and seals "Started" — the checkpoint the
    /// journal-era strip anchors on (without it the record believes the doc
    /// began empty, and a scrub past the first keystroke replays an
    /// imported novel away). Until this runs, nothing exists on disk and
    /// `save_now` refuses to write; a no-edit open quits byte-identical.
    /// Idempotent — every caller past the first is a no-op.
    fn materialize_store(&mut self) {
        if self.store.is_none() {
            return; // storeless (smoke): the birth state stays parked
        }
        let Some((text, spans, blocks)) = self.pending_birth.take() else { return };
        let store = self.store.as_ref().expect("checked just above");
        store.seed(&text);
        store.seal_session_with("Started", false, (text, spans, blocks));
    }

    /// The single "the document changed, it must be saved" chokepoint. Every
    /// mutation site routes through here instead of poking `store_dirty`
    /// directly, so no field can silently skip persistence the way the note
    /// composer once did. Keep this the ONLY place that sets the flag true.
    fn mark_dirty(&mut self) {
        // A persistent mutation is exactly what ends lazy birth — cards,
        // goals and every other non-text channel route through here, so an
        // unborn import materializes before its first save can be gated.
        self.materialize_store();
        self.store_dirty = true;
        self.save_revision.0 = self
            .save_revision
            .0
            .checked_add(1)
            .expect("document save revision overflow");
        // A fresh edit is useful new information: try it promptly after the
        // ordinary one-second idle lull, even if an older attempt backed off.
        self.save_retry_at = None;
    }

    /// Fan buffer changes out to every offset-tracking consumer (formatting
    /// spans, durable store). Must run after every mutation.
    /// Words in the MANUSCRIPT only — the compost rail is excluded (asides.md
    /// §1: "the accounting does not bleed"). Slicing by char range avoids
    /// cloning the text; `manuscript_char_range` is the whole doc when there is
    /// no rail.
    fn manuscript_word_count(&self) -> usize {
        count_words(self.doc.rope().slice(self.doc.manuscript_char_range()).chunks())
    }

    /// Words in the Scraps pile — the seam row's live count, the footer
    /// chip's count, and the caret-scoped count control ("scraps · N").
    /// 0 with no seam (and for a textless pile held by the retype guard).
    fn scraps_word_count(&self) -> usize {
        match self.doc.scraps_char_range() {
            Some(r) => count_words(self.doc.rope().slice(r).chunks()),
            None => 0,
        }
    }

    /// The count control's caret-scoped text (P12; scopes-search 5): in the
    /// pile it reads "scraps · N" alone; in the piece, "piece · N" — but the
    /// "piece ·" prefix exists only once a seam does (no vocabulary before
    /// its referent, P4): a seamless doc says "N words" as it always has.
    /// The chrome count and the seam count visibly sum.
    /// The chip counts the PIECE, always (owner's call, 2026-07-11): the
    /// caret-scoped "piece · N"/"scraps · N" label spent always-visible bar
    /// space on a fact the page already shows — the Scraps delineation
    /// header carries the pile's own live count — and it hid the session
    /// goal whenever the caret wandered below the seam. One region, one
    /// instrument: the chip shows and edits the same datum in every state.
    fn count_label(&self) -> String {
        format!("{} words", format_thousands(self.word_count))
    }

    fn sync_mutations(&mut self) {
        let ops = self.doc.take_ops();
        if ops.is_empty() {
            return;
        }
        // Real buffer ops only — this stamp is what tells a live typing burst
        // from a lull (deferred_pass), so caret moves must never touch it.
        self.last_text_edit = Some(Instant::now());
        self.word_count = self.manuscript_word_count();
        // Lazy birth ends HERE, before the mirror: these ops are positioned
        // against the imported text, so the seed must land under them first
        // (applying an op at char N to an unseeded empty doc would panic).
        self.materialize_store();
        // Apply to the store before releasing the borrow, so the dirty-flag
        // chokepoint (mark_dirty) can take &mut self.
        match &self.store {
            Some(store) => store.apply(&ops),
            None => return,
        }
        self.mark_dirty();
        self.dirty_since_checkpoint = true;
        self.session_had_edits = true;
    }

    /// Mirror the open note composer's draft onto the note so the idle-save
    /// heartbeat persists it like any other keystroke. No-op (and no dirty
    /// flag) while the body is unchanged, so an idle composer doesn't force a
    /// save every tick; undo boundaries stay on the Enter-commit path.
    fn sync_active_note_draft(&mut self, cx: &mut Context<Self>) {
        // Mirror the live composer onto the note IT edits — the id and the
        // input come from the same `Composing` variant, so the draft can never
        // follow a clicked AI card or another note's anchor (that once leaked
        // the note's text onto AI cards and persisted it).
        let CardFocus::Composing { id, input } = &self.focus else {
            return;
        };
        let (id, body) = (*id, input.read(cx).content.clone());
        if self.doc.note_body(id).is_some_and(|cur| cur != body.as_str()) {
            self.doc.set_note_body_draft(id, body);
            self.mark_dirty();
        }
    }

    /// Re-enter the document where the last session left it (DESIGN §4
    /// invariant: caret restored, zero questions asked, within a second). The
    /// re-entry intent question was retired (impl 04 §1); the caret-resume half
    /// of the ritual stays — it is the only thing the sidecar now carries.
    pub fn restore_session(&mut self, entry: crate::files::SessionEntry) {
        if let Some(caret) = entry.caret {
            // Clamp to the document and snap to a char boundary (the doc
            // may have changed under us since the caret was recorded).
            let byte = self
                .doc
                .char_to_byte(self.doc.rope().byte_to_char(caret.min(self.doc.len_bytes())));
            self.selected_range = byte..byte;
            self.autoscroll_request = true;
        }
    }

    /// Quit-time bookkeeping: remember the caret so the next open resumes
    /// mid-sentence. The only thing quit records now — the intent question
    /// (and its End Session verb) is gone (impl 04 §1).
    pub fn record_exit_state(&self) {
        if cfg!(test) {
            // The quit tests drive real close paths; the caret memory
            // writes to the REAL state dir (files.rs isolates env-dependent
            // behavior in its own single sequential test) and must not
            // collect junk temp-path entries from every test run.
            return;
        }
        let Some(store) = &self.store else { return };
        crate::files::record_caret(store.path(), self.cursor_offset());
    }

    /// Load the [voice] corpus and build the self-baseline. Synchronous —
    /// essays are small; runs once at startup.
    pub fn load_voice_corpus(&mut self) {
        if self.config.voice.corpus.is_empty() {
            return;
        }
        let mut texts: Vec<String> = Vec::new();
        for pattern in &self.config.voice.corpus {
            let expanded = if let Some(rest) = pattern.strip_prefix("~/") {
                crate::paths::home_dir().join(rest).to_string_lossy().into_owned()
            } else {
                pattern.clone()
            };
            let Ok(paths) = glob::glob(&expanded) else {
                eprintln!("strop: bad corpus glob: {pattern}");
                continue;
            };
            for path in paths.flatten() {
                let text = match path.extension().and_then(|e| e.to_str()) {
                    Some("md") => std::fs::read_to_string(&path)
                        .ok()
                        .map(|md| strop_core::markdown::from_markdown(&md).0),
                    Some("strop") => Store::open_with_backup_destination(
                        &path,
                        Some(&crate::paths::migration_backups_dir()),
                    )
                        .ok()
                        .and_then(|(_, loaded)| loaded.map(|l| l.text)),
                    _ => std::fs::read_to_string(&path).ok(),
                };
                if let Some(text) = text
                    && text.split_whitespace().count() >= 200
                {
                    texts.push(text);
                }
            }
        }
        let lang = match self.config.language {
            Language::Ru => typograph::Lang::Ru,
            Language::En => typograph::Lang::En,
            Language::Auto => typograph::detect_lang(texts.join(" ").chars().take(4000)),
        };
        let n = texts.len();
        self.voice_baseline = strop_core::voice::baseline(&texts, lang);
        if self.voice_baseline.is_some() {
            eprintln!("strop: voice baseline from {n} corpus texts");
        } else if n > 0 {
            eprintln!("strop: voice corpus has {n} usable texts; need 3+");
        }
    }

    /// Restore persisted cross-session undo/redo.
    pub fn restore_history(&mut self, history: strop_core::document::History) {
        self.doc.import_history(history);
    }

    pub fn restore_annotations(&mut self, annotations: Annotations) {
        // The pass counter is transient but pass_id values persist on cards:
        // without re-seeding, a new session's pass 1 would collide with a
        // loaded card's pass_id and rest the wrong cards behind the rail.
        let max_pass = annotations.notes().iter().map(|n| n.pass_id).max();
        self.diagnosis_pass = self.diagnosis_pass.max(max_pass.unwrap_or(0));
        self.doc.set_notes(annotations);
    }

    /// Install the persisted edit-run journal at load.
    pub fn restore_journal(&mut self, journal: strop_core::journal::Journal) {
        self.doc.set_journal(journal);
    }

    /// Install the persisted graveyard at load, then recompute the manuscript
    /// word count (a loaded doc may carry a boundary that scopes it).
    pub fn restore_graveyard(&mut self, graveyard: strop_core::document::Graveyard) {
        self.doc.set_graveyard(graveyard);
        self.word_count = self.manuscript_word_count();
    }

    /// Install the persisted provenance records at load.
    pub fn restore_provenance(&mut self, provenance: strop_core::document::Provenance) {
        self.doc.set_provenance(provenance);
    }

    /// The one recorded MIGRATION (time-persistence 4; 08 §2 path 2): a
    /// shipped compost-at-top document flips to the tail era at open, before
    /// the first edit. Layered record, exactly like restore's: a "Before
    /// migration" checkpoint of the top-era present (its state is the
    /// migration's inverse — Restore of it normalizes, idempotently), the
    /// flip itself (journal-paused, one Seam event, undo stacks dropped in
    /// core), a save, and a "Migrated" checkpoint of the new geometry.
    pub fn migrate_scraps_geometry(&mut self) {
        if self.doc.aside_boundary().is_none() {
            return;
        }
        if let Some(store) = &self.store {
            store.add_checkpoint("Before migration", false);
        }
        if !self.doc.migrate_top_to_tail() {
            return;
        }
        self.sync_mutations();
        self.word_count = self.manuscript_word_count();
        let _ = self.save_now();
        if let Some(store) = &self.store {
            store.add_checkpoint("Migrated", false);
        }
        self.mark_dirty();
    }

    /// Route the palette/shortcut verb into the strip's naming composer.
    fn add_checkpoint(&mut self, _: &AddCheckpoint, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if !self.strip.open {
            self.open_strip(window, cx);
        }
        self.open_strip_name(window, cx);
    }

    fn open_strip_name(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        if self.strip_name_input.is_some() {
            return;
        }
        if self.strip.saved_sel.is_none() {
            self.strip.saved_sel = Some(self.selected_range.clone());
        }
        // Parked ON a writer-named version, the verb is Rename (§3c): the
        // composer opens holding the current name, selected — the
        // prefilled-datum idiom: typing replaces it, erasing it erases the
        // datum (an emptied commit demotes).
        let seed = self
            .strip
            .parked
            .then(|| self.strip_named_station_at(self.strip.pos_ms))
            .flatten();
        self.strip_name_target = seed.as_ref().map(|_| self.strip.pos_ms);
        let input = cx.new(|cx| match &seed {
            Some(name) => TextField::single_selected(cx, name.clone()),
            None => TextField::single(cx, String::new()),
        });
        cx.subscribe_in(
            &input,
            window,
            |editor, _, event: &TextFieldEvent, window, cx| match event {
                TextFieldEvent::Commit(name) => editor.commit_strip_name(name, window, cx),
                TextFieldEvent::Cancel => editor.cancel_strip_name(window, cx),
            },
        )
        .detach();
        cx.observe(&input, |_, _, cx| cx.notify()).detach();
        let focus = input.read(cx).focus_handle.clone();
        window.focus(&focus, cx);
        self.strip_name_input = Some(input);
        cx.notify();
    }

    fn cancel_strip_name(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        if self.strip_name_input.take().is_none() {
            return;
        }
        self.strip_name_target = None;
        if !self.strip.parked && let Some(selection) = self.strip.saved_sel.take() {
            self.selected_range = selection;
        }
        window.focus(&self.focus_handle, cx);
        cx.notify();
    }

    /// The universal blur law reaches the naming composer (corridor report,
    /// 2026-07-16: it was the ONE field in Strop that dropped its draft on
    /// focus loss). A click-away commits a non-empty draft and quietly
    /// dismisses an empty one; Esc remains the deliberate cancel. Safe to
    /// commit because naming now has its inverse — a version's name can be
    /// removed in the history panel (P13).
    fn resolve_strip_name(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let Some(input) = self.strip_name_input.as_ref() else {
            return;
        };
        let draft = input.read(cx).content.clone();
        // Create mode: an empty draft dismisses quietly. Rename mode: an
        // emptied field IS the demotion — the writer deleted the datum,
        // and blur commits what the field holds (§3c).
        if draft.trim().is_empty() && self.strip_name_target.is_none() {
            self.cancel_strip_name(window, cx);
        } else {
            self.commit_strip_name(&draft, window, cx);
        }
    }

    fn commit_strip_name(
        &mut self,
        name: &str,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        if self.commit_strip_name_core(name, cx) {
            if !self.strip.parked && let Some(selection) = self.strip.saved_sel.take() {
                self.selected_range = selection;
            }
            window.focus(&self.focus_handle, cx);
            cx.notify();
        }
    }

    /// The windowless half of the blur law: a close or departure cannot
    /// reach `window.focus`, but a typed name still commits on the way out —
    /// leaving must not shred the draft. (Focus and selection are the
    /// leaving path's own business.)
    fn resolve_strip_name_draft(&mut self, cx: &mut Context<Self>) {
        let Some(input) = self.strip_name_input.take() else {
            return;
        };
        let draft = input.read(cx).content.clone();
        if !draft.trim().is_empty() || self.strip_name_target.is_some() {
            self.commit_strip_name_core(&draft, cx);
        }
        self.strip_name_target = None;
    }

    /// Look up the writer-named station standing exactly at `pos_ms` in the
    /// current bake — the rename verb's precondition (§3c).
    fn strip_named_station_at(&self, pos_ms: i64) -> Option<String> {
        self.strip.bake.as_ref()?.stations.iter()
            .find(|s| s.at_ms == pos_ms && s.writer_named())
            .map(|s| s.label.clone())
    }

    /// Store + re-bake for a named version; true when it was actually
    /// stored. Window-free so the departure/close paths can share it.
    fn commit_strip_name_core(&mut self, name: &str, cx: &mut Context<Self>) -> bool {
        let name = name.trim();
        // Rename mode (§3c): the composer opened over an existing named
        // version. A non-empty commit renames it; an emptied one demotes it
        // to an unnamed station — the naming verb's inverse (P13). The
        // recorded state is never removed.
        if let Some(ts) = self.strip_name_target.take() {
            let Some(store) = &self.store else { return false };
            let Some(ix) = store
                .checkpoints()
                .iter()
                .rposition(|cp| cp.manual && cp.timestamp_ms() == ts)
            else {
                return false;
            };
            store.rename_checkpoint(ix, name);
            let now = self.strip.bake.as_ref().map_or(ts, |b| b.now_ms);
            self.strip_bake(now);
            self.strip_name_input = None;
            self.mark_dirty();
            cx.notify();
            return true;
        }
        if name.is_empty() {
            return false;
        }
        // Naming a version is a deliberate act of record: an unborn import
        // materializes first, so the checkpoint lands on a seeded store
        // (and after the "Started" seal, keeping the birth first).
        self.materialize_store();
        let Some(store) = &self.store else { return false };
        let before = store.checkpoints().len();
        let timestamp_ms = if self.strip.parked {
            self.strip.pos_ms
        } else {
            strop_core::journal::now_ms()
        };
        let state = if self.strip.parked {
            let Some(scratch) = self.strip.scratch.as_ref() else { return false };
            strop_core::store::CheckpointState {
                text: scratch.replay.text(),
                spans: scratch.replay.spans.clone(),
                blocks: scratch.replay.blocks.clone(),
            }
        } else {
            strop_core::store::CheckpointState {
                text: self.doc.text(),
                spans: self.doc.spans().clone(),
                blocks: self.doc.blocks().clone(),
            }
        };
        store.add_checkpoint_at(name, timestamp_ms, state);
        if store.checkpoints().len() == before {
            return false;
        }
        let now = self.strip.bake.as_ref().map_or(timestamp_ms, |b| b.now_ms);
        self.strip_bake(now);
        self.strip_name_input = None;
        self.dirty_since_checkpoint = false;
        self.mark_dirty();
        cx.notify();
        true
    }

    /// Build the rewind list from the checkpoints' MATERIALIZED states —
    /// word deltas between consecutive states and (when a self-baseline
    /// exists) per-checkpoint voice drift. Cheap (stored states + word
    /// diffs, microseconds each), but only once every checkpoint carries a
    /// state: a legacy one would fall back to a multi-second historical
    /// checkout — the old sidebar hang (71 s measured for 13 checkpoints).
    /// Callers gate on `checkpoints_materialized`.
    fn build_history_entries(&self) -> Vec<HistoryEntry> {
        let Some(store) = &self.store else {
            return Vec::new();
        };
        let mut entries: Vec<HistoryEntry> = Vec::new();
        let mut prev_text = String::new();
        for cp in store.checkpoints() {
            let Some((text, spans, blocks)) = store.checkpoint_state(&cp) else {
                continue;
            };
            let delta = strop_core::diff::word_delta(&strop_core::diff::prose_diff(
                &prev_text, &text,
            ));
            // Flag-only scalar: shown when assess() puts the checkpoint
            // outside the writer's normal range. Gated on the corpus floor
            // (200 words) — shorter states are statistical noise. The
            // signature must use the BASELINE's language (the vectors are
            // per-language and differently sized).
            let drift_sigma = self.voice_baseline.as_ref().and_then(|b| {
                if text.split_whitespace().count() < 200 {
                    return None;
                }
                let report = b.assess(&strop_core::voice::signature(&text, b.lang()));
                (report.overall_sigma > 2.).then_some(report.overall_sigma)
            });
            prev_text = text.clone();
            entries.push(HistoryEntry {
                name: cp.name.clone(),
                created_unix: cp.created_unix,
                manual: cp.manual,
                text,
                spans,
                blocks,
                delta,
                drift_sigma,
            });
        }
        entries
    }

    /// Open the rewind list. With materialized checkpoint states this is
    /// instant. A LEGACY file (checkpoints recorded before states were
    /// stored) instead shows the shell immediately — names, dates,
    /// structure — while a background pass materializes the states once,
    /// persists them into the file, and then fills in texts, deltas and the
    /// preview. The old behaviour materialized inline on the main thread.
    fn enter_history(&mut self, cx: &mut Context<Self>) {
        // The strip and the panel never open together (spec §0).
        if self.strip.open {
            if self.strip.parked || self.strip.pin_ms.is_some() {
                self.begin_strip_departure(StripDeparture::Panel, cx);
                return;
            }
            self.close_strip_now(cx);
        }
        let Some(store) = &self.store else {
            return;
        };
        let materializing = !store.checkpoints_materialized();
        let entries: Vec<HistoryEntry> = if materializing {
            store
                .checkpoints()
                .into_iter()
                .map(|cp| HistoryEntry {
                    name: cp.name,
                    created_unix: cp.created_unix,
                    manual: cp.manual,
                    text: String::new(),
                    spans: SpanSet::default(),
                    blocks: BlockMap::default(),
                    delta: (0, 0),
                    drift_sigma: None,
                })
                .collect()
        } else {
            self.build_history_entries()
        };
        if entries.is_empty() {
            return;
        }
        let selected = entries.len() - 1;
        // You land on the newest checkpoint: if it's automatic, its run
        // starts unfolded so the selected row is visible.
        let mut expanded = HashSet::new();
        if !entries[selected].manual {
            expanded.insert(auto_group_start(&entries, selected));
        }
        // The panel preview shares the strip's law: a live selection's byte
        // offsets mean nothing against a checkpoint's text — save it for the
        // exit and collapse it, or the wash paints the wrong words (P6).
        if self.strip.saved_sel.is_none() {
            self.strip.saved_sel = Some(self.selected_range.clone());
            let c = self.selected_range.end;
            self.selected_range = c..c;
        }
        self.history_view = Some(HistoryView {
            entries,
            selected,
            named_only: false,
            compare_current: false,
            expanded,
            materializing,
        });
        self.rebuild_preview();
        if materializing {
            self.backfill_checkpoint_states(cx);
        }
        cx.notify();
    }

    /// Materialize legacy checkpoints' states OFF the main thread and write
    /// them back — once per file, ever. Snapshot bytes go to a background
    /// task with its own private doc (the live one never blocks); the states
    /// come back, persist into the checkpoint records (so every later open
    /// is instant), and the sidebar, if still open, fills in.
    fn backfill_checkpoint_states(&mut self, cx: &mut Context<Self>) {
        if self.history_backfill_running {
            return;
        }
        let Some(store) = &self.store else { return };
        let Ok(bytes) = store.export_bytes() else { return };
        self.history_backfill_running = true;
        let task = cx
            .background_executor()
            .spawn(async move { Store::materialize_checkpoint_states(&bytes) });
        cx.spawn(async move |this, cx| {
            let states = task.await;
            this.update(cx, |editor: &mut Editor, cx| {
                editor.history_backfill_running = false;
                {
                    let Some(store) = &editor.store else { return };
                    for (ix, state) in states {
                        store.set_checkpoint_state(ix, state);
                    }
                }
                editor.mark_dirty();
                if editor.history_view.as_ref().is_some_and(|hv| hv.materializing) {
                    let entries = editor.build_history_entries();
                    if !entries.is_empty() {
                        if let Some(hv) = &mut editor.history_view {
                            hv.selected = hv.selected.min(entries.len() - 1);
                            hv.entries = entries;
                            hv.materializing = false;
                        }
                        editor.rebuild_preview();
                    }
                }
                cx.notify();
            })
            .ok();
        })
        .detach();
    }

    fn exit_history(&mut self, cx: &mut Context<Self>) {
        self.history_view = None;
        self.history_preview = None;
        // Leaving the panel returns the live selection (the document is
        // unchanged by a preview round-trip, so its offsets hold).
        if let Some(s) = self.strip.saved_sel.take() {
            self.selected_range = s;
        }
        cx.notify();
    }

    fn rebuild_preview(&mut self) {
        use strop_core::diff::DiffOp;
        let Some(hv) = &self.history_view else {
            self.history_preview = None;
            return;
        };
        // States still assembling in the background: nothing to diff yet
        // (the canvas keeps showing the live document until they land).
        if hv.materializing {
            self.history_preview = None;
            return;
        }
        let entry = &hv.entries[hv.selected];
        let empty_spans = SpanSet::default();
        let empty_blocks = BlockMap::default();
        let current_text;
        let (old, old_spans, old_blocks, new, new_spans, new_blocks) = if hv.compare_current {
            current_text = self.doc.text();
            (
                entry.text.as_str(),
                &entry.spans,
                &entry.blocks,
                current_text.as_str(),
                self.doc.spans(),
                self.doc.blocks(),
            )
        } else {
            let (old, old_spans, old_blocks) = match hv.selected.checked_sub(1) {
                Some(i) => {
                    let prev = &hv.entries[i];
                    (prev.text.as_str(), &prev.spans, &prev.blocks)
                }
                None => ("", &empty_spans, &empty_blocks),
            };
            (
                old,
                old_spans,
                old_blocks,
                entry.text.as_str(),
                &entry.spans,
                &entry.blocks,
            )
        };
        let new_blocks_boundary = new_blocks.boundary();

        // Byte offsets of each '\n'-separated paragraph, plus char->byte
        // span conversion for each source (live spans are char-indexed).
        let par_offsets = |text: &str| {
            let mut offs = vec![0usize];
            offs.extend(text.match_indices('\n').map(|(b, _)| b + 1));
            offs
        };
        let spans_to_bytes = |text: &str, spans: &SpanSet| {
            let mut idx: Vec<usize> = text.char_indices().map(|(b, _)| b).collect();
            idx.push(text.len());
            let b = |ci: usize| idx.get(ci).copied().unwrap_or(text.len());
            spans
                .spans()
                .iter()
                .map(|s| (b(s.range.start)..b(s.range.end), s.attr.clone()))
                .collect::<Vec<_>>()
        };
        let old_offs = par_offsets(old);
        let new_offs = par_offsets(new);
        let old_spans_b = spans_to_bytes(old, old_spans);
        let new_spans_b = spans_to_bytes(new, new_spans);

        let mut text = String::new();
        let mut inserts = Vec::new();
        let mut deletes = Vec::new();
        let mut spans_bytes: Vec<(Range<usize>, InlineAttr)> = Vec::new();
        let mut kinds: Vec<BlockKind> = Vec::new();
        for (i, b) in strop_core::diff::prose_diff_blocks(old, new).iter().enumerate() {
            if i > 0 {
                text.push('\n');
            }
            // Block style follows the newer side when it exists there.
            kinds.push(
                b.new_par
                    .and_then(|p| new_blocks.kinds().get(p))
                    .or_else(|| b.old_par.and_then(|p| old_blocks.kinds().get(p)))
                    .cloned()
                    .unwrap_or(BlockKind::Paragraph),
            );
            // Within the block, Delete segments concatenate to the old
            // paragraph and Same+Insert to the new one (byte-exact, by
            // prose_diff_blocks' contract) — walk both cursors and project
            // each source's spans onto the merged text.
            let mut old_b = b.old_par.map_or(0, |p| old_offs[p]);
            let mut new_b = b.new_par.map_or(0, |p| new_offs[p]);
            for seg in &b.segs {
                let start = text.len();
                let len = seg.text.len();
                let (src_spans, src_start) = match seg.op {
                    DiffOp::Delete => (&old_spans_b, old_b),
                    _ => (&new_spans_b, new_b),
                };
                for (r, attr) in src_spans {
                    let s = r.start.max(src_start);
                    let e = r.end.min(src_start + len);
                    if s < e {
                        spans_bytes
                            .push((start + (s - src_start)..start + (e - src_start), attr.clone()));
                    }
                }
                text.push_str(&seg.text);
                match seg.op {
                    DiffOp::Insert => {
                        inserts.push(start..text.len());
                        new_b += len;
                    }
                    DiffOp::Delete => {
                        deletes.push(start..text.len());
                        old_b += len;
                    }
                    DiffOp::Same => {
                        old_b += len;
                        new_b += len;
                    }
                }
            }
        }
        self.history_preview = Some(PreviewDoc {
            text,
            inserts,
            deletes,
            spans_bytes,
            kinds,
            // The diff of two geometries takes the NEWER side's seam
            // (time-persistence 5, same rule as the block styles above).
            boundary: new_blocks_boundary,
        });
    }

    /// Wire click-away-commits for a single-line field: the instant it loses
    /// focus, emit `Commit` so the field's own subscriber saves and tears it
    /// down — it becomes a label immediately, not at some later stray click
    /// (the low-latency rule; matches the doc-rename field). `still` re-fetches
    /// the live field, so a blur that races an Enter/Escape (already gone) is a
    /// no-op. NOT for end-session, whose Commit quits — blur there must not.
    fn commit_field_on_blur(
        &self,
        input: &Entity<TextField>,
        window: &mut Window,
        cx: &mut Context<Self>,
        still: impl Fn(&Editor) -> Option<Entity<TextField>> + 'static,
    ) {
        let handle = input.read(cx).focus_handle.clone();
        let weak = cx.entity().downgrade();
        // LAW 2 / D2: a bare focus-out is not a departure. A GENERATION counter
        // (V7b) — bumped by every focus-out AND every focus-in — supersedes the
        // old shared AtomicBool: each blur captures its own generation and its
        // timer commits only if the count is still current. A keyboard-layout
        // switch or alt-tab that returns focus bumps the count (focus-in), so
        // the pending commit is stale; and a blur/focus/blur BOUNCE can no
        // longer let the first blur's timer commit on the second blur's behalf
        // before that blur's own grace has elapsed (the AtomicBool did).
        let generation = std::sync::Arc::new(std::sync::atomic::AtomicUsize::new(0));
        {
            let generation = generation.clone();
            window
                .on_focus_in(&handle, cx, move |_window, _cx| {
                    generation.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                })
                .detach();
        }
        let still = std::rc::Rc::new(still);
        window
            .on_focus_out(&handle, cx, move |_, window, cx| {
                let Some(editor) = weak.upgrade() else { return };
                let my_gen = generation.fetch_add(1, std::sync::atomic::Ordering::Relaxed) + 1;
                let generation = generation.clone();
                let still = still.clone();
                let weak = editor.downgrade();
                window
                    .spawn(cx, async move |cx| {
                        cx.background_executor()
                            .timer(Duration::from_millis(FIELD_BLUR_GRACE_MS))
                            .await;
                        cx.update(|window, app| {
                            if generation.load(std::sync::atomic::Ordering::Relaxed) != my_gen
                                || !window.is_window_active()
                            {
                                return; // superseded, or app deactivation — not a departure
                            }
                            let Some(editor) = weak.upgrade() else { return };
                            editor.update_checked(app, |editor, cx| {
                                if let Some(field) = still(editor) {
                                    let text = field.read(cx).content.clone();
                                    field.update_checked(cx, |_, fcx| {
                                        fcx.emit(TextFieldEvent::Commit(text))
                                    });
                                }
                            });
                        })
                        .ok();
                    })
                    .detach();
            })
            .detach();
    }

    fn edit_image_alt(&mut self, block: usize, window: &mut Window, cx: &mut Context<Self>) {
        let BlockKind::Image { src, alt } = self.doc.blocks().kind(block).clone()
        else {
            return;
        };
        let input = cx.new(|cx| TextField::single(cx, alt));
        cx.subscribe_in(
            &input,
            window,
            move |editor, _, event: &TextFieldEvent, window, cx| {
                if let TextFieldEvent::Commit(new_alt) = event {
                    editor.doc.set_block_kind(
                        block,
                        BlockKind::Image {
                            src: src.clone(),
                            alt: new_alt.clone(),
                        },
                    );
                    editor.mark_dirty();
                    // A legitimate in-state mutation re-stamps the picture
                    // selection's revision guard (inline-images §8 / R3) —
                    // committing the alt must not decay the very state
                    // whose strip the writer just typed into.
                    editor.restamp_image_sel(block);
                }
                editor.alt_input = None;
                window.focus(&editor.focus_handle, cx);
                cx.notify();
            },
        )
        .detach();
        self.commit_field_on_blur(&input, window, cx, move |e| {
            e.alt_input
                .as_ref()
                .filter(|(b, _)| *b == block)
                .map(|(_, f)| f.clone())
        });
        let input_focus = input.read(cx).focus_handle.clone();
        window.focus(&input_focus, cx);
        self.alt_input = Some((block, input));
        cx.notify();
    }

    fn start_rename(&mut self, ix: usize, window: &mut Window, cx: &mut Context<Self>) {
        let Some(hv) = &self.history_view else { return };
        let seed = hv.entries[ix].name.clone();
        let input = cx.new(|cx| TextField::single(cx, seed));
        cx.subscribe_in(
            &input,
            window,
            move |editor, _, event: &TextFieldEvent, window, cx| {
                // A non-empty commit renames (and promotes an automatic
                // entry); an EMPTIED commit is the inverse verb — demotion
                // to an unnamed version (P13: naming has an inverse; the
                // recorded state itself is never removed). Emptying an
                // already-unnamed row is a no-op, so autos can't be
                // "demoted" into churn by an idle blur.
                if let TextFieldEvent::Commit(name) = event {
                    let name = name.trim();
                    let demoting = name.is_empty()
                        && editor.history_view.as_ref().is_some_and(|hv| {
                            hv.entries.get(ix).is_some_and(|e| e.manual)
                        });
                    if !name.is_empty() || demoting {
                        if let Some(store) = &editor.store {
                            store.rename_checkpoint(ix, name);
                            editor.mark_dirty();
                        }
                        if let Some(hv) = &mut editor.history_view
                            && let Some(e) = hv.entries.get_mut(ix)
                        {
                            e.name = name.to_owned();
                            e.manual = !name.is_empty();
                        }
                    }
                }
                editor.rename_input = None;
                window.focus(&editor.focus_handle, cx);
                cx.notify();
            },
        )
        .detach();
        self.commit_field_on_blur(&input, window, cx, move |e| {
            e.rename_input
                .as_ref()
                .filter(|(i, _)| *i == ix)
                .map(|(_, f)| f.clone())
        });
        let input_focus = input.read(cx).focus_handle.clone();
        window.focus(&input_focus, cx);
        self.rename_input = Some((ix, input));
        cx.notify();
    }

    fn history_select(&mut self, ix: usize, cx: &mut Context<Self>) {
        if let Some(hv) = &mut self.history_view {
            hv.selected = ix.min(hv.entries.len() - 1);
            // Arrow-stepping into a collapsed auto run unfolds it: the
            // selected row must be visible (no hidden modes, no hidden
            // selection).
            if !hv.entries[hv.selected].manual {
                hv.expanded
                    .insert(auto_group_start(&hv.entries, hv.selected));
            }
            self.rebuild_preview();
            self.scroll_top = px(0.);
            cx.notify();
        }
    }

    /// Restore the selected checkpoint: auto-checkpoint the present first
    /// (the rail narrates what happened), restore as an undoable forward
    /// edit, exit history. Reads the entry's own materialized state — the
    /// old `state_at` re-fetch here was another multi-second historical
    /// checkout for data the sidebar already held.
    fn restore_selected(&mut self, cx: &mut Context<Self>) {
        let Some(hv) = &self.history_view else { return };
        if hv.materializing {
            return; // states still assembling; the row can't restore yet
        }
        let entry = &hv.entries[hv.selected];
        let (text, spans, blocks) = (
            entry.text.clone(),
            entry.spans.clone(),
            entry.blocks.clone(),
        );
        let from_unix = entry.created_unix;
        self.restore_to_state(text, spans, blocks, from_unix, cx);
        cx.notify();
    }

    /// The shared restore mechanism (review B6, spec §2), reused by both the
    /// history panel's Restore and the strip's own. Restore is an ordinary
    /// UNDOABLE forward edit that appends nothing to the past — it destroys
    /// nothing (design §3). Its record is deliberately layered: a "Before
    /// restoring" checkpoint of the present (so this restore is itself one
    /// Restore away from undone), the wholesale swap (journal-suppressed — it
    /// would be one document-sized run), an honest `Restore` journal event,
    /// and a POST-restore "Restored" checkpoint that materializes the restored
    /// state as the reconstruction anchor (without it, `text_at(now)` would
    /// rebuild the PRE-restore document). `from_unix` is the moment copied
    /// from, in SECONDS (matching `Checkpoint.created_unix`). The caller
    /// notifies.
    fn restore_to_state(
        &mut self,
        text: String,
        spans: SpanSet,
        blocks: BlockMap,
        from_unix: i64,
        cx: &mut Context<Self>,
    ) {
        // A restore IS a document mutation: an unborn import materializes
        // before the record below snapshots the store (unreachable today —
        // pre-birth there is no history to restore FROM — but this keeps
        // the invariant local instead of relying on that distance).
        self.materialize_store();
        // Save first so the "Before restore" checkpoint materializes the
        // present exactly as it stands (see add_checkpoint). Its name is a
        // bare automatic: inlining the source version's title composed
        // writer text into a system label — P8's born-from bug class. The
        // sage arc already points at the source (P10: words don't repeat
        // what the arc says).
        let _ = self.save_now();
        let Some(store) = &self.store else { return };
        store.add_checkpoint("Before restore", false);
        self.doc.restore_state(&text, spans, blocks);
        self.selected_range = 0..0;
        self.selection_reversed = false;
        self.cursor_affinity_down = false;
        self.goal_x = None;
        self.marked_range = None;
        self.caret_attrs.clear();
        // F3: Restore exits everything, everywhere — the reading room drops
        // in the same breath as the previews below (the "nothing moved"
        // promise belongs to Esc, not to a document swap).
        self.cold_read = None;
        *self.cr_page_bounds.borrow_mut() = None;
        // The text changed for real — a selection saved at any preview's
        // entrance is void, and must not be re-applied by the exits below.
        self.strip.saved_sel = None;
        self.strip.saved_scroll = None;
        // Drops any preview (panel `history_view` OR the strip's
        // `history_preview`) so the live restored document is what shows.
        self.exit_history(cx);
        self.sync_mutations();
        let rebased = self.doc.notes().notes().to_vec();
        // A restore can orphan writer notes (reanchor sets `orphaned` when a
        // passage vanished): migrate their text to the compost (spec §3).
        self.migrate_orphans_after_restore(cx);
        // The restore's own record: the journal suppressed the wholesale
        // swap (it would be one document-sized run), so the honest event
        // carries the fact — and a POST-restore checkpoint materializes the
        // restored state as the reconstruction anchor (review B6: without
        // it, text_at(now) would rebuild the PRE-restore document).
        let len_chars = self.doc.rope().len_chars();
        let t = strop_core::journal::now_ms();
        let entries = rebased.into_iter().map(|n| {
            let disposition = if self.doc.notes().get(n.id).is_none() {
                strop_core::journal::CardDisposition::Migrated
            } else if n.orphaned {
                strop_core::journal::CardDisposition::Orphaned
            } else {
                strop_core::journal::CardDisposition::Anchored
            };
            strop_core::journal::CardRebaseEntry {
                id: n.id,
                range: n.range,
                status: n.status,
                title: n.title,
                level: n.level,
                pass_id: n.pass_id,
                orphaned: n.orphaned,
                unverified: n.unverified,
                disposition,
            }
        }).collect();
        let journal = self.doc.journal_mut();
        journal.record_event(strop_core::journal::JournalEvent::Restore {
                t,
                from_unix,
                len_chars,
            });
        journal.record_event(strop_core::journal::JournalEvent::CardsRebased { t, entries });
        // The anchor goes in BEFORE the save: one durable generation holds
        // the restored text, both events, and the materialized post-restore
        // checkpoint together — a crash between two saves must never leave
        // the record with a restore it cannot replay past.
        if let Some(store) = &self.store {
            store.add_checkpoint("Restored", false);
        }
        let _ = self.save_now();
        // F3, the strip epilogue (hoisted from `strip_restore` so EVERY
        // entrance — panel, strip, the book's Restore chip — leaves an open
        // strip unparked, snapped to now, and re-baked over the new data).
        if self.strip.open {
            let now = strop_core::journal::now_ms();
            self.strip.parked = false;
            self.strip.scrubbing = false;
            self.strip.pin_ms = None;
            self.compare_preview = None;
            self.compare_selection = None;
            self.strip.pos_ms = now;
            self.strip.scratch = None;
            self.strip.view_offset = f32::MAX; // back to the tail with the new data
            self.history_preview = None;
            self.strip_reveal_byte = None;
            self.strip_bake(now);
            cx.notify();
        }
        self.mark_dirty();
        self.bump_activity();
    }

    // -- The history strip (P1 — docs/impl/01-history-strip.md) ---------------

    /// ctrl-alt-h / the titlebar clock: toggle the strip (the new first history
    /// surface). The right-side panel stays reachable via the palette ("History
    /// panel"); the two never open together (spec §0).
    fn toggle_strip(&mut self, _: &ToggleStrip, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.strip.open {
            self.close_strip(cx);
        } else {
            self.open_strip(window, cx);
        }
    }

    fn open_strip(&mut self, _window: &mut Window, cx: &mut Context<Self>) {
        if self.strip.open {
            return;
        }
        // History freezes committed card bodies. Resolve an open composer
        // before baking so the record and its projection share one boundary.
        self.resolve_composer_draft(cx);
        // Strip and panel never coexist (spec §0): the panel yields.
        if self.history_view.is_some() {
            self.exit_history(cx);
        }
        let now = strop_core::journal::now_ms();
        self.strip.open = true;
        self.strip.saved_scroll = Some(f32::from(self.scroll_top));
        self.strip.parked = false;
        self.strip.pin_ms = None;
        self.compare_preview = None;
        self.compare_selection = None;
        self.strip.pos_ms = now;
        // Pin the view to the TAIL: the strip opens where the writer just was
        // (v1 opened on the oldest screenful, playhead off-screen right). The
        // sentinel resolves against the rail width at paint — the geometry Rc
        // is only written then.
        self.strip.view_offset = f32::MAX;
        self.strip_bake(now);
        cx.notify();
    }

    fn close_strip(&mut self, cx: &mut Context<Self>) {
        if self.strip.parked || self.strip.pin_ms.is_some() {
            self.begin_strip_departure(StripDeparture::Close, cx);
        } else {
            self.close_strip_now(cx);
        }
    }

    fn close_strip_now(&mut self, cx: &mut Context<Self>) {
        self.resolve_strip_name_draft(cx);
        self.strip_departure = None;
        self.strip.open = false;
        self.strip.parked = false;
        self.strip.scrubbing = false;
        self.strip.pin_ms = None;
        self.compare_preview = None;
        self.compare_selection = None;
        self.strip.scratch = None;
        self.strip.bake = None;
        self.strip_pulse = None;
        // Closing from a park is a return too: the live selection comes back.
        let returning_locus = if let Some(s) = self.strip.saved_sel.take() {
            self.selected_range = s;
            true
        } else {
            false
        };
        if returning_locus {
            self.restore_strip_scroll();
        } else {
            self.strip.saved_scroll = None;
        }
        // Drop any preview so the live document returns; a reveal the
        // preview never painted dies with it.
        self.history_preview = None;
        self.strip_reveal_byte = None;
        *self.strip_rail.borrow_mut() = None;
        cx.notify();
    }

    fn restore_strip_scroll(&mut self) {
        let Some(saved) = self.strip.saved_scroll.take() else { return };
        let max = self.last_frame.as_ref().map_or(px(saved), TextFrame::max_scroll);
        self.scroll_top = px(saved).clamp(px(0.), max);
        self.autoscroll_request = false;
    }

    /// Build the immutable bake from `(journal, checkpoints, cards)` and bump
    /// the session-monotonic `bakes` counter (the stability-law assertion —
    /// only open and Restore ever call this; scrubbing never does). Snapshots
    /// the checkpoint metadata so the strip never re-reads the store mid-scrub.
    fn strip_bake(&mut self, now_ms: i64) {
        let stations = self.strip_stations();
        let cards = self.strip_cards();
        let seed_len = self.strip_seed_len();
        let bake = StripBake::build(self.doc.journal(), &stations, &cards, seed_len, now_ms);
        self.strip.bake = Some(bake);
        self.strip.bakes += 1;
        self.strip.scratch = None; // re-anchor against the new bake
    }

    /// Checkpoints reduced to draw/anchor metadata (`timestamp_ms`; legacy
    /// second-resolution entries fall back inside that accessor). Word/char
    /// counts come from the ALREADY
    /// materialized state (a cheap in-memory read — no time-travel; a stateless
    /// legacy checkpoint reports 0/0 and sizes no span, per Bug A).
    fn strip_stations(&self) -> Vec<strip::StationSnap> {
        let Some(store) = &self.store else {
            return Vec::new();
        };
        store
            .checkpoints()
            .into_iter()
            .map(|cp| {
                let (words, chars) = cp
                    .state
                    .as_ref()
                    .map(|s| {
                        // Each station's count rebases against ITS OWN
                        // boundary (scopes-search 6) — accounting is
                        // manuscript-only in every era.
                        let rope = ropey::Rope::from_str(&s.text);
                        let m = strop_core::document::manuscript_range_of(&rope, &s.blocks);
                        (count_words(rope.slice(m).chunks()), s.text.chars().count())
                    })
                    .unwrap_or((0, 0));
                strip::StationSnap {
                    created_ms: cp.timestamp_ms(),
                    name: cp.name,
                    manual: cp.manual,
                    has_state: cp.state.is_some(),
                    words,
                    chars,
                }
            })
            .collect()
    }

    /// Each margin card's lifespan for its thread: raise time (the note's
    /// `created_unix` SECONDS ×1000) → its `CardClosed` event, else open to now.
    fn strip_cards(&self) -> Vec<strip::CardSnap> {
        use strop_core::journal::JournalEvent;
        let closes: HashMap<u64, (i64, bool)> = self
            .doc
            .journal()
            .events
            .iter()
            .filter_map(|e| match e {
                JournalEvent::CardClosed { t, id, resolved } => Some((*id, (*t, *resolved))),
                _ => None,
            })
            .collect();
        self.doc
            .notes()
            .notes()
            .iter()
            .map(|n| {
                let closed = closes.get(&n.id);
                strip::CardSnap {
                    id: n.id,
                    raised_ms: n.created_unix * 1000,
                    closed_ms: closed.map(|(t, _)| *t),
                    anchor: n.range.start,
                    resolved: closed.map_or(n.status == NoteStatus::Done, |(_, r)| *r),
                    kind: n.kind,
                }
            })
            .collect()
    }

    /// The document's char length at journal start (the earliest materialized
    /// checkpoint ≤ the first run), so the envelope is seeded for a doc that
    /// already held content when journaling began (else 0 — born empty).
    fn strip_seed_len(&self) -> usize {
        let Some(store) = &self.store else {
            return 0;
        };
        let Some(first) = self.doc.journal().runs.first().map(|r| r.t0) else {
            return 0;
        };
        store
            .checkpoints()
            .iter()
            .rfind(|cp| cp.timestamp_ms() <= first && cp.state.is_some())
            .and_then(|cp| cp.state.as_ref())
            .map(|s| s.text.chars().count())
            .unwrap_or(0)
    }

    /// A materialized checkpoint's state, found by its ms anchor time. Called
    /// only on re-anchor (a scrub crossing a checkpoint), never per frame.
    fn checkpoint_state_at_ms(&self, ms: i64) -> Option<(String, SpanSet, BlockMap)> {
        let store = self.store.as_ref()?;
        let cps = store.checkpoints();
        // .rev(): same-second neighbors exist by design — "Before restore"
        // and "Restored" are written moments apart, and the LATER one is the
        // truthful anchor (wave-1 review: anchoring on the earlier twin
        // rebuilt the pre-restore text right after a restore).
        let cp = cps
            .iter()
            .rev()
            .find(|cp| cp.timestamp_ms() == ms && cp.state.is_some())?;
        store.checkpoint_state(cp)
    }

    /// Park the playhead at a rail x (window coords) and begin a continuous
    /// scrub; `pin` (shift-click) drops/clears the Compare playhead instead.
    /// Is there any PAST to view? False for a document with no journal and no
    /// checkpoints beyond the present (a zero-width axis) — parking there would
    /// preview "now" and needlessly enter read-only mode (P13: no view without
    /// content). Any journaled run IS a past, however brief (the pre-floor
    /// behavior — a flat px floor also blocked real sub-minute edits, review:
    /// five-lens pass); without runs, the 1.5px floor covers the seconds-old
    /// birth checkpoint an import writes: a document born moments ago has a
    /// birth record, not a past (a legacy checkpoint era clears it at
    /// CKPT_MIN_PX per span).
    fn strip_has_past(&self) -> bool {
        let has_runs = !self.doc.journal().runs.is_empty();
        self.strip.bake.as_ref().is_some_and(|b| {
            let w = b.timeline.total_work;
            if has_runs { w > 0. } else { w > 1.5 }
        })
    }

    fn strip_park_at_x(&mut self, x: f32, y: f32, pin: bool, cx: &mut Context<Self>) {
        // §3a arbitration: named objects act exactly, most specific first —
        // stations (a deliberate mark), then threads (a card's path), then
        // dates, then the two lanes.
        let station_pos = station_hit_at(
            &self.strip_station_hits.borrow(), point(px(x), px(y)));
        if let Some(pos) = station_pos {
            if self.strip_has_past() {
                self.strip_save_live_locus();
                self.strip.parked = true;
                self.strip.scrubbing = false;
                self.strip.scrub_fabric = false;
                self.strip_scrub_to(pos, true, cx);
                self.strip_reveal_edit_at(pos);
            }
            return;
        }
        let thread_hit = self.strip_thread_hits.borrow().iter()
            .find(|hit| hit.bounds.contains(&point(px(x), px(y)))).cloned();
        if let Some(hit) = thread_hit {
            let Some(pos) = self.strip_pos_at_fabric_x(x) else { return };
            self.strip_save_live_locus();
            self.strip.parked = true;
            self.strip.scrubbing = false;
            self.strip.scrub_fabric = false;
            self.strip_scrub_to(pos, false, cx);
            let work = self.strip.bake.as_ref().map(|b| b.timeline.work_at(pos))
                .unwrap_or(hit.work0);
            let span = hit.work1 - hit.work0;
            let f = if span.abs() < f32::EPSILON { 0. } else {
                ((work - hit.work0) / span).clamp(0., 1.)
            };
            let anchor = hit.anchor0 as f32
                + (hit.anchor1 as f32 - hit.anchor0 as f32) * f;
            // Deferred: mapping this byte through `last_frame` here would
            // read the PREVIOUS moment's layout (the scrub above just
            // changed the preview) — the reveal waits for its own frame,
            // where the packed card lands beside it.
            if let Some(preview) = self.history_preview.as_ref() {
                let rope = ropey::Rope::from_str(&preview.text);
                self.strip_reveal_byte = Some(rope.char_to_byte(
                    (anchor.round().max(0.) as usize).min(rope.len_chars()),
                ));
            }
            self.past_card_focus = Some((hit.card_id, Instant::now()));
            cx.notify();
            cx.spawn(async move |this, cx| {
                cx.background_executor().timer(Duration::from_millis(700)).await;
                let _ = this.update(cx, |editor, cx| {
                    if editor.past_card_focus.is_some_and(|(id, at)| {
                        id == hit.card_id && at.elapsed() >= Duration::from_millis(650)
                    }) {
                        editor.past_card_focus = None;
                        cx.notify();
                    }
                });
            }).detach();
            return;
        }
        let date_pos = self
            .strip_date_hits
            .borrow()
            .iter()
            .find(|hit| hit.bounds.contains(&point(px(x), px(y))))
            .map(|hit| hit.at_ms);
        if let Some(pos) = date_pos {
            if self.strip_has_past() {
                self.strip_save_live_locus();
                self.strip.parked = true;
                self.strip.scrubbing = false;
                self.strip.scrub_fabric = false;
                self.strip_scrub_to(pos, true, cx);
                self.strip_reveal_edit_at(pos);
            }
            return;
        }
        // Two hit lanes, matching what each looks like (P7): the rail row and
        // everything above it is the seek bar — a click maps a FRACTION of the
        // whole history; the fabric below is the cloth itself — a click lands
        // on the moment UNDER the cursor, however the view is panned, and the
        // view never yanks away from what was just touched.
        let fabric = (*self.strip_rail.borrow())
            .is_some_and(|g| y - g.band_top > strip::RAIL_Y + 8.);
        let pos = if fabric {
            self.strip_pos_at_fabric_x(x)
        } else {
            self.strip_pos_at_rail_x(x)
        };
        let Some(pos) = pos else {
            return;
        };
        // No history → never park (the reported guard).
        if !self.strip_has_past() {
            return;
        }
        if pin {
            self.strip_toggle_pin(pos, cx);
            return;
        }
        self.strip_save_live_locus();
        self.strip.parked = true;
        self.strip.scrubbing = true;
        self.strip.scrub_fabric = fabric;
        self.strip_drag_moved = false;
        self.strip_scrub_to(pos, !fabric, cx);
    }

    /// The release detent (corridor fix 2026-07-16, amending §3a): a park
    /// that ENDS within a few work-px of a deliberate mark settles onto the
    /// mark's exact timestamp — a named version beats the half-sentence
    /// thirty seconds after it. The DRAG stays continuous (the live preview
    /// keeps its exactness under the hand); only the release settles, so the
    /// cloth contract holds while deliberate moments win the landing.
    fn strip_settle_ms(&self, pos_ms: i64) -> i64 {
        // Comparing is fine forensics — B often needs the moment just
        // beside a mark, so the detent stands down while a pin is set
        // (corridor round two). The rescue visit keeps it.
        if self.strip.pin_ms.is_some() {
            return pos_ms;
        }
        let Some(bake) = self.strip.bake.as_ref() else {
            return pos_ms;
        };
        let (station_snap_px, now_snap_px) = strip_snap_radii();
        let w = bake.timeline.work_at(pos_ms);
        let station = bake.stations
            .iter()
            .map(|s| (s.at_ms, (bake.timeline.work_at(s.at_ms) - w).abs()))
            .filter(|(_, d)| *d <= station_snap_px)
            .min_by(|a, b| a.1.total_cmp(&b.1));
        let now_d = (bake.timeline.total_work - w).abs();
        if now_d <= now_snap_px
            && station.is_none_or(|(_, station_d)| now_d < station_d)
        {
            bake.now_ms
        } else {
            station.map_or(pos_ms, |(ms, _)| ms)
        }
    }

    /// One discrete pointer park = one reveal (§3a, corridor round three):
    /// scroll the preview to where the WRITING was at the parked moment —
    /// the run under t, its chars interpolated through the interior, or the
    /// latest run before it. A drag never reveals (the writer parked her
    /// eyes on a passage to watch it change under the scrub); keyboard
    /// steps don't either — the hand that points gets taken there, the keys
    /// that nudge keep the eye still. Deferred to the parked layout's own
    /// frame via `strip_reveal_byte`.
    fn strip_reveal_edit_at(&mut self, pos_ms: i64) {
        let ch = self
            .doc
            .journal()
            .runs
            .iter()
            .take_while(|r| r.t0 <= pos_ms)
            .last()
            .map(|r| {
                let ins = r.ins.chars().count();
                if pos_ms >= r.t1 {
                    r.pos + ins
                } else {
                    let span = (r.t1 - r.t0).max(1) as f32;
                    let f = ((pos_ms - r.t0) as f32 / span).clamp(0., 1.);
                    r.pos + (ins as f32 * f) as usize
                }
            });
        let (Some(ch), Some(preview)) = (ch, self.history_preview.as_ref()) else {
            return;
        };
        let rope = ropey::Rope::from_str(&preview.text);
        self.strip_reveal_byte = Some(rope.char_to_byte(ch.min(rope.len_chars())));
    }

    /// Map a rail x (window coords) → fraction of the WHOLE history → wall ms.
    /// The thumb travels `min(total_work, rail_width)` (design §1): when the
    /// history fits, the rail and the fixed-scale fabric coincide 1:1; when it
    /// overflows, the thumb compresses the whole duration into the rail while
    /// the fabric follows under it. Both this input map and the painted thumb
    /// use `strip_travel`.
    fn strip_pos_at_rail_x(&self, x: f32) -> Option<i64> {
        let geom = (*self.strip_rail.borrow())?;
        let bake = self.strip.bake.as_ref()?;
        let travel = strip_travel(geom.rail_x1 - geom.rail_x0, bake.timeline.total_work);
        if travel <= 0. {
            return Some(bake.now_ms);
        }
        if x < geom.rail_x0 || x > geom.rail_x0 + travel {
            return None;
        }
        let frac = ((x - geom.rail_x0) / travel).clamp(0., 1.);
        Some(bake.timeline.wall_at(frac * bake.timeline.total_work))
    }

    /// The effective fabric pan: the stored offset clamped to the current
    /// geometry. Open stores f32::MAX to pin the view to the tail — the clamp
    /// resolves the sentinel against a rail width the strip only learns at
    /// paint (the geometry Rc is written per-frame).
    fn strip_view(&self) -> f32 {
        let Some(geom) = *self.strip_rail.borrow() else {
            return 0.;
        };
        let Some(bake) = self.strip.bake.as_ref() else {
            return 0.;
        };
        let max = (bake.timeline.total_work - (geom.rail_x1 - geom.rail_x0)).max(0.);
        self.strip.view_offset.clamp(0., max)
    }

    /// Map a fabric x (window coords) → the working px under the cursor at the
    /// CURRENT pan → wall ms. Direct manipulation of the visible cloth.
    fn strip_pos_at_fabric_x(&self, x: f32) -> Option<i64> {
        let geom = (*self.strip_rail.borrow())?;
        let bake = self.strip.bake.as_ref()?;
        let work = x - geom.rail_x0 + self.strip_view();
        if work < 0. || work > bake.timeline.total_work {
            return None;
        }
        Some(bake.timeline.wall_at(work))
    }

    /// The one live→parked seam: save the writer's live locus — the selection
    /// (P6: its offsets mean nothing against preview text, so it collapses)
    /// and the scroll — so EVERY departure hands the present back exactly as
    /// she left it. A no-op while already parked: the locus of record is the
    /// last live moment, not the last click; re-arming here is what lets a
    /// second dwell in one open-strip session return home too (the first
    /// departure consumed the values open_strip armed).
    fn strip_save_live_locus(&mut self) {
        if self.strip.parked {
            return;
        }
        self.strip.saved_sel = Some(self.selected_range.clone());
        let c = self.selected_range.end;
        self.selected_range = c..c;
        self.strip.saved_scroll = Some(f32::from(self.scroll_top));
    }

    /// One scrub step: move the playhead and reconstruct the past (the mutable
    /// half of the stability law — the bake never moves; only these do).
    ///
    /// `lock` binds the fabric to the thumb: view = work − frac·travel, the
    /// one formula under which the playhead line passes through the thumb AND
    /// the correct spot in the cloth at every scale (at fitting scale it
    /// reduces to view = 0; at now it lands the view on the tail). Rail seeks,
    /// stepping, open and Now all lock; a fabric touch does NOT — the moment
    /// just clicked stays under the cursor, and the thumb alone shows the
    /// global position until the next rail interaction re-binds them.
    fn strip_scrub_to(&mut self, pos_ms: i64, lock: bool, cx: &mut Context<Self>) {
        // Re-entering the past cancels a pending departure beat: the writer
        // changed her mind mid-return, and a stale StayOpen must not answer
        // for (or swallow) the next close — the rig's park-during-beat race.
        self.strip_departure = None;
        // Every scrub voids an unconsumed reveal — it was computed for the
        // moment a CLICK parked, and must not land on whatever frame a later
        // drag or keystroke happens to paint. The discrete paths that want a
        // reveal re-arm it right after this call (§3a: one park, one reveal).
        self.strip_reveal_byte = None;
        self.strip.pos_ms = pos_ms;
        self.strip_reconstruct(pos_ms);
        if lock {
            let view = {
                let geom = *self.strip_rail.borrow();
                match (geom, self.strip.bake.as_ref()) {
                    (Some(g), Some(b)) => {
                        let rail_w = (g.rail_x1 - g.rail_x0).max(1.);
                        let total = b.timeline.total_work.max(f32::EPSILON);
                        let travel = strip_travel(rail_w, b.timeline.total_work);
                        let work = b.timeline.work_at(pos_ms);
                        Some((work - work / total * travel).max(0.))
                    }
                    _ => None,
                }
            };
            if let Some(v) = view {
                self.strip.view_offset = v;
            }
        }
        cx.notify();
    }

    /// Arrow keys while parked: step the playhead to the previous/next snap
    /// point — stations, the shoulders of big cuts, the ends. The rescue
    /// ratchet: "just before the damage" is one keypress, not a tremor.
    fn strip_step(&mut self, dir: i64, cx: &mut Context<Self>) {
        let Some(bake) = self.strip.bake.as_ref() else {
            return;
        };
        let pos = self.strip.pos_ms;
        let next = if dir < 0 {
            bake.snap_ms.iter().rev().find(|&&t| t < pos).copied()
        } else {
            bake.snap_ms.iter().find(|&&t| t > pos).copied()
        };
        if let Some(t) = next {
            self.strip_save_live_locus();
            self.strip.parked = true;
            self.strip_scrub_to(t, true, cx);
        }
    }

    /// alt-arrows: the fine lane (§3a, corridor round two). Plain arrows walk
    /// the deliberate marks; a press here moves exactly one work-px of the
    /// fixed quant — the precise instrument for the moment BETWEEN marks that
    /// the release detent would otherwise make hard to reach by hand.
    fn strip_fine_step(&mut self, dir: f32, cx: &mut Context<Self>) {
        if !self.strip.is_parked() {
            return;
        }
        let Some(bake) = self.strip.bake.as_ref() else {
            return;
        };
        let work = bake.timeline.work_at(self.strip.pos_ms) + dir;
        let pos = bake
            .timeline
            .wall_at(work.clamp(0., bake.timeline.total_work));
        if pos != self.strip.pos_ms {
            self.strip_scrub_to(pos, true, cx);
        }
    }

    /// Reconstruct the document as it stood at `pos_ms` (spec §2). Anchors on
    /// the latest materialized checkpoint ≤ t (the ms law), replays the journal
    /// forward through a bare `ReplayDoc` (no store — a scrub never journals),
    /// and shows it read-only through the EXISTING `history_preview` path so
    /// the margin lane hides and the canvas renders the past. Rightward drags
    /// advance the cached scratch incrementally; a leftward jump or a new
    /// anchor rebuilds it.
    fn strip_reconstruct(&mut self, pos_ms: i64) {
        let anchor_ms: Option<i64> = self.strip.bake.as_ref().and_then(|b| {
            strip::anchor_index(&b.anchor_ms, pos_ms).map(|i| b.anchor_ms[i])
        });
        let anchor_key = anchor_ms.unwrap_or(i64::MIN);
        let runs_until = self.doc.journal().runs_until(pos_ms);
        let reuse = self
            .strip
            .scratch
            .as_ref()
            .is_some_and(|s| s.anchor_ms == anchor_key && runs_until >= s.replay.applied);
        if !reuse {
            // A leftward drag within the SAME anchor rebuilds from the
            // scratch's own cached state; only a genuinely new anchor reads
            // the store (whose checkpoint list parse is per-call).
            let cached = self
                .strip
                .scratch
                .as_ref()
                .filter(|s| s.anchor_ms == anchor_key)
                .map(|s| s.anchor_state.clone());
            let (text, spans, blocks) = cached.unwrap_or_else(|| match anchor_ms {
                Some(a) => self
                    .checkpoint_state_at_ms(a)
                    .unwrap_or_else(|| (String::new(), SpanSet::default(), BlockMap::default())),
                None => (String::new(), SpanSet::default(), BlockMap::default()),
            });
            let applied = anchor_ms.map_or(0, |a| self.doc.journal().runs_until(a));
            let mut replay =
                strop_core::journal::ReplayDoc::new(&text, spans.clone(), blocks.clone(), applied);
            // Seam events at or before the anchor are already reflected in
            // the anchor state's own BlockMap — start the cursor past them.
            replay.seams_applied = anchor_ms.map_or(0, |a| self.doc.journal().seams_until(a));
            self.strip.scratch = Some(strip::ScrubDoc {
                replay,
                anchor_ms: anchor_key,
                anchor_state: (text, spans, blocks),
            });
        }
        // Advance forward to pos_ms (disjoint field borrows: scratch vs doc).
        // Unchanged replay on a reused scratch = the projection below would
        // rebuild an identical PreviewDoc — skip the O(doc) work per frame.
        let mut advanced = false;
        if let Some(scratch) = self.strip.scratch.as_mut() {
            advanced = scratch.replay.advance(self.doc.journal(), pos_ms);
        }
        if reuse && !advanced {
            return;
        }
        // Project the reconstructed rope + spans + blocks into a PreviewDoc.
        let Some(scratch) = self.strip.scratch.as_ref() else {
            return;
        };
        let text = scratch.replay.text();
        // The readout counts against the STATE'S OWN boundary (scopes-search
        // 6): park 2,000 words and the strip's report for that same moment
        // drops by 2,000, exactly like the live chip.
        let words = count_words(
            scratch
                .replay
                .rope
                .slice(strop_core::document::manuscript_range_of(
                    &scratch.replay.rope,
                    &scratch.replay.blocks,
                ))
                .chunks(),
        );
        let spans_bytes: Vec<(Range<usize>, InlineAttr)> = {
            let mut idx: Vec<usize> = text.char_indices().map(|(b, _)| b).collect();
            idx.push(text.len());
            let b = |ci: usize| idx.get(ci).copied().unwrap_or(text.len());
            scratch
                .replay
                .spans
                .spans()
                .iter()
                .map(|s| (b(s.range.start)..b(s.range.end), s.attr.clone()))
                .collect()
        };
        let kinds = scratch.replay.blocks.kinds().to_vec();
        // No diff coloring — the strip shows the past AS IT WAS, not a diff.
        self.history_preview = Some(PreviewDoc {
            text,
            inserts: Vec::new(),
            deletes: Vec::new(),
            spans_bytes,
            kinds,
            // The scrubbed moment's own seam (time-persistence 2/5), evolved
            // by the replay's Seam events.
            boundary: scratch.replay.blocks.boundary(),
        });
        self.strip.words_at = words;
    }

    /// Esc / the Now chip: drop the preview, return to the present, keep the
    /// strip open (spec §2). Also clears any Compare pin (review: every state
    /// needs an exit).
    fn strip_return_to_now(&mut self, cx: &mut Context<Self>) {
        self.begin_strip_departure(StripDeparture::StayOpen, cx);
    }

    /// All non-Restore doors out of a parked/comparing frame share this
    /// return-through-now. A repeated command completes the pending door.
    fn begin_strip_departure(
        &mut self,
        continuation: StripDeparture,
        cx: &mut Context<Self>,
    ) {
        if let Some((_, started, from)) = self.strip_departure.take() {
            // A second departure command during the beat completes the
            // pending departure immediately — with the NEW continuation,
            // never the stale one (Esc-then-close must close, not re-run
            // "stay open").
            self.strip_departure = Some((continuation, started, from));
            self.finish_strip_departure(cx);
            return;
        }
        self.resolve_composer_draft(cx);
        self.resolve_strip_name_draft(cx);
        let from_ms = self.strip.pos_ms;
        let now = self
            .strip
            .bake
            .as_ref()
            .map_or_else(strop_core::journal::now_ms, |b| b.now_ms);
        self.strip.parked = false;
        self.strip.scrubbing = false;
        self.strip.pin_ms = None;
        self.compare_preview = None;
        self.compare_selection = None;
        self.strip.pos_ms = now;
        self.strip.scratch = None;
        // Re-pin the view to the tail — returning to now also returns the eye.
        self.strip.view_offset = f32::MAX;
        // Esc returns the identical frame: the live selection comes back (a
        // preview round-trip never mutates the document, so its offsets hold);
        // the preview's own selection dies with the preview.
        if let Some(s) = self.strip.saved_sel.take() {
            self.selected_range = s;
        }
        self.restore_strip_scroll();
        self.history_preview = None;
        // An unpainted reveal dies with the preview it aimed at — left alive,
        // the next LIVE frame would consume the past byte and drag the just-
        // restored scroll to wherever that moment's edit happened to be.
        self.strip_reveal_byte = None;
        self.strip_departure = Some((continuation, Instant::now(), from_ms));
        cx.notify();
        cx.spawn(async move |this, cx| {
            for _ in 0..6 {
                cx.background_executor()
                    .timer(Duration::from_millis(STRIP_DEPARTURE_MS / 6))
                    .await;
                let done = this.update(cx, |editor, cx| {
                    if editor.strip_departure.is_none() {
                        return true;
                    }
                    cx.notify();
                    false
                });
                if !matches!(done, Ok(false)) { return }
            }
            this.update(cx, |editor, cx| editor.finish_strip_departure(cx)).ok();
        }).detach();
    }

    fn finish_strip_departure(&mut self, cx: &mut Context<Self>) {
        let Some((continuation, _, _)) = self.strip_departure.take() else { return };
        match continuation {
            StripDeparture::StayOpen => cx.notify(),
            StripDeparture::Close => self.close_strip_now(cx),
            StripDeparture::Panel => {
                self.close_strip_now(cx);
                self.enter_history(cx);
            }
        }
    }

    /// An edit gesture arrived while parked in the past (Bug B): the past is
    /// read-only, so the text is untouched and the banner's moment label
    /// pulses instead — the ONE uniform refusal for every mutation (insert,
    /// delete, format, block, undo, redo, link, paste, cut). No restore is
    /// ever committed by a keystroke (P2: the tool never wants). The fade
    /// alpha is a pure function of `Instant`; a short spawn loop re-notifies
    /// across the ~900ms so the flash actually decays on screen.
    fn pulse_strip(&mut self, cx: &mut Context<Self>) {
        self.strip_pulse = Some(Instant::now());
        cx.spawn(async move |this, cx| {
            for _ in 0..STRIP_PULSE_FRAMES {
                cx.background_executor()
                    .timer(Duration::from_millis(STRIP_PULSE_MS / STRIP_PULSE_FRAMES))
                    .await;
                let cont = this.update(cx, |editor: &mut Editor, cx| {
                    let done = editor
                        .strip_pulse
                        .is_none_or(|t| t.elapsed() >= Duration::from_millis(STRIP_PULSE_MS));
                    if done {
                        editor.strip_pulse = None;
                    }
                    cx.notify();
                    done
                });
                // Stop once the fade finished (Ok(true)) or the entity is gone
                // (Err); keep re-notifying only while Ok(false).
                if !matches!(cont, Ok(false)) {
                    break;
                }
            }
        })
        .detach();
    }

    /// Compare (shift-click): a second faint playhead whose delta folds into
    /// the readout's single line. A second shift-click on/near it clears it.
    fn strip_toggle_pin(&mut self, pos_ms: i64, cx: &mut Context<Self>) {
        let clear = self.strip.pin_ms.is_some_and(|p| {
            // Near the existing pin, in working px — a toggle-off.
            self.strip.bake.as_ref().is_some_and(|b| {
                (b.timeline.work_at(p) - b.timeline.work_at(pos_ms)).abs() < 8.
            })
        });
        if clear {
            self.strip.pin_ms = None;
            self.compare_preview = None;
            self.compare_selection = None;
        } else {
            self.strip.pin_ms = Some(pos_ms);
            self.strip.pin_words = self.strip_word_count_at(pos_ms);
            // Shift-click remains an expert entrance. If it targets the
            // parked frame, cache exactly the already reconstructed state.
            // An arbitrary A is materialized once by the same replay helper.
            self.compare_preview = if pos_ms == self.strip.pos_ms {
                self.history_preview.clone()
            } else {
                self.strip_preview_at(pos_ms)
            };
            self.compare_show_b = false;
            self.compare_active_b = false;
            self.compare_scroll_a = ScrollHandle::new();
            self.compare_scroll_b = ScrollHandle::new();
            self.compare_selection = None;
        }
        cx.notify();
    }

    fn strip_begin_compare(&mut self, cx: &mut Context<Self>) {
        if !self.strip.is_parked() {
            return;
        }
        self.strip.pin_ms = Some(self.strip.pos_ms);
        self.strip.pin_words = self.strip.words_at;
        self.compare_preview = self.history_preview.clone();
        self.compare_show_b = false;
        self.compare_active_b = false;
        self.compare_scroll_a = ScrollHandle::new();
        self.compare_scroll_b = ScrollHandle::new();
        self.compare_selection = None;
        cx.notify();
    }

    fn strip_done_comparing(&mut self, cx: &mut Context<Self>) {
        self.strip.pin_ms = None;
        self.compare_preview = None;
        self.compare_selection = None;
        cx.notify();
    }

    fn strip_preview_at(&self, pos_ms: i64) -> Option<PreviewDoc> {
        let bake = self.strip.bake.as_ref()?;
        let anchor_ms = strip::anchor_index(&bake.anchor_ms, pos_ms).map(|i| bake.anchor_ms[i]);
        let (text, spans, blocks) = match anchor_ms {
            Some(a) => self.checkpoint_state_at_ms(a)
                .unwrap_or_else(|| (String::new(), SpanSet::default(), BlockMap::default())),
            None => (String::new(), SpanSet::default(), BlockMap::default()),
        };
        let applied = anchor_ms.map_or(0, |a| self.doc.journal().runs_until(a));
        let mut replay = strop_core::journal::ReplayDoc::new(&text, spans, blocks, applied);
        replay.seams_applied = anchor_ms.map_or(0, |a| self.doc.journal().seams_until(a));
        replay.advance(self.doc.journal(), pos_ms);
        let text = replay.text();
        let mut idx: Vec<usize> = text.char_indices().map(|(b, _)| b).collect();
        idx.push(text.len());
        let byte = |ci: usize| idx.get(ci).copied().unwrap_or(text.len());
        let spans_bytes = replay.spans.spans().iter()
            .map(|s| (byte(s.range.start)..byte(s.range.end), s.attr.clone()))
            .collect();
        Some(PreviewDoc {
            text,
            inserts: Vec::new(),
            deletes: Vec::new(),
            spans_bytes,
            kinds: replay.blocks.kinds().to_vec(),
            boundary: replay.blocks.boundary(),
        })
    }

    /// Word count of the reconstruction at `pos_ms`, computed on a THROWAWAY
    /// `ReplayDoc` (never touching the cached scratch or the live preview) —
    /// used once when a Compare pin is set, so the readout's folded delta is
    /// free thereafter.
    fn strip_word_count_at(&self, pos_ms: i64) -> usize {
        let Some(bake) = self.strip.bake.as_ref() else {
            return 0;
        };
        let anchor_ms = strip::anchor_index(&bake.anchor_ms, pos_ms).map(|i| bake.anchor_ms[i]);
        let (text, spans, blocks) = match anchor_ms {
            Some(a) => self
                .checkpoint_state_at_ms(a)
                .unwrap_or_else(|| (String::new(), SpanSet::default(), BlockMap::default())),
            None => (String::new(), SpanSet::default(), BlockMap::default()),
        };
        let applied = anchor_ms.map_or(0, |a| self.doc.journal().runs_until(a));
        let mut replay = strop_core::journal::ReplayDoc::new(&text, spans, blocks, applied);
        replay.seams_applied = anchor_ms.map_or(0, |a| self.doc.journal().seams_until(a));
        replay.advance(self.doc.journal(), pos_ms);
        // Against the state's own boundary (scopes-search 6), like words_at.
        count_words(
            replay
                .rope
                .slice(strop_core::document::manuscript_range_of(
                    &replay.rope,
                    &replay.blocks,
                ))
                .chunks(),
        )
    }

    /// The strip's own Restore (spec §2): build a `CheckpointState`-shaped value
    /// from the reconstructed scratch and route through the SAME restore path
    /// as the panel (undoable forward edit, notes reanchor, the "Before
    /// restoring" and "Restored" checkpoints, the `Restore` event). Then the one
    /// lawful in-session re-bake (data changed) and a return to the new present.
    fn strip_restore(&mut self, cx: &mut Context<Self>) {
        if !self.strip.is_parked() {
            return;
        }
        let Some(scratch) = self.strip.scratch.as_ref() else {
            self.strip_return_to_now(cx);
            return;
        };
        let text = scratch.replay.text();
        let spans = scratch.replay.spans.clone();
        let blocks = scratch.replay.blocks.clone();
        let from_unix = self.strip.pos_ms / 1000;
        // The strip epilogue (unpark, snap to now, re-bake) now lives inside
        // `restore_to_state` (F3) so every Restore entrance shares it.
        self.restore_to_state(text, spans, blocks, from_unix, cx);
        // Belt for the degraded no-store path (restore_to_state returned
        // before its epilogue): the strip still returns to the live now.
        if self.strip.parked {
            self.strip_return_to_now(cx);
        }
        cx.notify();
    }

    /// Wheel over the strip pans the FABRIC only (never the thumb, never the
    /// document — design §3); the view offset varies, the bake stays frozen.
    fn strip_pan(&mut self, d: f32, cx: &mut Context<Self>) {
        let max = {
            let geom = *self.strip_rail.borrow();
            match (geom, self.strip.bake.as_ref()) {
                (Some(g), Some(b)) => {
                    Some((b.timeline.total_work - (g.rail_x1 - g.rail_x0)).max(0.))
                }
                _ => None,
            }
        };
        let Some(max) = max else { return };
        // Resolve the pin-to-tail sentinel BEFORE the arithmetic: f32::MAX
        // absorbs the delta (MAX - d == MAX), which would eat the first wheel
        // tick after an open (review: five-lens pass, geometry).
        let base = self.strip.view_offset.clamp(0., max);
        self.strip.view_offset = (base - d).clamp(0., max);
        cx.notify();
    }

    /// Export next to the .strop file (doc.strop -> doc.md).
    fn export_markdown(&mut self, _: &ExportMarkdown, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        let Some(store) = &self.store else {
            eprintln!("strop: no document file to export next to");
            return;
        };
        let path = store.path().with_extension("md");
        match MarkdownExport::prepare(&self.doc, store).write_to(&path) {
            Ok(()) => {
                eprintln!("strop: exported {}", path.display());
                // A ship-shaped moment — the strip marks it.
                self.doc
                    .journal_mut()
                    .record_event(strop_core::journal::JournalEvent::Export {
                        t: strop_core::journal::now_ms(),
                    });
                self.mark_dirty();
            }
            Err(e) => eprintln!("strop: export failed: {e}"),
        }
        cx.notify();
    }

    /// Insert a footnote: a ref atom at the cursor, a def block at the end,
    /// cursor lands in the def. (Two transactions; two undos remove it.)
    fn insert_footnote(&mut self, _: &InsertFootnote, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        // Fresh internal label, Pandoc-style: never reused (counting defs
        // collides after a deletion). The PAINTED number derives from ref
        // order at paint time; the stored id is identity only.
        let n = self
            .doc
            .blocks()
            .kinds()
            .iter()
            .filter_map(|k| match k {
                BlockKind::FootnoteDef { id } => id.parse::<u64>().ok(),
                _ => None,
            })
            .chain(self.doc.spans().spans().iter().filter_map(|s| match &s.attr {
                InlineAttr::FootnoteRef(id) => id.parse::<u64>().ok(),
                _ => None,
            }))
            .max()
            .unwrap_or(0)
            + 1;
        let id = n.to_string();
        let sel = self.selected_range.clone();
        self.doc.edit_bytes(sel.start..sel.end, &id);
        let char_range = {
            let rope = self.doc.rope();
            rope.byte_to_char(sel.start)..rope.byte_to_char(sel.start + id.len())
        };
        self.doc
            .format_in_current_tx(char_range, InlineAttr::FootnoteRef(id.clone()), true);
        let len = self.doc.len_bytes();
        self.doc.edit_bytes(len..len, "\n");
        let def_block = self.doc.block_of_byte(self.doc.len_bytes());
        self.doc
            .set_block_kind_in_current_tx(def_block, BlockKind::FootnoteDef { id });
        let end = self.doc.len_bytes();
        self.selected_range = end..end;
        self.selection_reversed = false;
        self.cursor_affinity_down = false;
        self.goal_x = None;
        self.caret_attrs.clear();
        self.sync_mutations();
        self.mark_dirty();
        self.bump_activity();
        cx.notify();
    }

    /// Footnotes whose refs are visible in the viewport, as zone rows,
    /// plus the count of rows collapsed by the stacking policy (DESIGN
    /// §2-footnotes: all up to 3, then the 3 nearest the viewport center
    /// and a "+N more" row). Derived from the last painted frame.
    fn visible_footnotes(&self) -> (Vec<ZoneNote>, usize) {
        // Common case: a document with no footnote refs surfaces no zone notes.
        // Skip the whole-viewport paragraph scan and per-ref block search that
        // otherwise run unconditionally on every render (incl. idle blinks).
        if !self
            .doc
            .spans()
            .spans()
            .iter()
            .any(|s| matches!(s.attr, InlineAttr::FootnoteRef(_)))
        {
            return (Vec::new(), 0);
        }
        let Some(frame) = self.last_frame.as_ref() else {
            return (Vec::new(), 0);
        };
        let top = frame.scroll_top;
        let bottom = top + frame.viewport_height;
        let mut lo = usize::MAX;
        let mut hi = 0usize;
        for par in &frame.paragraphs {
            if par.top + par.height > top && par.top < bottom {
                lo = lo.min(par.range.start);
                hi = hi.max(par.range.end);
            }
        }
        // The frame may be one paint behind the document (compositor
        // throttling, big edits): clamp its byte ranges to the live rope.
        let len = self.doc.len_bytes();
        let (lo, hi) = (lo.min(len), hi.min(len));
        if lo >= hi {
            return (Vec::new(), 0);
        }
        let rope = self.doc.rope();
        let (clo, chi) = (rope.byte_to_char(lo), rope.byte_to_char(hi));
        let numbers = {
            let refs: Vec<(usize, &str)> = self
                .doc
                .spans()
                .spans()
                .iter()
                .filter_map(|s| match &s.attr {
                    InlineAttr::FootnoteRef(id) => Some((s.range.start, id.as_str())),
                    _ => None,
                })
                .collect();
            footnote_numbers(&refs, self.doc.blocks().kinds())
        };
        // (row, byte offset of the ref's start — for ordering/stacking)
        let mut out: Vec<(ZoneNote, usize)> = Vec::new();
        for span in self.doc.spans().spans() {
            let InlineAttr::FootnoteRef(id) = &span.attr else {
                continue;
            };
            if span.range.start >= chi || span.range.end <= clo {
                continue;
            }
            let no = match numbers.get(id) {
                Some(n) => *n,
                None => continue,
            };
            if out.iter().any(|(seen, _)| seen.no == no) {
                continue;
            }
            let Some(block) = self
                .doc
                .blocks()
                .kinds()
                .iter()
                .position(|k| matches!(k, BlockKind::FootnoteDef { id: d } if d == id))
            else {
                continue;
            };
            let (start, end) = block_bounds_in(&self.doc, block);
            // One visual home (H4): if the definition block is itself on
            // screen — the reader has scrolled down to the Footnotes
            // section — don't also mirror it in the page-bottom zone. The
            // zone is for footnotes whose def is off-screen above/below.
            if start < hi && end > lo {
                continue;
            }
            let full = self.doc.slice_bytes(start..end);
            let (def, def_len) = if full.chars().count() > 110 {
                let cut: String = full.chars().take(110).collect();
                let cut_len = cut.len();
                (cut + "…", cut_len)
            } else {
                let full_len = full.len();
                (full, full_len)
            };
            out.push((
                ZoneNote {
                    no,
                    def,
                    def_start: start,
                    def_len,
                    ref_byte: rope.char_to_byte(span.range.end),
                },
                rope.char_to_byte(span.range.start),
            ));
        }
        // Reading order, whatever order the span set stores.
        out.sort_by_key(|(_, ref_start)| *ref_start);
        let total = out.len();
        if total > 3 {
            // Keep the 3 nearest the viewport center; reading order stays.
            let center = f32::from(top + frame.viewport_height / 2.);
            let mut by_dist: Vec<usize> = (0..total).collect();
            by_dist.sort_by(|&a, &b| {
                let d = |i: usize| {
                    frame
                        .position_of(out[i].1, false)
                        .map_or(f32::MAX, |p| (f32::from(p.y) - center).abs())
                };
                d(a).total_cmp(&d(b))
            });
            let keep: HashSet<usize> = by_dist.into_iter().take(3).collect();
            out = out
                .into_iter()
                .enumerate()
                .filter(|(i, _)| keep.contains(i))
                .map(|(_, n)| n)
                .collect();
        }
        (out.into_iter().map(|(n, _)| n).collect(), total.saturating_sub(3))
    }

    /// One document, one window, one process: opening spawns a sibling
    /// instance (in-place document switching is backlogged).
    fn open_file(&mut self, _: &OpenFile, _: &mut Window, cx: &mut Context<Self>) {
        let rx = cx.prompt_for_paths(gpui::PathPromptOptions {
            files: true,
            directories: false,
            multiple: false,
            prompt: Some("Open".into()),
        });
        cx.spawn(async move |_, _| {
            if let Ok(Ok(Some(paths))) = rx.await {
                let Some(path) = paths.first() else { return };
                let path = crate::files::resolve_portal_path_async(path.clone()).await;
                let Ok(exe) = std::env::current_exe() else { return };
                if let Err(e) = std::process::Command::new(exe).arg(&path).spawn() {
                    eprintln!("strop: open in new window: {e}");
                }
            }
        })
        .detach();
    }

    /// Save a copy: .md exports markdown, anything else a full .strop
    /// snapshot (history included). The open document keeps its own path —
    /// continuous save never re-targets.
    fn save_copy_as(&mut self, _: &SaveCopyAs, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        let _ = self.save_now();
        let Some(store) = &self.store else {
            eprintln!("strop: no document to copy");
            return;
        };
        // Seed the dialog with the HOST directory: seeding a portal FUSE
        // dir invites the picker to mint a foreign name inside the doc
        // mount — the invisible-temp trap (files.rs law).
        let dir = crate::files::host_parent_or_documents(store.path());
        let suggested = format!(
            "{} copy.strop",
            store.path().file_stem().and_then(|s| s.to_str()).unwrap_or("document")
        );
        let rx = cx.prompt_for_new_path(&dir, Some(&suggested));
        let markdown = MarkdownExport::prepare(&self.doc, store);
        cx.spawn(async move |this, cx| {
            if let Ok(Ok(Some(path))) = rx.await {
                let path = crate::files::resolve_portal_path_async(path).await;
                if path.extension().is_some_and(|e| e == "md") {
                    if let Err(e) = markdown.write_to(&path) {
                        eprintln!("strop: save copy: {e}");
                    }
                } else {
                    this.update(cx, |editor: &mut Editor, _| {
                        if let Some(store) = &editor.store
                            && let Err(e) = store.save_copy_to(&path)
                        {
                            eprintln!("strop: save copy: {e}");
                        }
                    })
                    .ok();
                }
            }
        })
        .detach();
    }

    /// ctrl-m: note on the selection (or the word at the caret), then
    /// open the composer for its body.
    fn add_note(&mut self, _: &AddNote, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        let range = if self.selected_range.is_empty() {
            self.word_range_at(self.cursor_offset())
        } else {
            self.selected_range.clone()
        };
        if range.is_empty() {
            return;
        }
        let rope = self.doc.rope();
        let char_range = rope.byte_to_char(range.start)..rope.byte_to_char(range.end);
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_secs() as i64)
            .unwrap_or(0);
        let id = self.doc.add_note(char_range, String::new(), now);
        self.mark_dirty();
        let saved = (self.selected_range.clone(), self.selection_reversed);
        self.open_composer(id, String::new(), window, cx);
        // Save the writer's selection so the composer's exit lands where thought
        // left off (LAW 2 split-exit; the keyboard/dead-zone exits restore it).
        // AFTER open_composer, whose internal resolve of any prior composer would
        // otherwise clear it.
        self.composer_return = Some(saved);
        // A focus-moving verb LATCHES the flanks down (LAW 1 / C2): the selection
        // persists but the offer withdraws, so the composer is never overpainted
        // and no re-offer fires when the composer commits and the selection
        // returns unchanged.
        self.flank_latched = true;
        self.bump_activity();
        cx.notify();
    }

    /// The shared resolve (V15a): apply an open composer's draft to the doc —
    /// empty trimmed body → C4 empty-DISCARD (no blank card manufactured), else
    /// commit — and settle CardFocus accordingly. Focus and notify are the
    /// callers' to own; returns whether a composer was actually open.
    fn resolve_composer_draft(&mut self, cx: &mut Context<Self>) -> bool {
        let (id, body) = match &self.focus {
            CardFocus::Composing { id, input } => (*id, input.read(cx).content.clone()),
            _ => return false,
        };
        self.composer_return = None;
        if body.trim().is_empty() {
            // Undo-aligned cancel: drops the add's paired empty undo step when
            // still topmost, else scrubs history so no undo/redo resurrects a
            // blank card (review finding 4).
            self.doc.cancel_provisional_note(id);
            self.focus = CardFocus::Idle;
        } else {
            self.doc.set_note_body(id, body);
            self.focus = CardFocus::Selected(id);
        }
        self.mark_dirty();
        true
    }

    /// Commit (or C4 empty-DISCARD) the open composer WITHOUT moving focus — the
    /// LAW 2 blur path, where focus has already genuinely left the field, so
    /// stealing it back to the document would be wrong. A no-op unless a
    /// composer is open.
    pub(crate) fn commit_composer_no_focus(&mut self, cx: &mut Context<Self>) {
        if self.resolve_composer_draft(cx) {
            cx.notify();
        }
    }

    /// Commit (or C4 empty-discard) the open composer and hand focus back to the
    /// prose — the LAW 2 GESTURE path (a click resolves the field at once). Does
    /// NOT restore the saved caret; the caller decides (a prose click places the
    /// caret at the click point; a dead-zone click restores). `true` if a
    /// composer was open.
    fn commit_or_discard_composer(&mut self, window: &mut Window, cx: &mut Context<Self>) -> bool {
        if self.resolve_composer_draft(cx) {
            window.focus(&self.focus_handle, cx);
            true
        } else {
            false
        }
    }

    /// Restore the caret/selection saved at composer-open (LAW 2 / C4 split
    /// exit): the keyboard-commit and dead-zone-click exits land where thought
    /// left off. The restored selection is unchanged, so it keeps the flank latch.
    fn apply_composer_return(&mut self, ret: Option<(Range<usize>, bool)>, cx: &mut Context<Self>) {
        let Some((range, reversed)) = ret else { return };
        let len = self.doc.len_bytes();
        self.selected_range = range.start.min(len)..range.end.min(len);
        self.selection_reversed = reversed;
        self.flank_sel = self.selected_range.clone();
        self.flank_latched = true;
        cx.notify();
    }

    /// Commit every open single-line transient field on a writer GESTURE (LAW 2:
    /// a click resolves the field family at once, not on the delayed blur). Each
    /// field's own Commit subscription closes it — the durable write rides that
    /// path. A no-op when nothing is open.
    pub(crate) fn commit_transient_fields_on_gesture(&mut self, cx: &mut Context<Self>) {
        let fields = [
            self.doc_rename_input.clone(),
            self.goal_input.clone(),
            self.rename_input.as_ref().map(|(_, f)| f.clone()),
            self.alt_input.as_ref().map(|(_, f)| f.clone()),
        ];
        for field in fields.into_iter().flatten() {
            let text = field.read(cx).content.clone();
            field.update_checked(cx, |_, fcx| fcx.emit(TextFieldEvent::Commit(text)));
        }
    }

    /// Quit is the one resolution boundary broader than writer gestures: every
    /// durable transient field must reach the document before `save_now`.
    pub(crate) fn commit_transient_fields_on_quit(&mut self, cx: &mut Context<Self>) {
        self.commit_transient_fields_on_gesture(cx);
        if let Some(field) = self.link_input.as_ref().map(|(_, field)| field.clone()) {
            let text = field.read(cx).content.clone();
            field.update_checked(cx, |_, fcx| fcx.emit(TextFieldEvent::Commit(text)));
        }
        self.cr_commit_input_inner(cx);
    }

    /// Leave the composer by KEYBOARD (Enter/Escape). The draft is already the
    /// note's text; the exit restores the writer's saved caret (LAW 2).
    fn finish_composing(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let ret = self.composer_return.take();
        if self.resolve_composer_draft(cx) {
            window.focus(&self.focus_handle, cx);
        }
        self.apply_composer_return(ret, cx);
        cx.notify();
    }

    /// Highlight a card without editing it (AI diagnoses; a note clicked via
    /// its anchor). Resolves any open composer first so the previous note's
    /// draft is saved and its composer never lingers.
    fn select_card(&mut self, id: u64, window: &mut Window, cx: &mut Context<Self>) {
        if self.resolve_composer_draft(cx) {
            window.focus(&self.focus_handle, cx);
        }
        self.focus = CardFocus::Selected(id);
    }

    /// Drop all card selection (a click that hits no anchor). Resolves any
    /// open composer first.
    fn deselect_card(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        if self.resolve_composer_draft(cx) {
            window.focus(&self.focus_handle, cx);
        }
        self.focus = CardFocus::Idle;
    }

    fn open_composer(
        &mut self,
        id: u64,
        body: String,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        // Switching composers: commit the one we're leaving before opening this.
        if self.resolve_composer_draft(cx) {
            window.focus(&self.focus_handle, cx);
        }
        let input = cx.new(|cx| TextField::multiline(cx, body));
        cx.subscribe_in(
            &input,
            window,
            // Enter and Escape both end composing through the one exit; the live
            // text is already the note's body, so the event payload is moot.
            move |editor, _, _event: &TextFieldEvent, window, cx| {
                editor.finish_composing(window, cx);
            },
        )
        .detach();
        // Click-away commits — but only on a real DEPARTURE (LAW 2 / D2): a
        // transient focus-out (keyboard-layout switch, app deactivation) is
        // never a commit. Each blur owns a generation, so a blur/focus/blur
        // bounce cannot let the first timer commit on the second blur's behalf.
        // Empty ⇒ discard (C4). Guarded on THIS composer still being open so a
        // switch/click that already resolved it can't double-commit.
        let handle = input.read(cx).focus_handle.clone();
        let weak = cx.entity().downgrade();
        let generation = std::sync::Arc::new(std::sync::atomic::AtomicUsize::new(0));
        {
            let generation = generation.clone();
            window
                .on_focus_in(&handle, cx, move |_window, _cx| {
                    generation.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
                })
                .detach();
        }
        window
            .on_focus_out(&handle, cx, move |_, window, cx| {
                let my_gen = generation.fetch_add(1, std::sync::atomic::Ordering::Relaxed) + 1;
                let generation = generation.clone();
                let weak = weak.clone();
                window
                    .spawn(cx, async move |cx| {
                        cx.background_executor()
                            .timer(Duration::from_millis(FIELD_BLUR_GRACE_MS))
                            .await;
                        cx.update(|window, app| {
                            if generation.load(std::sync::atomic::Ordering::Relaxed) != my_gen
                                || !window.is_window_active()
                            {
                                return;
                            }
                            let Some(editor) = weak.upgrade() else { return };
                            editor.update_checked(app, |editor, cx| {
                                if editor.focus.composing_id() == Some(id) {
                                    editor.commit_composer_no_focus(cx);
                                }
                            });
                        })
                        .ok();
                    })
                    .detach();
            })
            .detach();
        let input_focus = input.read(cx).focus_handle.clone();
        window.focus(&input_focus, cx);
        self.focus = CardFocus::Composing { id, input };
    }

    fn set_note_status(
        &mut self,
        id: u64,
        status: NoteStatus,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        // Commit any open draft first (the click may be on this card's own
        // done/×, or on another card while this one composes).
        if self.resolve_composer_draft(cx) {
            window.focus(&self.focus_handle, cx);
        }
        // A resolved card leaves with a brief exit fade rather than blinking
        // out: snapshot its rendered slot BEFORE the model change (afterwards
        // it has no card to snapshot). The model itself commits immediately —
        // only the light lingers (departing), never the data.
        if matches!(status, NoteStatus::Done | NoteStatus::Dismissed)
            && let Some(card) = {
                let layout = self.margin_cards(true);
                layout.cards.into_iter().chain(layout.glance).find(|c| c.id == id)
            }
        {
            self.departing.push((card, Instant::now()));
            self.schedule_departing_clear(cx);
        }
        self.doc.set_note_status(id, status);
        // Thread terminals on the strip: when a card left and by which door.
        if matches!(status, NoteStatus::Done | NoteStatus::Dismissed) {
            self.doc
                .journal_mut()
                .record_event(strop_core::journal::JournalEvent::CardClosed {
                    t: strop_core::journal::now_ms(),
                    id,
                    resolved: status == NoteStatus::Done,
                });
        }
        if self.focus.active_id() == Some(id) {
            self.focus = CardFocus::Idle;
        }
        self.mark_dirty();
        self.bump_activity();
        cx.notify();
    }

    /// Retire the departing exit-fade ghosts once their light is spent —
    /// shared by every writer-initiated departure (a resolved card, a parked
    /// passage's retiring diagnosis, the provenance row's leave).
    fn schedule_departing_clear(&self, cx: &mut Context<Self>) {
        cx.spawn(async move |this, cx| {
            cx.background_executor()
                .timer(CARD_RESOLVE + Duration::from_millis(50))
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                editor
                    .departing
                    .retain(|(_, since)| since.elapsed() < CARD_RESOLVE);
                cx.notify();
            })
            .ok();
        })
        .detach();
    }

    /// The thesis, running: an editorial pass that names problems as
    /// queries in the margin and never rewrites a word.
    fn run_diagnosis(&mut self, _: &RunDiagnosis, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        // ctrl-shift-d honours the configured default. Menu rows pin their
        // own depth into a run without creating a second sticky mode.
        self.run_pass(PassKind::Diagnostic(self.effective_mode()), cx);
    }

    fn run_believing(&mut self, _: &RunBelieving, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        self.run_pass(PassKind::Believing, cx);
    }

    /// The door (DESIGN §4.4): flip between drafting (margin quiet) and
    /// reviewing (cards surface). The deliberate "register change" the
    /// research asks for — never inferred, never automatic in v1, so a
    /// drafting burst can never be interrupted by a wrong guess.
    fn toggle_review(&mut self, _: &ToggleReview, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        self.toggle_door(cx);
    }

    /// The chip/shortcut transition. Opening lands a parked pass; closing
    /// commits transient card text and never flushes hidden work.
    fn toggle_door(&mut self, cx: &mut Context<Self>) {
        let opening = self.drafting;
        if !opening {
            self.commit_composer_no_focus(cx);
            let closing: Vec<MarginCard> = self
                .margin_cards(true)
                .cards
                .into_iter()
                .filter(|card| card.kind == NoteKind::Diagnosis)
                .collect();
            if !closing.is_empty() {
                self.departing.extend(closing.into_iter().map(|card| (card, Instant::now())));
                self.schedule_departing_clear(cx);
            }
            self.focus = CardFocus::Idle;
        }
        self.drafting = !self.drafting;
        if opening {
            self.flush_deferred_pass(cx);
        }
        cx.notify();
    }

    /// Open the door from outside the editor (the tutorial, whose whole
    /// point is to show the margin demo cards).
    pub fn enter_reviewing(&mut self) {
        self.drafting = false;
    }

    /// Open diagnosis/believing cards the closed door is currently holding
    /// back (the rail's count). Notes (the writer's own) are never counted —
    /// the door quiets the editor, not the writer.
    fn resting_diagnoses(&self) -> usize {
        self.doc
            .notes()
            .open()
            .filter(|n| n.kind == NoteKind::Diagnosis)
            .count()
    }

    /// The chip counts current editorial claims. An all-unverified set keeps
    /// its referent but drains the count's ink.
    fn door_chip_count(&self) -> Option<(usize, bool)> {
        door_chip_semantics(
            self.doc
                .notes()
                .open()
                .filter(|n| n.kind == NoteKind::Diagnosis)
                .map(|n| n.unverified),
        )
    }

    /// Copy-level diagnoses suppressed while a developmental one is still
    /// open — the mandatory altitude order (don't polish prose that the
    /// structural edit may cut; Reedsy, Sommers). Zero unless both exist.
    fn suppressed_copy(&self) -> usize {
        let has_dev = self
            .doc
            .notes()
            .open()
            .any(|n| n.kind == NoteKind::Diagnosis && n.level == "developmental");
        if !has_dev {
            return 0;
        }
        self.doc
            .notes()
            .open()
            .filter(|n| n.kind == NoteKind::Diagnosis && n.level == "copy")
            .count()
    }

    /// The configured levels-of-edit default, else "line" (Perkins' default
    /// register). Direct menu requests carry their own depth in `PassKind`.
    fn effective_mode(&self) -> String {
        let mode = self.config.ai.mode.clone();
        match mode.as_str() {
            "developmental" | "copy" => mode,
            _ => "line".to_owned(),
        }
    }

    /// The editor button's live face inputs (impl 04 §0). `configured` gates
    /// NeedsSetup even before any pass runs (ai_status is None until one does),
    /// so an unconfigured provider is announced on the button, not just when a
    /// pass is attempted.
    fn face_inputs(&self) -> FaceInputs {
        FaceInputs {
            needs_setup: !self.config.ai.configured()
                || matches!(self.ai_status, Some(AiStatus::NeedsSetup { .. })),
            error: matches!(self.ai_status, Some(AiStatus::Error { .. })),
            cooking: matches!(self.ai_status, Some(AiStatus::Running { .. })),
            ready: self.deferred_pass.is_some(),
            empty: self
                .ai_empty_result
                .as_ref()
                .is_some_and(|result| result.unacknowledged),
            door_open: !self.drafting,
        }
    }

    fn editor_face(&self) -> EditorFace {
        face_for(&self.face_inputs())
    }

    /// Open editorial queries (open diagnosis cards) — the button's "{n} open"
    /// and the footer's "{open} queries open". `resting_diagnoses` already
    /// counts exactly these, regardless of the door.
    fn open_query_count(&self) -> usize {
        self.resting_diagnoses()
    }

    /// The copy row's gate (impl 04 §0): while any developmental query is open,
    /// polishing prose the structural edit may cut is premature (the altitude
    /// order — Reedsy, Sommers). This is the REQUEST-side complement of
    /// `suppressed_copy`'s RESULT-hold — both key off the same signal (an open
    /// developmental diagnosis), so the button and the lane never disagree. It
    /// releases the moment the last developmental query closes, no pass re-run.
    fn copy_gated(&self) -> bool {
        copy_gate_active(self.doc.notes().open().map(|n| (n.kind, n.level.as_str())))
    }

    /// Toggle the editor button's dropdown (impl 04 §0). A pass in flight leaves
    /// the rows inert (see the menu render), but the button still opens so the
    /// pulse and the door verb stay reachable.
    fn toggle_editor_menu(&mut self, cx: &mut Context<Self>) {
        self.editor_menu_open = !self.editor_menu_open;
        // One situational popup at a time (§0.6 layer discipline): the
        // editor menu and the omnibar dropdown never stand together.
        if self.editor_menu_open {
            self.palette_input = None;
            self.replace_input = None;
            self.replace_result = None;
            self.omni_return = None;
        } else {
            self.acknowledge_empty_result();
        }
        cx.notify();
    }

    fn close_editor_menu(&mut self, cx: &mut Context<Self>) {
        if self.editor_menu_open {
            self.editor_menu_open = false;
            self.acknowledge_empty_result();
            cx.notify();
        }
    }

    fn acknowledge_empty_result(&mut self) {
        if let Some(result) = &mut self.ai_empty_result {
            result.unacknowledged = false;
        }
    }

    fn resolved_ai_language(
        &mut self,
        manuscript: &str,
    ) -> strop_core::language::ResolvedLanguage {
        let revision = self.doc.revision();
        let configured = self.config.ai.language.trim().to_owned();
        if let Some(cache) = &self.ai_language_cache
            && cache.revision == revision
            && cache.configured == configured
        {
            return cache.resolved.clone();
        }
        let resolved = strop_core::language::resolve(manuscript, &configured);
        self.ai_language_cache = Some(AiLanguageCache {
            revision,
            configured,
            resolved: resolved.clone(),
        });
        resolved
    }

    fn run_pass(&mut self, kind: PassKind, cx: &mut Context<Self>) {
        if self.ai_worker_active {
            self.queued_ai_pass = Some(kind);
            self.ai_status = Some(AiStatus::Running {
                label: "waiting for the previous read to finish".into(),
            });
            cx.notify();
            return;
        }
        if matches!(self.ai_status, Some(AiStatus::Running { .. })) {
            return;
        }
        // A new request supersedes the attached menu's last-result record.
        self.ai_empty_result = None;
        // Re-read the config: edit → save → retry must work without a
        // restart (the guided config-file flow's contract).
        if let Ok(config) = crate::config::try_load() {
            self.config = config;
        }
        let ai = self.config.ai.clone();
        if !ai.configured() {
            // Remember what was asked: once a provider exists, THIS exact
            // pass (believing/doubting/depth) runs without the writer re-issuing.
            self.pending_pass = Some(kind);
            self.ai_generation += 1;
            self.ai_status = Some(AiStatus::NeedsSetup { local_model: None });
            self.probe_local_model(self.ai_generation, cx);
            cx.notify();
            return;
        }
        self.last_pass = kind.clone();
        // You asked to evaluate — open the door, so results land in a margin
        // the writer is actually looking at (and any earlier resting cards
        // come back into view alongside them). Asking again is also the most
        // explicit attention shift there is: a still-parked earlier pass
        // lands now rather than racing the run it just triggered.
        self.drafting = false;
        self.flush_deferred_pass(cx);
        // Scope is manuscript-relative even when the document has a compost
        // rail. A selected passage is the target; neighboring paragraphs are
        // context only. With no selection the whole piece is eligible up to
        // the deliberate cost/quality ceiling — never a silent prefix.
        let manuscript = self.doc.manuscript_slice().0;
        let mrange = self.doc.manuscript_char_range();
        let had_selection = !self.selected_range.is_empty();
        let selection = if !had_selection {
            None
        } else {
            let rope = self.doc.rope();
            let start = rope.byte_to_char(self.selected_range.start.min(rope.len_bytes()));
            let end = rope.byte_to_char(self.selected_range.end.min(rope.len_bytes()));
            let start = start.max(mrange.start).min(mrange.end);
            let end = end.max(start).min(mrange.end);
            (start < end).then(|| (start - mrange.start)..(end - mrange.start))
        };
        if had_selection && selection.is_none() {
            self.ai_status = Some(AiStatus::Error {
                title: "The editor reads manuscript passages".into(),
                detail: "Select text in the manuscript and ask again.".into(),
                recovery: AiRecovery::ManuscriptSelection,
            });
            cx.notify();
            return;
        }
        let scope = match strop_core::diagnose::prompt_scope(&manuscript, selection) {
            Ok(scope) => scope,
            Err(error) => {
                self.ai_status = Some(AiStatus::Error {
                    title: "This is too long for one editor read".into(),
                    detail: format!("{error}. Select a shorter passage for now."),
                    recovery: AiRecovery::DismissOnly,
                });
                cx.notify();
                return;
            }
        };
        let target_language = self.resolved_ai_language(&manuscript);
        let max_tokens = output_token_budget(&kind, &target_language.code);
        // The staleness snapshot: the revision this read is asked against.
        // Integration compares it to the revision THEN — a "draft changed"
        // verdict without an actual change in between is a fabrication.
        let base_revision = self.doc.revision();
        self.ai_generation += 1;
        let generation = self.ai_generation;
        self.ai_worker_active = true;
        self.ai_status = Some(AiStatus::Running {
            label: format!("{} · {}", kind.run_label(), ai.model),
        });
        cx.notify();

        cx.spawn(async move |this, cx| {
            let api_key = ai.resolved_api_key();
            let base_url = ai.base_url.clone();
            let model = ai.model.clone();
            let result = cx
                .background_executor()
                .spawn(async move {
                    let client = strop_core::llm::LlmClient::new(&base_url, &api_key, &model);
                    // The pinned kind picks the prompt; a Diagnostic carries its
                    // own depth (so `system_prompt` never falls through to line).
                    let system = match &kind {
                        PassKind::Believing => strop_core::diagnose::believing_system_prompt(),
                        PassKind::Doubting => strop_core::diagnose::doubting_system_prompt(),
                        PassKind::Diagnostic(mode) => strop_core::diagnose::system_prompt(mode),
                    };
                    let user = strop_core::diagnose::user_prompt_scoped(
                        &scope.target,
                        &scope.context_before,
                        &scope.context_after,
                        &target_language.prompt_name,
                    );
                    let schema = strop_core::diagnose::response_schema(kind.mode_str());
                    let response = client
                        .chat_structured(&system, &user, max_tokens, &schema)
                        .map_err(AiFailure::Llm)?;
                    if let Some(refusal) = &response.refusal {
                        return Err(AiFailure::Refusal(refusal.clone()));
                    }
                    match response.finish_reason.as_deref() {
                        Some("length") => {
                            return Err(AiFailure::Truncated {
                                message: "the provider stopped at its output limit".into(),
                                whole_manuscript: scope.whole_manuscript,
                            });
                        }
                        Some("content_filter") => {
                            return Err(AiFailure::Refusal(
                                "the provider's content filter stopped the reply".into(),
                            ));
                        }
                        Some("stop") | None => {}
                        Some(reason) => {
                            return Err(AiFailure::Parse(format!(
                                "the completion ended with finish reason {reason}"
                            )));
                        }
                    }
                    let report = match strop_core::diagnose::parse_for(
                        &response.content,
                        kind.mode_str(),
                    ) {
                        Ok(report) => report,
                        Err(error) => return Err(AiFailure::Parse(error)),
                    };
                    if report.diagnoses.is_empty() && !report.rejected.is_empty() {
                        return Err(AiFailure::Parse(
                            strop_core::diagnose::rejection_summary(&report),
                        ));
                    }
                    let rejected = report.rejected.len();
                    let diagnoses = report.diagnoses;
                    let log = crate::ai_log::PassLog {
                        t_unix_ms: crate::ai_log::now_ms(),
                        provider: crate::ai_log::provider_host(&base_url),
                        model,
                        pass: kind.mode_str().to_owned(),
                        scope: if scope.whole_manuscript {
                            "whole".to_owned()
                        } else {
                            "selection".to_owned()
                        },
                        target_chars: scope.target.chars().count(),
                        finish_reason: response.finish_reason,
                        prompt_tokens: response.usage.prompt_tokens,
                        completion_tokens: response.usage.completion_tokens,
                        retries: response.retries,
                        latency_ms: response.latency_ms,
                        request_id: response.request_id,
                        accepted: diagnoses.len(),
                        rejected,
                        language: target_language.code,
                        language_source: target_language.source.as_str().to_owned(),
                        language_confidence: target_language.confidence,
                        language_reliable: target_language.reliable,
                    };
                    Ok(CompletedAiPass {
                        diagnoses,
                        rejected,
                        scope,
                        log,
                        base_revision,
                    })
                })
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                editor.ai_worker_active = false;
                if editor.ai_generation != generation {
                    if let Some(queued) = editor.queued_ai_pass.take() {
                        editor.run_pass(queued, cx);
                    } else {
                        cx.notify();
                    }
                    return; // cancelled or superseded — drop silently
                }
                match result {
                    Ok(completed) => {
                        crate::ai_log::record(&completed.log);
                        editor.deliver_pass_report(
                            completed.diagnoses,
                            completed.rejected,
                            Some(completed.scope),
                            completed.base_revision,
                            generation,
                            cx,
                        )
                    }
                    Err(failure) => {
                        crate::ai_log::record_failure(&crate::ai_log::FailureLog {
                            t_unix_ms: crate::ai_log::now_ms(),
                            provider: crate::ai_log::provider_host(
                                &editor.config.ai.base_url,
                            ),
                            model: &editor.config.ai.model,
                            pass: editor.last_pass.mode_str(),
                            failure: failure.kind(),
                        });
                        editor.ai_status = Some(failure.into_status(
                            &editor.config.ai.base_url,
                            &editor.config.ai.model,
                        ));
                    }
                }
                if let Some(queued) = editor.queued_ai_pass.take() {
                    editor.run_pass(queued, cx);
                }
                cx.notify();
            })
            .ok();
        })
        .detach();
    }

    fn cancel_ai_run(&mut self, _: &CancelAiRun, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        self.cancel_ai_run_inner(cx);
    }

    fn cancel_ai_run_inner(&mut self, cx: &mut Context<Self>) {
        // UI-level cancel: the response of the abandoned generation is
        // ignored when it lands (no need to abort the request itself).
        // A parked deferral dies with its generation too (flush checks it),
        // but drop it eagerly so nothing lingers.
        self.ai_generation += 1;
        self.ai_status = None;
        self.ai_empty_result = None;
        self.pending_pass = None;
        self.deferred_pass = None;
        self.queued_ai_pass = None;
        cx.notify();
    }

    /// Is the writer inside a live typing burst right now? True while the
    /// last real buffer edit is younger than `TYPING_LULL`. This one predicate
    /// is the entire "when may AI results land" model — no gaze tracking, no
    /// idle timers, no modes: prose recently changed ⇒ hold; still ⇒ land.
    fn typing_burst_live(&self) -> bool {
        self.last_text_edit
            .is_some_and(|t| t.elapsed() < TYPING_LULL)
    }

    /// Integrate a completed pass into the document NOW: anchor the quotes
    /// against the current text and route its outcome to cards, recovery, or
    /// the editor control's zero-result state.
    /// The single landing site for both the direct path (results arrive in a
    /// lull) and the deferred path (flushed after a burst).
    fn integrate_pass(
        &mut self,
        diagnoses: Vec<strop_core::diagnose::Diagnosis>,
        rejected: usize,
        scope: Option<strop_core::diagnose::PromptScope>,
        base_revision: u64,
        _generation: u64,
        cx: &mut Context<Self>,
    ) {
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_secs() as i64)
            .unwrap_or(0);
        let count = diagnoses.len();
        // Read BEFORE this integration's own mutations: did the document
        // actually change between the ask and the landing? Only an actual
        // change may ever be blamed for ungroundable quotes.
        let doc_changed = self.doc.revision() != base_revision;
        // Anchor against the text as it is NOW — quotes
        // that no longer match are dropped.
        self.diagnosis_pass += 1;
        let pass_id = self.diagnosis_pass;
        let grounded = ground_diagnoses(&self.doc, diagnoses, scope.as_ref(), now, pass_id);
        let groundable = grounded.groundable;
        let context_grounded = grounded.context_grounded;
        let target_missing = grounded.target_missing;
        let annotations = grounded.annotations;
        let kept = annotations.len();
        self.doc.add_diagnoses(annotations);
        // The strip's veil: which read landed, when, how many queries.
        self.doc
            .journal_mut()
            .record_event(strop_core::journal::JournalEvent::Pass {
                t: strop_core::journal::now_ms(),
                mode: self.last_pass.mode_str().to_owned(),
                cards: kept as u32,
            });
        self.mark_dirty();
        // The landed cards get one entrance fade (CARD_APPEAR); the marks
        // clear right after it finishes so nothing ever re-fades. Their ids
        // are exactly the open notes stamped with this pass.
        if kept > 0 {
            self.appearing = self
                .doc
                .notes()
                .open()
                .filter(|n| n.pass_id == pass_id)
                .map(|n| n.id)
                .collect();
            cx.spawn(async move |this, cx| {
                cx.background_executor()
                    .timer(CARD_APPEAR + Duration::from_millis(150))
                    .await;
                this.update(cx, |editor: &mut Editor, cx| {
                    editor.appearing.clear();
                    cx.notify();
                })
                .ok();
            })
            .detach();
        }
        match ai_landing(
            count,
            rejected,
            groundable,
            target_missing,
            kept,
            doc_changed,
            context_grounded,
        ) {
            AiLanding::Cards => {
                // The cards are the result. Malformed/stale sibling counts
                // remain in diagnostics; backend maintenance is not writer work.
                self.ai_status = None;
                self.ai_empty_result = None;
            }
            AiLanding::Invalid => {
                self.ai_empty_result = None;
                self.ai_status = Some(AiStatus::Error {
                    title: "The editor's reply could not be read".into(),
                    detail: "Try the read again. Operational details are in the AI diagnostics log."
                        .into(),
                    recovery: AiRecovery::Retry,
                });
            }
            AiLanding::Stale => {
                self.ai_empty_result = None;
                self.ai_status = Some(AiStatus::Error {
                    title: "The draft changed before the read landed".into(),
                    detail: "The old quotes were not attached to different text.".into(),
                    recovery: AiRecovery::ReadAgain,
                });
            }
            AiLanding::Unlanded => {
                // Verdict honesty: the revision did NOT change (or the
                // quotes only match context) — the failed grounding is the
                // read's, never the draft's. Short and factual; no advice.
                self.ai_empty_result = None;
                self.ai_status = Some(AiStatus::Error {
                    title: "The read did not land".into(),
                    detail: "The reply quoted text that is not in the passage it read.".into(),
                    recovery: AiRecovery::Retry,
                });
            }
            AiLanding::Empty => {
                // Structurally valid, normally completed, no rejected or
                // stale items, and no NEW cards. The control carries receipt.
                self.ai_status = None;
                self.ai_empty_result = Some(AiEmptyResult {
                    kind: self.last_pass.clone(),
                    unacknowledged: true,
                });
            }
        }
        cx.notify();
    }

    /// The arrival gate — the ONE decision of the reveal clock. Mid-typing-
    /// burst, results WAIT: landing now would pop squiggles into the sentence
    /// being typed and re-pack the lane under the writer's eyes. The lull
    /// watcher integrates them the moment the burst ends; scroll or the door
    /// flush sooner. Held UN-anchored on purpose — quotes anchor against the
    /// text as it stands at reveal, not at arrival. In a lull (the common
    /// case: the writer asked and is waiting), results land immediately.
    fn deliver_pass(
        &mut self,
        diagnoses: Vec<strop_core::diagnose::Diagnosis>,
        generation: u64,
        cx: &mut Context<Self>,
    ) {
        // The seed/demo path has no run_pass snapshot; "asked against the
        // current revision" is the honest equivalent.
        let base_revision = self.doc.revision();
        self.deliver_pass_report(diagnoses, 0, None, base_revision, generation, cx);
    }

    fn deliver_pass_report(
        &mut self,
        diagnoses: Vec<strop_core::diagnose::Diagnosis>,
        rejected: usize,
        scope: Option<strop_core::diagnose::PromptScope>,
        base_revision: u64,
        generation: u64,
        cx: &mut Context<Self>,
    ) {
        if self.drafting || self.typing_burst_live() || self.cold_read.is_some() {
            // F7: the reveal clock holds in the reading room — a pass
            // completing mid-read parks; exit flushes it after the
            // suppressed surfaces restore.
            self.deferred_pass = Some(DeferredPass {
                diagnoses,
                rejected,
                scope,
                generation,
                base_revision,
            });
            // The provider call is complete. Ready outranks neither a real
            // worker nor an error, so clear Running before the button derives
            // its face; this also removes Cancel from a result that is already
            // safely parked for reveal.
            self.ai_status = None;
            self.watch_for_lull(cx);
        } else {
            self.integrate_pass(diagnoses, rejected, scope, base_revision, generation, cx);
        }
    }

    /// Land the parked pass, if its generation still stands. Called by the
    /// lull watcher and by the explicit attention shifts (scroll, the door) —
    /// any of them may fire first; the `take()` makes the flush idempotent.
    fn flush_deferred_pass(&mut self, cx: &mut Context<Self>) {
        let Some(d) = self.deferred_pass.take() else {
            return;
        };
        if d.generation != self.ai_generation {
            return; // cancelled or superseded while parked
        }
        self.integrate_pass(d.diagnoses, d.rejected, d.scope, d.base_revision, d.generation, cx);
    }

    /// Poll (4×/s) until the typing burst ends, then flush the parked pass.
    /// Exits when the deferral is gone — flushed here, flushed by a scroll or
    /// the door, or dropped by a cancel — so at most one watcher does work,
    /// and a re-armed deferral just rides the loop that is already running.
    fn watch_for_lull(&mut self, cx: &mut Context<Self>) {
        cx.spawn(async move |this, cx| {
            loop {
                cx.background_executor()
                    .timer(Duration::from_millis(250))
                    .await;
                let done = this.update(cx, |editor: &mut Editor, cx| {
                    if editor.deferred_pass.is_none() {
                        return true;
                    }
                    // F7: the room holds results parked like a live burst
                    // does — the lull watcher waits it out; the exit flush
                    // usually lands them first.
                    if editor.drafting
                        || editor.typing_burst_live()
                        || editor.cold_read.is_some()
                    {
                        return false;
                    }
                    editor.flush_deferred_pass(cx);
                    true
                });
                if done.unwrap_or(true) {
                    break;
                }
            }
        })
        .detach();
    }

    /// Background probe for a local OpenAI-compatible model (Ollama's
    /// default port). Reuses `list_models` — connection-refused returns
    /// instantly when nothing is listening, so the cost on machines
    /// without it is negligible. On success it upgrades the live
    /// NeedsSetup card to offer a key-free, fully-local first pass.
    fn probe_local_model(&mut self, generation: u64, cx: &mut Context<Self>) {
        cx.spawn(async move |this, cx| {
            let found = cx
                .background_executor()
                .spawn(async move {
                    let client = strop_core::llm::LlmClient::new(LOCAL_OLLAMA_URL, "ollama", "");
                    client.list_models().ok().and_then(pick_local_model)
                })
                .await;
            let Some(model) = found else { return };
            this.update(cx, |editor: &mut Editor, cx| {
                // Only if the writer is still looking at the same unfulfilled
                // setup card (not cancelled, not already configured/running).
                if editor.ai_generation == generation
                    && matches!(editor.ai_status, Some(AiStatus::NeedsSetup { .. }))
                {
                    editor.ai_status = Some(AiStatus::NeedsSetup {
                        local_model: Some(model),
                    });
                    cx.notify();
                }
            })
            .ok();
        })
        .detach();
    }

    /// One-click local path: point the config at Ollama, then run the pass
    /// the writer already asked for. No key, no signup, no leaving the app —
    /// and the manuscript never leaves the machine.
    fn use_local_model(&mut self, model: String, cx: &mut Context<Self>) {
        match crate::config::save_ai(LOCAL_OLLAMA_URL, None, &model) {
            Ok(_) => {
                self.config = crate::config::load();
                self.ai_status = None;
                self.run_pending_pass(cx);
            }
            Err(e) => {
                self.ai_status = Some(AiStatus::Error {
                    title: "Couldn't save the local provider".to_owned(),
                    detail: e,
                    recovery: AiRecovery::RetryLocal(model),
                });
                cx.notify();
            }
        }
    }

    /// Run whatever pass was queued while the provider was being set up;
    /// defaults to a diagnosis if the queue is empty (the writer reached
    /// setup some other way — running the core feature is the right guess).
    fn run_pending_pass(&mut self, cx: &mut Context<Self>) {
        let kind = self
            .pending_pass
            .take()
            .unwrap_or_else(|| PassKind::Diagnostic(self.effective_mode()));
        self.run_pass(kind, cx);
    }

    /// Guided config-file escape hatch: ensure the commented template exists
    /// and open it. The opened editor is its own receipt; the template carries
    /// its instructions.
    fn open_ai_config(&mut self, _: &OpenAiConfig, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        let path = crate::config::write_template_if_missing();
        crate::files::open_external(&path);
        cx.notify();
    }

    /// The palette's legacy Test command now routes into the owning settings
    /// form and reports Running/OK/Failed inline there.
    fn test_ai_connection(
        &mut self,
        _: &TestAiConnection,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        self.open_ai_settings(&OpenAiSettings, window, cx);
        if self.ai_settings.is_some() {
            self.ai_settings_test(cx);
        }
    }

    /// The AI settings panel (F4): the in-app surface for the core
    /// onboarding task. Prefilled from config.toml; Save writes back
    /// through toml_edit, so the file stays the storage and hand edits
    /// stay respected (DESIGN §0 directive 3).
    fn open_ai_settings(&mut self, _: &OpenAiSettings, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.ai_settings.is_some() {
            return;
        }
        let cfg = crate::config::load();
        let base_url = cx.new(|cx| TextField::settings(cx, cfg.ai.base_url.clone(), false));
        let api_key = cx.new(|cx| TextField::settings(cx, cfg.ai.api_key.clone(), true));
        let model = cx.new(|cx| TextField::settings(cx, cfg.ai.model.clone(), false));
        for input in [&base_url, &api_key, &model] {
            cx.subscribe_in(
                input,
                window,
                |editor, _, event: &TextFieldEvent, window, cx| match event {
                    TextFieldEvent::Commit(_) => editor.ai_settings_commit(cx),
                    TextFieldEvent::Cancel => editor.close_ai_settings(window, cx),
                },
            )
            .detach();
        }
        // Typing in the model field re-filters the list live.
        cx.observe(&model, |editor, _, cx| {
            if let Some(panel) = &mut editor.ai_settings {
                panel.selected = 0;
            }
            cx.notify();
        })
        .detach();
        cx.observe(&base_url, |_, _, cx| cx.notify()).detach();
        cx.observe(&api_key, |_, _, cx| cx.notify()).detach();
        let focus = base_url.read(cx).focus_handle.clone();
        window.focus(&focus, cx);
        self.ai_settings = Some(AiSettings {
            base_url,
            api_key,
            model,
            test: AiSettingsTest::Idle,
            models: Vec::new(),
            selected: 0,
            models_note: None,
        });
        cx.notify();
    }

    fn close_ai_settings(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        self.ai_settings = None;
        self.ai_settings_generation += 1; // drop in-flight test/list replies
        window.focus(&self.focus_handle, cx);
        cx.notify();
    }

    /// (base_url, api_key, model) as currently typed, trimmed.
    fn ai_settings_values(&self, cx: &Context<Self>) -> Option<(String, String, String)> {
        let panel = self.ai_settings.as_ref()?;
        Some((
            panel.base_url.read(cx).content.trim().to_owned(),
            panel.api_key.read(cx).content.trim().to_owned(),
            panel.model.read(cx).content.trim().to_owned(),
        ))
    }

    /// Models matching the model field (case-insensitive substring);
    /// empty field = the whole list.
    fn ai_settings_filtered(&self, cx: &Context<Self>) -> Vec<String> {
        let Some(panel) = self.ai_settings.as_ref() else {
            return Vec::new();
        };
        let query = panel.model.read(cx).content.trim().to_lowercase();
        panel
            .models
            .iter()
            .filter(|m| query.is_empty() || m.to_lowercase().contains(&query))
            .cloned()
            .collect()
    }

    /// Enter in any panel field: pick from the visible model list if it
    /// still offers something new; otherwise run the test call.
    fn ai_settings_commit(&mut self, cx: &mut Context<Self>) {
        let filtered = self.ai_settings_filtered(cx);
        let Some(panel) = &mut self.ai_settings else {
            return;
        };
        if let Some(pick) = filtered.get(panel.selected.min(filtered.len().saturating_sub(1))) {
            let already = panel.model.read(cx).content.trim() == pick.as_str();
            if !already {
                let pick = pick.clone();
                panel.model.update_checked(cx, |input, cx| {
                    input.content = pick;
                    cx.notify();
                });
                cx.notify();
                return;
            }
        }
        self.ai_settings_test(cx);
    }

    fn settings_up(&mut self, _: &SettingsUp, _: &mut Window, cx: &mut Context<Self>) {
        if let Some(panel) = &mut self.ai_settings {
            panel.selected = panel.selected.saturating_sub(1);
            cx.notify();
        }
    }

    fn settings_down(&mut self, _: &SettingsDown, _: &mut Window, cx: &mut Context<Self>) {
        let len = self.ai_settings_filtered(cx).len();
        if let Some(panel) = &mut self.ai_settings
            && len > 0
        {
            panel.selected = (panel.selected + 1).min(len - 1);
            cx.notify();
        }
    }

    /// [Test]: the same 1-token chat as Test AI Connection, but against
    /// the values typed in the form (not yet saved), reported inline.
    fn ai_settings_test(&mut self, cx: &mut Context<Self>) {
        let Some((base_url, key, model)) = self.ai_settings_values(cx) else {
            return;
        };
        let Some(panel) = &mut self.ai_settings else {
            return;
        };
        if base_url.is_empty() || model.is_empty() {
            panel.test = AiSettingsTest::Failed {
                message: "base URL and model are both needed for a test call".into(),
            };
            cx.notify();
            return;
        }
        panel.test = AiSettingsTest::Running;
        self.ai_settings_generation += 1;
        let generation = self.ai_settings_generation;
        cx.notify();
        cx.spawn(async move |this, cx| {
            let api_key = resolved_key(&key);
            let result = cx
                .background_executor()
                .spawn(async move {
                    let client = strop_core::llm::LlmClient::new(&base_url, &api_key, &model);
                    let started = std::time::Instant::now();
                    client
                        .chat("Reply with exactly: ok", "ok?", 16)
                        .map(|_| started.elapsed().as_millis() as u64)
                })
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                if editor.ai_settings_generation != generation {
                    return;
                }
                let (base_url, model) = match editor.ai_settings_values(cx) {
                    Some((b, _, m)) => (b, m),
                    None => return,
                };
                match result {
                    Ok(ms) => {
                        if let Some(panel) = &mut editor.ai_settings {
                            panel.test = AiSettingsTest::Ok { ms };
                        }
                        // A provider that just answered can also tell us
                        // what it serves: refresh the picker for free.
                        editor.ai_settings_list_models(cx);
                    }
                    Err(e) => {
                        let AiStatus::Error { title, detail, .. } =
                            AiFailure::Llm(e).into_status(&base_url, &model)
                        else {
                            unreachable!("into_status always errors")
                        };
                        if let Some(panel) = &mut editor.ai_settings {
                            panel.test = AiSettingsTest::Failed {
                                message: if detail.is_empty() {
                                    title
                                } else {
                                    format!("{title} — {detail}")
                                },
                            };
                        }
                    }
                }
                cx.notify();
            })
            .ok();
        })
        .detach();
    }

    /// A provider chip was clicked: drop its base URL into the field, clear
    /// stale test state, and — for the local provider, which needs no key —
    /// list its models straight away so the writer can pick and go.
    fn ai_settings_pick_provider(&mut self, base_url: &'static str, list: bool, cx: &mut Context<Self>) {
        let Some(panel) = &mut self.ai_settings else {
            return;
        };
        panel.test = AiSettingsTest::Idle;
        if !base_url.is_empty() {
            panel.base_url.update_checked(cx, |input, cx| {
                input.content = base_url.to_owned();
                cx.notify();
            });
        }
        if list {
            self.ai_settings_list_models(cx);
        }
        cx.notify();
    }

    /// [List models]: GET {base}/models on the background executor; the
    /// result is the pickable, filterable list (Open WebUI's flow).
    fn ai_settings_list_models(&mut self, cx: &mut Context<Self>) {
        let Some((base_url, key, _)) = self.ai_settings_values(cx) else {
            return;
        };
        let Some(panel) = &mut self.ai_settings else {
            return;
        };
        if base_url.is_empty() {
            panel.models_note = Some("base URL is needed to list models".into());
            cx.notify();
            return;
        }
        panel.models_note = Some("fetching model list…".into());
        self.ai_settings_generation += 1;
        let generation = self.ai_settings_generation;
        cx.notify();
        cx.spawn(async move |this, cx| {
            let api_key = resolved_key(&key);
            let result = cx
                .background_executor()
                .spawn(async move {
                    let client = strop_core::llm::LlmClient::new(&base_url, &api_key, "");
                    client.list_models()
                })
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                if editor.ai_settings_generation != generation {
                    return;
                }
                let Some(panel) = &mut editor.ai_settings else {
                    return;
                };
                match result {
                    Ok(models) if models.is_empty() => {
                        panel.models = Vec::new();
                        panel.models_note = Some("the provider returned an empty list".into());
                    }
                    Ok(models) => {
                        panel.models = models;
                        panel.selected = 0;
                        panel.models_note = None;
                    }
                    Err(e) => {
                        panel.models_note = Some(format!("couldn't list models: {e}"));
                    }
                }
                cx.notify();
            })
            .ok();
        })
        .detach();
    }

    /// [Save] / ctrl-enter: validate and write through toml_edit (comments and
    /// unknown keys survive), then close. The changed editor control is the
    /// receipt; incomplete settings remain inline instead of closing as success.
    fn save_ai_settings(&mut self, _: &SaveAiSettings, window: &mut Window, cx: &mut Context<Self>) {
        let Some((base_url, key, model)) = self.ai_settings_values(cx) else {
            return;
        };
        if base_url.is_empty() || model.is_empty() {
            if let Some(panel) = &mut self.ai_settings {
                panel.test = AiSettingsTest::Failed {
                    message: "base URL and model are both needed before saving".into(),
                };
            }
            cx.notify();
            return;
        }
        // STROP_API_KEY wins over the file; never write a key the
        // environment is already supplying (the panel says so too).
        let key_from_env = env_key_set();
        let api_key = (!key_from_env).then_some(key.as_str());
        match crate::config::save_ai(&base_url, api_key, &model) {
            Ok(_) => {
                self.config = crate::config::load();
                self.close_ai_settings(window, cx);
                self.ai_generation += 1;
                // The whole point of setup was to run a pass — so if one was
                // queued (the writer pressed ctrl-shift-d, hit the wall, and
                // came here), answer it now instead of making them re-ask.
                if self.config.ai.configured() && self.pending_pass.is_some() {
                    self.run_pending_pass(cx);
                } else {
                    self.ai_status = None;
                }
            }
            Err(e) => {
                if let Some(panel) = &mut self.ai_settings {
                    panel.test = AiSettingsTest::Failed { message: e };
                }
            }
        }
        cx.notify();
    }

    /// The omnibox (DESIGN §2-omnibox): one top-centre field, prefix-
    /// dispatched — plain text finds, `>` runs a command, `@` jumps to a
    /// heading. `palette_input` is its field; the `palette_*` machinery is
    /// shared across all three modes. `initial` seeds the query (and so the
    /// mode): "" = find, ">" = command, "@" = heading.
    fn open_omni(&mut self, initial: String, window: &mut Window, cx: &mut Context<Self>) {
        // One situational popup at a time (§0.6): summoning the omnibar
        // stands the editor menu down.
        self.close_editor_menu(cx);
        // A fresh field every open (the old entity drops); PaletteInput
        // context gives it up/down row motion and the editing chords.
        let input = cx.new(|cx| TextField::palette(cx, initial.clone()));
        cx.observe(&input, |editor, input, cx| {
            let q = input.read(cx).content.clone();
            editor.palette_query = q.clone();
            editor.replace_result = None;
            editor.palette_selected = 0; // query changed: selection restarts
            // Find previews live — the match scrolls into view as you type,
            // behind the omnibox (this is what dissolves the old bottom-strip
            // "match hidden under the find field" bug).
            if matches!(omni_mode(&q).0, OmniMode::Find) {
                editor.omni_apply_match(0, cx);
            } else {
                // Selection restarted at row 0 (above): the list should
                // follow it back to the top, not stay scrolled wherever the
                // previous query's browsing left it.
                editor.omni_scroll_into_view(0);
                if let Some(sel) = editor.omni_return.clone() {
                    // Leaving find mode (a `>` or `@` prefix) would park the
                    // preview selection on the last match — and a command
                    // executed next would act on it (the cross-mode selection
                    // leak, extraction audit #23). Walk it home; deleting the
                    // prefix re-enters find and re-previews.
                    let max = editor.doc.len_bytes();
                    editor.selected_range = sel.start.min(max)..sel.end.min(max);
                    editor.selection_reversed = false;
                }
            }
            cx.notify();
        })
        .detach();
        cx.subscribe_in(
            &input,
            window,
            |editor, input, event: &TextFieldEvent, window, cx| match event {
                TextFieldEvent::Commit(_) => {
                    let q = input.read(cx).content.clone();
                    // Find: Enter cycles to the next match, bar stays open.
                    // Command/heading: Enter runs the selected row and closes.
                    if matches!(omni_mode(&q).0, OmniMode::Find) {
                        editor.omni_find_next(cx);
                    } else {
                        editor.execute_palette_entry(&q, editor.palette_selected, window, cx);
                    }
                }
                TextFieldEvent::Cancel => {
                    // Esc restores the selection the omnibar opened on (S3,
                    // P13): the find preview walked `selected_range` across
                    // matches; cancel walks it home and scrolls it back in.
                    // This IS the excursion's Esc-home for a find that jumped
                    // below the seam, so it clears the latch too (or a later
                    // scroll-entered caret would teleport) — and remembers the
                    // skim stop as `pile_end` when the preview was parked there.
                    if editor.excursion.take().is_some() && editor.caret_in_scraps() {
                        editor.pile_end = Some(editor.cursor_offset());
                    }
                    if let Some(sel) = editor.omni_return.take() {
                        let max = editor.doc.len_bytes();
                        editor.selected_range = sel.start.min(max)..sel.end.min(max);
                        editor.selection_reversed = false;
                        editor.autoscroll_request = true;
                    }
                    editor.close_palette(window, cx)
                }
            },
        )
        .detach();
        let input_focus = input.read(cx).focus_handle.clone();
        window.focus(&input_focus, cx);
        self.omni_return = Some(self.selected_range.clone());
        self.palette_input = Some(input);
        self.replace_input = None;
        self.replace_result = None;
        self.palette_selected = 0;
        self.palette_query = initial.clone();
        // The handle outlives any one open/close cycle (it lives on the
        // Editor); a fresh open must not inherit wherever the last session
        // left the list scrolled.
        self.omni_scroll_into_view(0);
        // Read once per open, not per keystroke; executions write through to
        // disk AND to this copy, so the session stays self-consistent.
        self.palette_freq = crate::files::load_palette_freq();
        if !initial.is_empty() && matches!(omni_mode(&initial).0, OmniMode::Find) {
            self.omni_apply_match(0, cx);
        }
        cx.notify();
    }

    /// ctrl-f / the titlebar search pill: the omnibox in find mode, seeded
    /// with the selection so "select, ctrl-f" searches for it.
    fn find(&mut self, _: &Find, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        let seed = if self.selected_range.is_empty() {
            String::new()
        } else {
            // The seam never enters the query (scopes-search 2): a spanning
            // selection seeds the joined fragments, separator stripped.
            self.selection_text(&self.selected_range.clone())
        };
        self.open_omni(seed, window, cx);
    }

    /// The find-mode match ranges for the current query (empty otherwise).
    /// Case-insensitive (first-lowercase-char folding — exact for RU/EN,
    /// approximate for ß-class expansions).
    fn omni_match_ranges(&self) -> Vec<Range<usize>> {
        match omni_mode(&self.palette_query) {
            (OmniMode::Find, rest) => self.find_matches(rest),
            _ => Vec::new(),
        }
    }

    /// The find matches split by region (scopes-search 2): (in the piece,
    /// in scraps, capped). `capped` = the 500-match cap was hit, so the true
    /// totals are unknown — an announced split must degrade to "500+", never
    /// state an exact lie.
    fn find_split(&self, matches: &[Range<usize>]) -> (usize, usize, bool) {
        let m = self.doc.manuscript_char_range();
        let (ms, me) = (self.doc.char_to_byte(m.start), self.doc.char_to_byte(m.end));
        let piece = matches
            .iter()
            .filter(|r| r.start >= ms && r.start < me)
            .count();
        (piece, matches.len() - piece, matches.len() >= 500)
    }

    /// Move the document selection to the ix-th find match and scroll it into
    /// view (live preview for type / arrow / Enter / click). No-op off find
    /// mode or with no matches.
    fn omni_apply_match(&mut self, ix: usize, cx: &mut Context<Self>) {
        let matches = self.omni_match_ranges();
        if matches.is_empty() {
            return;
        }
        let ix = ix.min(matches.len() - 1);
        self.palette_selected = ix;
        self.omni_scroll_into_view(ix);
        // A find jump landing below the seam is a TRAVEL: it arms the
        // excursion latch (scopes-search 1) with home = the pre-find caret
        // (omni_return) and the scroll before this jump — so Esc-Esc
        // habituation works: Esc closes find, Esc travels home.
        let scroll_before = f32::from(self.scroll_top);
        self.selected_range = matches[ix].clone();
        self.selection_reversed = false;
        let start_ch = self
            .doc
            .rope()
            .byte_to_char(self.selected_range.start.min(self.doc.len_bytes()));
        if self.excursion.is_none()
            && self.doc.region_of_char(start_ch) == strop_core::document::Region::Scraps
        {
            let home = self
                .omni_return
                .as_ref()
                .map(|r| r.end)
                .unwrap_or(self.last_manuscript_caret);
            self.excursion = Some((home, scroll_before));
        }
        self.bump_activity();
        cx.notify();
    }

    /// Enter in find mode: advance to the next match, wrapping.
    fn omni_find_next(&mut self, cx: &mut Context<Self>) {
        let matches = self.omni_match_ranges();
        if matches.is_empty() {
            return;
        }
        let next = (self.palette_selected + 1) % matches.len();
        self.omni_apply_match(next, cx);
    }

    /// Tab hops between the omnibox query field and the replace field (the
    /// action bubbles up from the PaletteInput/NoteInput context to here),
    /// and cycles the AI settings panel's fields.
    fn note_tab(&mut self, _: &FieldTab, window: &mut Window, cx: &mut Context<Self>) {
        // AI settings panel: tab cycles base URL → key → model → base URL.
        if let Some(panel) = &self.ai_settings {
            let fields = [&panel.base_url, &panel.api_key, &panel.model];
            let focused = fields
                .iter()
                .position(|f| f.read(cx).focus_handle.is_focused(window))
                .unwrap_or(2);
            let next = fields[(focused + 1) % fields.len()].read(cx).focus_handle.clone();
            window.focus(&next, cx);
            cx.notify();
            return;
        }
        let (Some(omni), Some(rep)) = (self.palette_input.clone(), self.replace_input.clone())
        else {
            return;
        };
        if omni.read(cx).focus_handle.is_focused(window) {
            let h = rep.read(cx).focus_handle.clone();
            window.focus(&h, cx);
        } else {
            let h = omni.read(cx).focus_handle.clone();
            window.focus(&h, cx);
        }
        cx.notify();
    }

    /// ctrl-shift-p / F10 / the titlebar menu button: the omnibox in command
    /// mode — every command the app has, searchable, chord on the row (the
    /// menu bar of a chrome-minimal editor, PLAN.md E1). Already in command
    /// mode → close; in another mode → switch to it; closed → open.
    fn toggle_palette(&mut self, _: &TogglePalette, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.palette_input.is_some()
            && matches!(omni_mode(&self.palette_query).0, OmniMode::Command)
        {
            self.close_palette(window, cx);
            return;
        }
        self.open_omni(">".into(), window, cx);
    }

    fn close_palette(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        self.palette_input = None;
        self.replace_input = None;
        self.replace_result = None;
        self.omni_return = None;
        window.focus(&self.focus_handle, cx);
        cx.notify();
    }

    /// One window per document, one process per window: simple, and two
    /// windows can never fight over the same CRDT file.
    fn new_document(&mut self, _: &NewDocument, _: &mut Window, _: &mut Context<Self>) {
        crate::files::new_window_blank();
    }

    fn reveal_in_files(&mut self, _: &RevealInFiles, _: &mut Window, _: &mut Context<Self>) {
        if let Some(store) = &self.store {
            crate::files::reveal(store.path());
        }
    }

    fn copy_document_path(&mut self, _: &CopyDocumentPath, _: &mut Window, cx: &mut Context<Self>) {
        if let Some(store) = &self.store {
            cx.write_to_clipboard(ClipboardItem::new_string(
                store.path().display().to_string(),
            ));
        }
    }

    /// F2 or clicking the titlebar name: rename the document in place —
    /// the file on disk is renamed too (visible-from-birth contract).
    fn rename_document(&mut self, _: &RenameDocument, window: &mut Window, cx: &mut Context<Self>) {
        let Some(store) = &self.store else { return };
        if self.doc_rename_input.is_some() {
            return;
        }
        let stem = store
            .path()
            .file_stem()
            .and_then(|s| s.to_str())
            .unwrap_or("Untitled")
            .to_owned();
        let input = cx.new(|cx| TextField::single(cx, stem));
        cx.observe(&input, |_, _, cx| cx.notify()).detach();
        cx.subscribe_in(
            &input,
            window,
            |editor, _, event: &TextFieldEvent, window, cx| match event {
                TextFieldEvent::Commit(title) => editor.finish_rename(title.clone(), window, cx),
                TextFieldEvent::Cancel => {
                    editor.doc_rename_input = None;
                    editor.doc_rename_error = None;
                    window.focus(&editor.focus_handle, cx);
                    cx.notify();
                }
            },
        )
        .detach();
        // Click-away commits the rename (the title is a real edit, like the
        // note composer's body — losing focus should save it, not drop it). Via
        // the SHARED blur grace (finding 6 / LAW 2): a bare focus-out — the
        // transient blur a keyboard-layout switch fires — must not commit
        // mid-rename; only a real departure does. The Commit it emits routes
        // through the subscription above (finish_rename), which no-ops if the
        // field already closed.
        self.commit_field_on_blur(&input, window, cx, |e| e.doc_rename_input.clone());
        let input_focus = input.read(cx).focus_handle.clone();
        window.focus(&input_focus, cx);
        self.doc_rename_input = Some(input);
        cx.notify();
    }

    fn finish_rename(&mut self, title: String, window: &mut Window, cx: &mut Context<Self>) {
        self.doc_rename_error = None;
        let Some(stem) = crate::files::stem_from_title(&title) else {
            self.doc_rename_input = None;
            window.focus(&self.focus_handle, cx);
            cx.notify();
            return;
        };
        // Pending snapshots capture their destination; drain before moving so
        // a delayed write cannot recreate the old path after the rename.
        if let Err(e) = self.flush_saves() {
            eprintln!("strop: save before rename: {e}");
            self.doc_rename_input = None;
            window.focus(&self.focus_handle, cx);
            cx.notify();
            return;
        }
        if let Some(store) = &mut self.store {
            let old = store.path().to_owned();
            // Mint the new name in the HOST directory, never inside the
            // portal mount — a foreign filename in a doc mount becomes an
            // invisible `.xdp-*` temp on the host (files.rs law).
            let new_path = crate::files::host_parent_or_documents(&old)
                .join(format!("{stem}.strop"));
            match store.rename_file(new_path) {
                Ok(()) => {
                    crate::files::replace_recent(&old, store.path());
                    crate::files::add_platform_recent(store.path(), cx);
                    window.set_window_title(&format!("{stem} — Strop"));
                    self.doc_rename_input = None;
                    window.focus(&self.focus_handle, cx);
                }
                Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => {
                    self.doc_rename_error = Some("another file has this name");
                    if let Some(input) = &self.doc_rename_input {
                        let focus = input.read(cx).focus_handle.clone();
                        window.focus(&focus, cx);
                    }
                }
                Err(e) => {
                    eprintln!("strop: rename: {e}");
                    self.doc_rename_input = None;
                    window.focus(&self.focus_handle, cx);
                }
            }
        }
        cx.notify();
    }

    /// Commands first (ranked), then recent documents that match — the
    /// palette is both the menu and the door to the other essays. The
    /// empty state opens with a Frequent section (DESIGN §3.3): the five
    /// most-executed commands, which repeat in their home sections below.
    /// The rows for the current query, dispatched by prefix mode: find
    /// matches (with a line snippet), commands + frequent + recents, or
    /// headings filtered by the same fuzzy matcher.
    fn omni_rows(&self, query: &str) -> Vec<OmniRow> {
        let (mode, rest) = omni_mode(query);
        match mode {
            OmniMode::Find => self
                .find_matches(rest)
                .into_iter()
                .take(100)
                .map(|range| {
                    let start = range.start.min(self.doc.len_bytes());
                    let line = self.doc.rope().byte_to_line(start);
                    OmniRow::Match {
                        line,
                        snippet: self.omni_line_snippet(line),
                        scraps: self.byte_in_scraps(start),
                    }
                })
                .collect(),
            OmniMode::Heading => self
                .outline_items()
                .into_iter()
                .filter(|(_, _, text, _)| {
                    rest.is_empty() || crate::commands::score_text(rest, text).is_some()
                })
                .map(|(_, level, text, byte)| OmniRow::Heading {
                    byte,
                    level,
                    text,
                    scraps: self.byte_in_scraps(byte),
                })
                .collect(),
            OmniMode::Command => {
                let mut rows: Vec<OmniRow> = Vec::new();
                if rest.trim().is_empty() {
                    rows.extend(
                        crate::commands::frequent(&self.palette_freq)
                            .into_iter()
                            .map(OmniRow::Frequent),
                    );
                }
                rows.extend(
                    crate::commands::ranked_with_freq(rest, &self.palette_freq)
                        .into_iter()
                        .map(OmniRow::Cmd),
                );
                let current = self.store.as_ref().map(|s| s.path().to_owned());
                for p in crate::files::recents() {
                    if Some(&p) == current.as_ref() {
                        continue;
                    }
                    let name = p.file_stem().and_then(|s| s.to_str()).unwrap_or("");
                    if rest.trim().is_empty()
                        || crate::commands::score_text(rest.trim(), name).is_some()
                    {
                        rows.push(OmniRow::Recent(p));
                    }
                }
                rows
            }
        }
    }

    /// A trimmed, length-capped preview of a document line, for find rows.
    fn omni_line_snippet(&self, line: usize) -> String {
        let rope = self.doc.rope();
        if line >= rope.len_lines() {
            return String::new();
        }
        let raw: String = rope.line(line).chars().take(160).collect();
        let trimmed = raw.trim();
        let mut s: String = trimmed.chars().take(80).collect();
        if trimmed.chars().count() > 80 {
            s.push('…');
        }
        s
    }

    fn execute_palette_entry(
        &mut self,
        query: &str,
        ix: usize,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        let rows = self.omni_rows(query);
        let Some(row) = rows.get(ix) else {
            return;
        };
        match row {
            OmniRow::Cmd(cmd) | OmniRow::Frequent(cmd) => {
                let cmd = *cmd;
                let action = (cmd.make)();
                // Frequency writes through on every execution (DESIGN
                // §3.3) — disk and the session's in-memory copy together.
                let count = crate::files::bump_palette_freq(cmd.label);
                self.palette_freq.insert(cmd.label.to_owned(), count);
                // Close first: focus returns to the document, so the action
                // lands exactly as if its chord had been pressed there.
                self.close_palette(window, cx);
                window.dispatch_action(action, cx);
            }
            OmniRow::Recent(path) => {
                let path = path.clone();
                self.close_palette(window, cx);
                crate::files::open_in_new_window(&path);
            }
            OmniRow::Match { .. } => {
                // Clicking/selecting a find row jumps to it and keeps the
                // omnibox open (find is iterative — Esc commits).
                self.omni_apply_match(ix, cx);
            }
            OmniRow::Heading { byte, .. } => {
                let byte = *byte;
                // An @-jump below the seam is a latch-setting travel
                // (scopes-search 7): home = the pre-jump caret and scroll.
                let home = (self.cursor_offset(), f32::from(self.scroll_top));
                let ch = self.doc.rope().byte_to_char(byte.min(self.doc.len_bytes()));
                let into_pile = self.doc.region_of_char(ch)
                    == strop_core::document::Region::Scraps;
                self.close_palette(window, cx);
                if into_pile && self.excursion.is_none() && !self.caret_in_scraps() {
                    self.excursion = Some(home);
                }
                self.set_cursor(byte.min(self.doc.len_bytes()), false, cx);
            }
        }
    }

    fn palette_up(&mut self, _: &PaletteUp, _: &mut Window, cx: &mut Context<Self>) {
        let sel = self.palette_selected.saturating_sub(1);
        // Find mode previews the row live (selection + scroll); the others
        // just move the highlight.
        if matches!(omni_mode(&self.palette_query).0, OmniMode::Find) {
            self.omni_apply_match(sel, cx);
        } else {
            self.palette_selected = sel;
            self.omni_scroll_into_view(sel);
            cx.notify();
        }
    }

    fn palette_down(&mut self, _: &PaletteDown, _: &mut Window, cx: &mut Context<Self>) {
        let len = self
            .palette_input
            .as_ref()
            .map_or(0, |i| self.omni_rows(&i.read(cx).content).len());
        if len == 0 {
            return;
        }
        let sel = (self.palette_selected + 1).min(len - 1);
        if matches!(omni_mode(&self.palette_query).0, OmniMode::Find) {
            self.omni_apply_match(sel, cx);
        } else {
            self.palette_selected = sel;
            self.omni_scroll_into_view(sel);
            cx.notify();
        }
    }

    /// Nudge the omni-list to keep row `ix` visible (the fold bug this
    /// closes: keyboard `palette_up`/`palette_down` used to move the
    /// highlight past the visible window without scrolling — the writer
    /// navigated blind). `ScrollHandle::scroll_to_item` requests the
    /// *minimal* correction and is a no-op when `ix` is already on-screen,
    /// so this never fights a manual mouse-wheel scroll that hasn't been
    /// invalidated by a fresh selection.
    fn omni_scroll_into_view(&self, ix: usize) {
        let rows = self.omni_rows(&self.palette_query);
        if rows.is_empty() {
            return;
        }
        let ix = ix.min(rows.len() - 1);
        if ix == 0 {
            // A direct reset, not an item-based scroll: on the very first
            // frame the omnibox ever opens, GPUI hasn't measured this div's
            // own viewport bounds yet (`ScrollHandle::bounds` lags a frame
            // behind the child bounds `scroll_to_item` math needs), so it
            // can undershoot by a row on a cold open. Setting the offset
            // straight to zero sidesteps that — and also reaches row 0's
            // section header in grouped mode (bare `>`), which `scroll_to_
            // item(0)` alone would only promise is "somewhere visible".
            self.omni_scroll.set_offset(point(px(0.), px(0.)));
            return;
        }
        let (mode, rest) = omni_mode(&self.palette_query);
        let grouped = mode == OmniMode::Command && rest.trim().is_empty();
        self.omni_scroll.scroll_to_item(omni_child_index(&rows, grouped, ix));
    }

    fn render_omni(&self, window: &Window, cx: &Context<Self>) -> impl IntoElement {
        let field_w = omni_field_width(window);
        let input = self.palette_input.clone().expect("omnibox open");
        let query = input.read(cx).content.clone();
        let (mode, rest) = omni_mode(&query);
        let rows = self.omni_rows(&query);
        let selected = self.palette_selected.min(rows.len().saturating_sub(1));
        // Sections group only the command empty-state (Frequent / File / …);
        // find and heading rows are flat.
        let grouped = mode == OmniMode::Command && rest.trim().is_empty();
        let home = crate::paths::home_dir().to_string_lossy().into_owned();
        let mut list = div()
            .id("omni-list")
            .track_scroll(&self.omni_scroll)
            .max_h(px(420.))
            .overflow_y_scroll()
            .flex()
            .flex_col()
            .pb(px(6.));
        let mut last_section = "";
        for (ix, row) in rows.iter().enumerate() {
            let missing = matches!(row, OmniRow::Recent(path) if !path.exists());
            if grouped {
                let section = omni_row_section(row);
                if section != last_section {
                    last_section = section;
                    list = list.child(
                        div()
                            .px(px(12.))
                            .pt(px(10.))
                            .pb(px(2.))
                            .text_size(px(10.))
                            .text_color(rgb(MUTED_COLOR))
                            .child(section.to_uppercase()),
                    );
                }
            }
            // Left label, optional right detail, optional leading gutter
            // (find's line number / heading's level indent).
            let (label, right, lead): (String, Option<String>, Option<String>) = match row {
                OmniRow::Cmd(cmd) | OmniRow::Frequent(cmd) => {
                    (cmd.label.to_owned(), cmd.keys.map(|k| k.to_owned()), None)
                }
                OmniRow::Recent(p) => {
                    let mut stem = p.file_stem().and_then(|s| s.to_str()).unwrap_or("?").to_owned();
                    if missing {
                        stem.push_str(" · missing");
                    }
                    let dir = p
                        .parent()
                        .map(|d| d.display().to_string().replace(&home, "~"))
                        .unwrap_or_default();
                    (stem, Some(dir), None)
                }
                OmniRow::Match { line, snippet, scraps, .. } => (
                    snippet.clone(),
                    // The region as DATA, the find-split's register: a row
                    // that jumps into the pile says so before the jump.
                    scraps.then(|| "scraps".to_owned()),
                    Some(format!("{}", line + 1)),
                ),
                OmniRow::Heading { level, text, scraps, .. } => {
                    let indent = "  ".repeat((*level as usize).saturating_sub(1));
                    (
                        format!("{indent}{text}"),
                        Some(if *scraps {
                            format!("H{level} · scraps")
                        } else {
                            format!("H{level}")
                        }),
                        None,
                    )
                }
            };
            list = list.child(
                div()
                    .id(("omni-row", ix))
                    .px(px(12.))
                    .py(px(4.))
                    .flex()
                    .items_center()
                    .gap(px(10.))
                    .cursor(CursorStyle::PointingHand)
                    .when(missing, |d| d.bg(rgb(STALE_BG)))
                    .when(ix == selected, |d| d.bg(rgba(0x1A1A1812u32)))
                    .hover(|d| d.bg(rgba(0x1A1A180Au32)))
                    .on_mouse_down(
                        MouseButton::Left,
                        cx.listener(move |editor, _: &MouseDownEvent, window, cx| {
                            cx.stop_propagation();
                            let q = editor
                                .palette_input
                                .as_ref()
                                .map(|i| i.read(cx).content.clone())
                                .unwrap_or_default();
                            editor.execute_palette_entry(&q, ix, window, cx);
                        }),
                    )
                    .when_some(lead, |d, lead| {
                        d.child(
                            div()
                                .w(px(28.))
                                .flex_shrink_0()
                                .text_size(px(11.))
                                .text_color(rgb(MUTED_COLOR))
                                .child(lead),
                        )
                    })
                    .child(
                        div()
                            .flex_1()
                            .min_w(px(0.))
                            .truncate()
                            .text_size(px(13.))
                            .text_color(rgb(if missing { MUTED_COLOR } else { TEXT_COLOR }))
                            .child(label),
                    )
                    .when_some(right, |d, right| {
                        d.child(
                            div()
                                .flex_shrink_0()
                                .text_size(px(11.))
                                .text_color(rgb(MUTED_COLOR))
                                .max_w(px(220.))
                                .truncate()
                                .child(right),
                        )
                    }),
            );
        }
        if rows.is_empty() {
            list = list.child(if mode == OmniMode::Find && rest.is_empty() {
                // The hint row IS the controls it names (the ordering
                // round's Birman note: a button that types ">" is labelled
                // ">"): each sigil phrase is an inline action that types
                // its sigil into the field — the hint teaches by doing.
                let sigil = |id: &'static str, label: &'static str, seed: &'static str| {
                    inline_action(id, label).on_mouse_down(
                        MouseButton::Left,
                        cx.listener(move |editor, _: &MouseDownEvent, window, cx| {
                            cx.stop_propagation();
                            editor.open_omni(seed.into(), window, cx);
                        }),
                    )
                };
                div()
                    .px(px(12.))
                    .py(px(8.))
                    .text_size(px(13.))
                    .text_color(rgb(MUTED_COLOR))
                    .flex()
                    .flex_wrap()
                    .items_center()
                    .gap(px(6.))
                    .child("Type to find")
                    .child("·")
                    .child(sigil("omni-hint-cmd", "> for commands", ">"))
                    .child("·")
                    .child(sigil("omni-hint-head", "@ for headings", "@"))
                    .into_any_element()
            } else {
                let msg = match mode {
                    OmniMode::Find => "No matches",
                    OmniMode::Heading => "No headings",
                    OmniMode::Command => "No matching command",
                };
                div()
                    .px(px(12.))
                    .py(px(8.))
                    .text_size(px(13.))
                    .text_color(rgb(MUTED_COLOR))
                    .child(msg)
                    .into_any_element()
            });
        }
        // The query input lives in the TITLEBAR now (06 §1) — the card is the
        // field's dropdown: results (+ the replace row, a sanctioned distinct
        // function, S6), never a second query input. The match counter rides
        // the titlebar field. A mousedown on card chrome that isn't a row
        // refocuses the query (H2): the card must never look active while
        // keystrokes route to the prose behind it.
        let query_focus = input.read(cx).focus_handle.clone();
        div()
            .absolute()
            .top(px(BAR_HEIGHT + 2.))
            .left_0()
            .right_0()
            .flex()
            .justify_center()
            .child(
                // The dropdown wears the field's own width (06 §1): equal
                // boxes on the same centre line — every edge agrees, and the
                // card reads as the field's shadow, not a second object.
                // The left margin mirrors the titlebar's ensemble geometry
                // (menu button + gap ride the field's left flank), so the
                // centring math lands this card exactly under the field.
                div().w(px(field_w)).ml(px(OMNI_MENU_W)).child(
                    div()
                        .w(px(field_w))
                        .bg(rgb(0xFCFAF4))
                        .border_1()
                        .border_color(rgb(RULE_COLOR))
                        .rounded(px(8.))
                        .shadow_lg()
                        .font_family("PT Serif")
                        .flex()
                        .flex_col()
                        // §0.6: clicks inside the omnibox stay in it (rows
                        // handle their own); clicks outside reach the
                        // document's handler, which light-dismisses it. The
                        // wheel is contained the same way.
                        .on_mouse_down(MouseButton::Left, move |_, window, cx| {
                            cx.stop_propagation();
                            window.focus(&query_focus, cx);
                        })
                        .on_scroll_wheel(|_, _, cx| cx.stop_propagation())
                        .when_some(self.replace_input.clone(), |d, rep| {
                            d.child(
                                div()
                                    .p(px(8.))
                                    .border_b_1()
                                    .border_color(rgb(RULE_COLOR))
                                    .flex()
                                    .flex_col()
                                    .gap(px(5.))
                                    .child(
                                        div()
                                            .flex()
                                            .items_center()
                                            .gap(px(8.))
                                            .text_size(px(13.))
                                            .child(
                                                div()
                                                    .flex_shrink_0()
                                                    .text_color(rgb(MUTED_COLOR))
                                                    .child("Replace"),
                                            )
                                            .child(div().flex_1().min_w(px(0.)).child(rep))
                                            .child({
                                                // The All button wears its scope
                                                // (P12; scopes-search 2): the sweep
                                                // is manuscript-only, and the button
                                                // says so BEFORE the click.
                                                let label = {
                                                    let matches = self.omni_match_ranges();
                                                    let (piece, scraps, capped) =
                                                        self.find_split(&matches);
                                                    if capped {
                                                        "All · 500+ in the piece".to_owned()
                                                    } else if scraps > 0 {
                                                        format!("All · {piece} in the piece")
                                                    } else {
                                                        "All".to_owned()
                                                    }
                                                };
                                                div()
                                                    .id("replace-all")
                                                    .flex_shrink_0()
                                                    .px(px(8.))
                                                    .py(px(1.))
                                                    .rounded(px(4.))
                                                    .cursor(CursorStyle::PointingHand)
                                                    .bg(rgb(0xE8DFC8))
                                                    .hover(|d| d.bg(rgb(0xDFD3B0)))
                                                    .text_size(px(12.))
                                                    .on_mouse_down(
                                                        MouseButton::Left,
                                                        cx.listener(
                                                            |editor, _: &MouseDownEvent, _, cx| {
                                                                cx.stop_propagation();
                                                                editor.replace_all(cx);
                                                            },
                                                        ),
                                                    )
                                                    .child(label)
                                            }),
                                    )
                                    .when_some(self.replace_result.clone(), |d, result| {
                                        d.child(
                                            div()
                                                .pl(px(58.))
                                                .text_size(px(11.))
                                                .text_color(rgb(MUTED_COLOR))
                                                .child(result),
                                        )
                                    }),
                            )
                        })
                        .child(list),
                ),
            )
    }

    /// ctrl-h: open the omnibox in find mode (if not already there) and add
    /// the replace field beneath the query.
    fn replace(&mut self, _: &Replace, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        let in_find = self.palette_input.is_some()
            && matches!(omni_mode(&self.palette_query).0, OmniMode::Find);
        if !in_find {
            self.find(&Find, window, cx);
        }
        if self.replace_input.is_some() {
            return;
        }
        let input = cx.new(|cx| TextField::single(cx, String::new()));
        cx.observe(&input, |editor, _, cx| {
            editor.replace_result = None;
            cx.notify();
        })
        .detach();
        cx.subscribe_in(
            &input,
            window,
            |editor, _, event: &TextFieldEvent, window, cx| match event {
                TextFieldEvent::Commit(replacement) => {
                    editor.replace_current(replacement.clone(), cx);
                }
                TextFieldEvent::Cancel => editor.close_palette(window, cx),
            },
        )
        .detach();
        // Already searching? Move focus to the new field so the replacement
        // types straight in. Opened fresh (no query yet) → keep the query
        // focused so the search term comes first.
        if in_find {
            let h = input.read(cx).focus_handle.clone();
            window.focus(&h, cx);
        }
        self.replace_input = Some(input);
        cx.notify();
    }

    /// Replace the current match and advance to the next.
    fn replace_current(&mut self, replacement: String, cx: &mut Context<Self>) {
        self.replace_result = None;
        let (OmniMode::Find, query) = omni_mode(&self.palette_query) else {
            return;
        };
        let query = query.to_owned();
        let matches = self.find_matches(&query);
        if matches.is_empty() {
            return;
        }
        let ix = self.palette_selected % matches.len();
        let target = matches[ix].clone();
        self.doc.edit_bytes(target.clone(), &replacement);
        let cursor = target.start + replacement.len();
        self.selected_range = cursor..cursor;
        self.selection_reversed = false;
        self.sync_mutations();
        self.mark_dirty();
        // Land on what is now the match at the same index.
        let matches = self.find_matches(&query);
        if !matches.is_empty() {
            self.palette_selected = ix % matches.len();
            self.omni_scroll_into_view(self.palette_selected);
            self.selected_range = matches[self.palette_selected].clone();
        }
        self.bump_activity();
        cx.notify();
    }

    /// Replace every match in one undoable step (reverse order keeps
    /// earlier offsets valid; the buffer coalesces nothing here — each
    /// edit is its own transaction, so group manually via restore… no:
    /// edits run back-to-front so a single undo per edit would be tedious —
    /// instead snapshot once by funnelling through one transaction).
    fn replace_all(&mut self, cx: &mut Context<Self>) {
        let Some(rep) = self.replace_input.clone() else {
            return;
        };
        let (OmniMode::Find, query) = omni_mode(&self.palette_query) else {
            return;
        };
        let query = query.to_owned();
        let replacement = rep.read(cx).content.clone();
        let matches = self.find_matches(&query);
        if matches.is_empty() {
            return;
        }
        // Replace All sweeps the MANUSCRIPT only (08 §2; 07 R5): bulk
        // mutation respects the seam like every other bulk operation. Single
        // Replace (a watched, caret-precise edit — the writer's hands) works
        // everywhere; classification is by match start. The announcement
        // strings are Wave B; the count here stays honest meanwhile.
        let (mstart, mend) = {
            let r = self.doc.manuscript_char_range();
            (self.doc.char_to_byte(r.start), self.doc.char_to_byte(r.end))
        };
        let (sweep, untouched): (Vec<&Range<usize>>, Vec<&Range<usize>>) = matches
            .iter()
            .partition(|m| m.start >= mstart && m.start < mend);
        for m in sweep.iter().rev() {
            self.doc.edit_bytes((*m).clone(), &replacement);
        }
        let count = sweep.len();
        let skipped = untouched.len();
        self.selected_range = 0..0;
        self.selection_reversed = false;
        self.sync_mutations();
        self.mark_dirty();
        self.palette_selected = 0;
        self.omni_scroll_into_view(0);
        // The refusal IS the result data (scopes-search 2), retained beside
        // the initiating Replace controls rather than broadcast globally.
        self.replace_result = Some(if skipped > 0 {
            format!("Replaced {count} in the piece · {skipped} in scraps untouched")
        } else {
            format!("Replaced {count} in the piece")
        });
        self.bump_activity();
        cx.notify();
    }

    fn find_matches(&self, query: &str) -> Vec<Range<usize>> {
        if query.is_empty() {
            return Vec::new();
        }
        let text = self.doc.text();
        let fold = |c: char| c.to_lowercase().next().unwrap_or(c);
        let needle: Vec<char> = query.chars().map(fold).collect();
        let hay: Vec<(usize, char)> = text
            .char_indices()
            .map(|(b, c)| (b, fold(c)))
            .collect();
        let mut out = Vec::new();
        if needle.len() > hay.len() {
            return out;
        }
        let mut i = 0;
        while i + needle.len() <= hay.len() {
            if hay[i..i + needle.len()]
                .iter()
                .map(|(_, c)| *c)
                .eq(needle.iter().copied())
            {
                let start = hay[i].0;
                let end = hay
                    .get(i + needle.len())
                    .map(|(b, _)| *b)
                    .unwrap_or(text.len());
                out.push(start..end);
                i += needle.len();
                if out.len() >= 500 {
                    break;
                }
            } else {
                i += 1;
            }
        }
        out
    }

    fn render_alt_strip(&self, cx: &mut Context<Self>) -> Option<impl IntoElement> {
        // Two ways in, one strip (inline-images §8): the open composer
        // (double-click, or the click below) — or, while the picture is
        // SELECTED, the alt shown as data. The strip IS the control (P12):
        // clicking the data line enters the same edit state double-click
        // opens. Never both at once — the composer wins.
        let (editing, data): (Option<Entity<TextField>>, Option<(usize, String)>) =
            match self.alt_input.clone() {
                Some((_, input)) => (Some(input), None),
                None => {
                    let sel = self.image_sel_live()?;
                    let BlockKind::Image { alt, .. } = self.doc.blocks().kind(sel.block)
                    else {
                        return None;
                    };
                    (None, Some((sel.block, alt.clone())))
                }
            };
        Some(
            div()
                .absolute()
                .bottom_0()
                .left_0()
                .right_0()
                .bg(rgb(0xF4F1EA))
                .border_t_1()
                .border_color(rgb(RULE_COLOR))
                // The strip IS the alt field's surface: its clicks must never
                // bubble to the root's no-dead-zones resolver (C4) and commit
                // the very field the writer is clicking into (twin of
                // render_composer_strip).
                .on_mouse_down(MouseButton::Left, |_, _, cx| cx.stop_propagation())
                .px(px(28.))
                .py(px(8.))
                .flex()
                .items_center()
                .gap(px(8.))
                .font_family("PT Serif")
                .text_size(px(13.))
                .child(div().text_color(rgb(MUTED_COLOR)).child("Alt text:"))
                .map(|d| match (editing, data) {
                    (Some(input), _) => d.child(div().flex_1().child(input)),
                    (None, Some((block, alt))) => d.child(
                        div()
                            .flex_1()
                            .cursor(CursorStyle::IBeam)
                            .text_color(if alt.is_empty() {
                                rgb(MUTED_COLOR)
                            } else {
                                rgb(TEXT_COLOR)
                            })
                            .on_mouse_down(
                                MouseButton::Left,
                                cx.listener(move |editor, _, window, cx| {
                                    cx.stop_propagation();
                                    editor.edit_image_alt(block, window, cx);
                                }),
                            )
                            // Data, not a prompt: the em-dash says "empty",
                            // no ghost verbiage (P4).
                            .child(if alt.is_empty() { "—".to_owned() } else { alt }),
                    ),
                    (None, None) => d, // unreachable by construction above
                }),
        )
    }

    pub fn save_now(&mut self) -> std::io::Result<Option<SaveGeneration>> {
        let perf = std::env::var_os("STROP_PERF").map(|_| std::time::Instant::now());
        let mut queued = None;
        self.sync_mutations();
        // Unborn import (lazy birth): sync_mutations above would have
        // materialized any pending ops, so a birth still pending here means
        // NO persistent mutation has ever happened — and no file may be
        // created. Every save path funnels through this one refusal.
        if self.pending_birth.is_some() {
            return Ok(None);
        }
        // Settle the journal's tail run: persisted runs are immutable once
        // written, so the store only ever pushes finished items. Saves fire
        // at ≥1s idle, a natural run boundary anyway.
        self.doc.journal_mut().settle();
        if let Some(store) = &self.store {
            let path = store.path().to_owned();
            match store.prepare_save_with_state(
                self.doc.spans(),
                self.doc.blocks(),
                // 50, not 200: each persisted undo entry snapshots the FULL
                // (SpanSet, BlockMap, Annotations) — measured 1.58 MB of JSON
                // at 200 on a card-heavy document, rewritten into the
                // append-only oplog on every editing save. Fifty cross-session
                // undo steps is still deep (in-session undo is unaffected);
                // the persisted tail is what must stay proportionate.
                &self.doc.export_history(50),
                self.doc.notes(),
                self.doc.journal(),
                self.doc.graveyard(),
                self.doc.provenance(),
            ) {
                Ok(save) => {
                    let generation = self
                        .save_worker
                        .as_mut()
                        .expect("attached Store has a save worker")
                        .request(save);
                    self.latest_save.queued(PendingSave {
                        generation,
                        revision: self.save_revision,
                    });
                    queued = Some(generation);
                }
                Err(e) => {
                    let message = format!("Not saved: {e}");
                    eprintln!("strop: failed to prepare save {}: {e}", path.display());
                    self.save_error = Some(message);
                    self.save_retry_at = Some(Instant::now() + self.save_retry_delay);
                    self.save_retry_delay = (self.save_retry_delay * 2).min(Duration::from_secs(60));
                    self.latest_save.preparation_failed();
                    return Err(e);
                }
            }
        }
        if let Some(t) = perf {
            eprintln!("strop-perf: save_now {:?}", t.elapsed());
        }
        Ok(queued)
    }

    fn apply_save_completion(&mut self, completion: SaveCompletion) {
        let Some(pending) = self.latest_save.as_ref() else {
            return;
        };
        // Older completions cannot alter dirty/error state. The ordered worker
        // will report the latest request after them.
        if completion.generation != pending.generation {
            return;
        }
        let saved_revision = pending.revision;
        let _ = self.latest_save.take();
        match completion.result {
            Ok(()) => {
                if self.save_revision == saved_revision {
                    self.store_dirty = false;
                }
                self.save_retry_at = None;
                self.save_retry_delay = Duration::from_secs(1);
                self.save_error = None;
            }
            Err(e) => {
                let path = self
                    .store
                    .as_ref()
                    .map(|s| s.path().display().to_string())
                    .unwrap_or_else(|| "document".into());
                eprintln!("strop: failed to save {path}: {e}");
                self.save_error = Some(format!("Not saved: {e}"));
                self.save_retry_at = (self.save_revision == saved_revision)
                    .then(|| Instant::now() + self.save_retry_delay);
                self.save_retry_delay = (self.save_retry_delay * 2).min(Duration::from_secs(60));
            }
        }
    }

    fn drain_save_completions(&mut self) {
        while let Some(completion) = self.save_worker.as_ref().and_then(SaveWorker::try_completion) {
            self.apply_save_completion(completion);
        }
    }

    /// The clean-close predicate (quit guard a): true when a close can skip
    /// the final save because every byte is already durable. The editor's
    /// own flags cover marked mutations and in-flight/failed saves; the
    /// store's frontier baseline (`Store::needs_save`) covers doc mutations
    /// that never route through the dirty chokepoint — open-time session
    /// seals, idle-gap checkpoints — and the journal's unpersisted tail. An
    /// unborn import (lazy birth) is clean BY LAW: nothing exists on disk,
    /// and a mere close must not create anything.
    fn quit_close_clean(&mut self) -> bool {
        // Fold any just-committed transient-field ops in first — they are
        // exactly the bytes LAW 2 exists to protect.
        self.sync_mutations();
        if self.store_dirty || self.latest_save.is_some() || self.save_error.is_some() {
            return false;
        }
        if self.pending_birth.is_some() {
            return true;
        }
        match &self.store {
            Some(store) => !store.needs_save(self.doc.journal()),
            None => true,
        }
    }

    /// Queue the newest snapshot and wait only at a shutdown/rename boundary.
    pub fn flush_saves(&mut self) -> std::io::Result<()> {
        // Clean close writes nothing: when the flags AND the store's own
        // frontier baseline agree that disk already matches, the last-ditch
        // flush must not rewrite (or, under lazy birth, CREATE) the file.
        if self.quit_close_clean() {
            return Ok(());
        }
        // Use the generation produced by THIS attempt. Consulting editor
        // state here could accidentally select an older queued snapshot after
        // preparation of the newest revision failed.
        let Some(generation) = self.save_now()? else { return Ok(()) };
        let completion = self
            .save_worker
            .as_ref()
            .expect("pending save has a worker")
            .wait_for(generation);
        let result = completion
            .result
            .as_ref()
            .map(|_| ())
            .map_err(|e| std::io::Error::new(e.kind(), e.to_string()));
        self.apply_save_completion(completion);
        result
    }

    /// Keep the window alive until the newest save generation reaches disk.
    pub fn request_quit(
        &mut self,
        _: &crate::Quit,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        if matches!(self.quit_guard, QuitGuard::Bypass | QuitGuard::Saving | QuitGuard::SavingCopy) {
            return;
        }
        self.sync_active_note_draft(cx);
        self.quit_guard = QuitGuard::Saving;
        self.quit_veil = false;
        window.focus(&self.quit_focus, cx);
        // LAW 2: quit's resolution boundary is broader than any gesture's — the
        // composer AND every single-line field (link, cold-read reaction) must
        // reach the document before it is serialized. The composer mutates it
        // synchronously, but a single-line field resolves by EMITTING Commit,
        // and its subscriber only receives that when the effect cycle flushes.
        // So the save cannot run inline here: `defer_in` schedules it at the end
        // of the cycle, and the effect queue is FIFO — the emits above are
        // delivered, writing their text into the document, before it runs.
        self.commit_composer_no_focus(cx);
        self.commit_transient_fields_on_quit(cx);
        cx.defer_in(window, |editor, _, cx| {
            editor.settle_quit(cx);
        });
        cx.notify();
    }

    /// The deferred half of `request_quit`, after every transient field has
    /// resolved into the document. Clean close (quit guard a): nothing to
    /// flush means the window closes NOW — no save, no veil, no frame of
    /// chrome. Otherwise the final save is queued and the veil is armed on
    /// a delay (quit guard c); the completion doorbell (`SaveWake`) usually
    /// closes the window long before that timer fires.
    fn settle_quit(&mut self, cx: &mut Context<Self>) {
        if self.quit_close_clean() {
            self.record_exit_state();
            self.quit_guard = QuitGuard::Bypass;
            cx.quit();
            return;
        }
        let _ = self.save_now();
        self.finish_quit_if_ready(cx);
        self.arm_quit_veil(cx);
        cx.notify();
    }

    /// Quit guard c: the veil renders only if the final save is still
    /// pending after this long. A local disk finishes in single-digit
    /// milliseconds; only a genuinely slow write (network mount, spun-down
    /// drive) earns the "Saving before closing" chrome.
    fn arm_quit_veil(&mut self, cx: &mut Context<Self>) {
        if !matches!(self.quit_guard, QuitGuard::Saving) {
            return; // already closed — or Failed, which renders regardless
        }
        cx.spawn(async move |this, cx| {
            cx.background_executor().timer(QUIT_VEIL_DELAY).await;
            this.update(cx, |editor: &mut Editor, cx| {
                if editor.reveal_quit_veil() {
                    cx.notify();
                }
            })
            .ok();
        })
        .detach();
    }

    /// The timer's half of quit guard c, separated so the transition is a
    /// testable fact: the veil shows only while a save is still holding the
    /// window open. Returns whether anything changed.
    fn reveal_quit_veil(&mut self) -> bool {
        let saving = matches!(self.quit_guard, QuitGuard::Saving | QuitGuard::SavingCopy);
        if saving && !self.quit_veil {
            self.quit_veil = true;
            true
        } else {
            false
        }
    }

    fn finish_quit_if_ready(&mut self, cx: &mut Context<Self>) {
        if !matches!(self.quit_guard, QuitGuard::Saving) || self.latest_save.is_some() {
            return;
        }
        // A background result can legitimately mutate the document while the
        // save is in flight. Chase that newer revision instead of either
        // closing over stale bytes or making the writer press Retry.
        if self.store_dirty && self.save_error.is_none() {
            let _ = self.save_now();
            return;
        }
        if self.store_dirty || self.save_error.is_some() {
            self.quit_guard = QuitGuard::Failed(
                self.save_error.clone().unwrap_or_else(|| "The newest changes have not reached disk.".into()),
            );
            cx.notify();
            return;
        }
        self.record_exit_state();
        self.quit_guard = QuitGuard::Bypass;
        cx.quit();
    }

    fn cancel_quit(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        if matches!(self.quit_guard, QuitGuard::Failed(_)) {
            self.quit_guard = QuitGuard::Idle;
            self.quit_veil = false;
            window.focus(&self.focus_handle, cx);
            cx.notify();
        }
    }

    fn quit_anyway(&mut self, cx: &mut Context<Self>) {
        self.quit_guard = QuitGuard::Bypass;
        cx.quit();
    }

    /// The unhandled-quit salvage: when the last-ditch flush fails there is
    /// no window left for the Failed dialog, so LAW 2's final line is a full
    /// snapshot into the machine-local state dir — announced on stderr,
    /// never silently abandoned.
    pub fn salvage_recovery_copy(&self) {
        let Some(store) = &self.store else { return };
        let stem = store.path().file_stem().and_then(|s| s.to_str()).unwrap_or("document");
        let dir = crate::paths::state_dir().join("recovery");
        if let Err(e) = std::fs::create_dir_all(&dir) {
            eprintln!("strop: recovery dir failed too: {e}");
            return;
        }
        let path = dir.join(format!("{stem} {}.strop", strop_core::journal::now_ms()));
        match store.prepare_copy_to(&path).map(|save| save.write()) {
            Ok(Ok(())) => eprintln!("strop: salvaged a full copy at {}", path.display()),
            Ok(Err(e)) | Err(e) => eprintln!("strop: recovery copy failed: {e}"),
        }
    }

    fn save_quit_copy(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let QuitGuard::Failed(previous_error) = &self.quit_guard else { return };
        let previous_error = previous_error.clone();
        let Some(store) = &self.store else { return };
        // Same host-directory law as save_copy_as: never seed the picker
        // with a portal FUSE dir (files.rs, the invisible-temp trap).
        let dir = crate::files::host_parent_or_documents(store.path());
        let suggested = format!(
            "{} recovery.strop",
            store.path().file_stem().and_then(|s| s.to_str()).unwrap_or("document")
        );
        self.quit_guard = QuitGuard::SavingCopy;
        // The copy flow holds a path dialog open — deliberate, slow, and
        // exactly what today's veil narrates. No 200ms grace here.
        self.quit_veil = true;
        let rx = cx.prompt_for_new_path(&dir, Some(&suggested));
        cx.spawn(async move |this, cx| {
            let path = match rx.await {
                Ok(Ok(Some(path))) => path,
                _ => {
                    this.update(cx, |editor: &mut Editor, cx| {
                        editor.quit_guard = QuitGuard::Failed(previous_error);
                        cx.notify();
                    }).ok();
                    return;
                }
            };
            let path = crate::files::resolve_portal_path_async(path).await;
            let prepared = this.update(cx, |editor: &mut Editor, _| {
                editor.store.as_ref()
                    .ok_or_else(|| std::io::Error::other("document store is no longer open"))?
                    .prepare_copy_to(&path)
            }).unwrap_or_else(|_| Err(std::io::Error::other("document window closed")));
            let result = match prepared {
                Ok(save) => cx.background_executor().spawn(async move { save.write() }).await,
                Err(e) => Err(e),
            };
            this.update(cx, |editor: &mut Editor, cx| match result {
                Ok(()) => {
                    editor.quit_guard = QuitGuard::Bypass;
                    cx.quit();
                }
                Err(e) => {
                    editor.quit_guard = QuitGuard::Failed(format!("Could not save the copy: {e}"));
                    cx.notify();
                }
            }).ok();
        }).detach();
        window.focus(&self.quit_focus, cx);
        cx.notify();
    }

    /// Would text typed at the caret inherit `attr` from the existing spans?
    /// Mirrors `SpanSet::apply_op` insertion rules: strictly inside any
    /// span, or at the right edge of an expanding one.
    fn caret_inherits(&self, attr: &InlineAttr) -> bool {
        let pos = self
            .doc
            .rope()
            .byte_to_char(self.selected_range.start);
        self.doc.spans().spans().iter().any(|s| {
            s.attr == *attr
                && (s.range.start < pos && pos < s.range.end
                    || s.range.end == pos && s.attr.expands())
        })
    }

    /// Is `attr` active at the current selection/caret (for toggle logic
    /// and toolbar state)?
    fn attr_active(&self, attr: &InlineAttr) -> bool {
        if self.selected_range.is_empty() {
            if let Some((_, on)) = self.caret_attrs.iter().find(|(a, _)| a == attr) {
                return *on;
            }
            self.caret_inherits(attr)
        } else {
            let rope = self.doc.rope();
            let range = rope.byte_to_char(self.selected_range.start)
                ..rope.byte_to_char(self.selected_range.end);
            self.doc.spans().covers(range, attr)
        }
    }

    /// Toggle an inline attribute: over a selection, fully-covered removes
    /// and anything less applies; at a bare caret, sets a sticky attr for
    /// the next typed text (the universal rich-editor convention).
    fn toggle_span(&mut self, attr: InlineAttr, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        // Read-only while previewing the past: formatting the past is
        // undefined. The strip pulses its banner (the uniform refusal, Bug B);
        // the panel just no-ops.
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return;
        }
        if self.history_view.is_some() {
            return;
        }
        if self.selected_range.is_empty() {
            let target = !self.attr_active(&attr);
            self.caret_attrs.retain(|(a, _)| a != &attr);
            self.caret_attrs.push((attr, target));
            cx.notify();
            return;
        }
        let rope = self.doc.rope();
        let range =
            rope.byte_to_char(self.selected_range.start)..rope.byte_to_char(self.selected_range.end);
        self.doc.toggle_format(range, attr);
        self.mark_dirty();
        cx.notify();
    }

    /// Open the left flank's link argument-field (docs/impl/03-flanks.md §0.1).
    /// CAPTURES the selection's CHAR range now and applies to THAT on commit —
    /// never a re-read of `selected_range`, which could drift (Link doesn't
    /// expand under the caret). Pre-filled from the current target so editing a
    /// link shows it. The rename-input idiom: Enter commits, Esc cancels, a
    /// click-away blur commits (`commit_field_on_blur`).
    fn open_link_input(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        // Read-only while previewing the past (mirrors toggle_span).
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return;
        }
        if self.history_view.is_some() || self.selected_range.is_empty() {
            return;
        }
        let rope = self.doc.rope();
        let range = rope.byte_to_char(self.selected_range.start)
            ..rope.byte_to_char(self.selected_range.end);
        let seed = self.doc.link_over(range.clone()).unwrap_or_default();
        let input = cx.new(|cx| TextField::single(cx, seed));
        cx.subscribe_in(
            &input,
            window,
            move |editor, _, event: &TextFieldEvent, window, cx| match event {
                TextFieldEvent::Commit(url) => editor.commit_link(url.clone(), window, cx),
                TextFieldEvent::Cancel => editor.cancel_link(window, cx),
            },
        )
        .detach();
        // Blur commits (e.g. the palette steals focus): `still` re-checks the
        // field is the one open, so a stale handle never double-commits.
        self.commit_field_on_blur(&input, window, cx, |e| {
            e.link_input.as_ref().map(|(_, f)| f.clone())
        });
        if self.flank_focused {
            self.exit_flank(window, cx);
        }
        let handle = input.read(cx).focus_handle.clone();
        window.focus(&handle, cx);
        self.link_input = Some((range, input));
        cx.notify();
    }

    /// Commit the link over its CAPTURED range: a non-empty URL sets it, an empty
    /// one removes it (spec §0.1). Focus returns to the document; the flank stays
    /// up so the writer can apply another mark.
    fn commit_link(&mut self, url: String, window: &mut Window, cx: &mut Context<Self>) {
        let Some((range, _)) = self.link_input.take() else {
            return;
        };
        let url = url.trim().to_owned();
        self.doc
            .set_link(range, if url.is_empty() { None } else { Some(url) });
        self.mark_dirty();
        window.focus(&self.focus_handle, cx);
        cx.notify();
    }

    /// Esc from the link field cancels just the argument and returns to the flank
    /// (the two-level Esc, finding 59) — the selection and popover stay.
    fn cancel_link(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        self.link_input = None;
        window.focus(&self.focus_handle, cx);
        cx.notify();
    }

    /// Take BOTH flanks down by LATCHING (LAW 1; review H20): a focus-/text-
    /// moving verb (annotate, aside, exile) leaves the selection standing but the
    /// offer withdrawn, so only one pinned object sits at the selection's y and
    /// the predicate can never re-raise the flanks over the composer a settle
    /// beat later. The latch clears itself the moment the selection changes; an
    /// unchanged restored selection keeps it (no post-commit re-offer, P2). Also
    /// drops a half-typed link argument.
    fn dismiss_flanks(&mut self, cx: &mut Context<Self>) {
        self.flank_latched = true;
        self.link_input = None;
        cx.notify();
    }

    /// LAW 1 (papercuts-2026-07 §1) — flank visibility as a per-frame derived
    /// predicate: visible iff a settled non-empty selection exists, the prose
    /// owns keyboard focus (no transient field open), and the offer is not
    /// latched. The mouse-drag and off-screen/history/cold-read conjuncts live
    /// in `flank_layout` (they also need the frame geometry); this is the core
    /// LAW that the render path, the debug dump, and the rig all read.
    fn flanks_visible(&self) -> bool {
        flanks_visible_pred(
            self.selected_range.is_empty(),
            self.is_selecting,
            self.flank_risen,
            self.flank_latched,
            self.transient_field_open(),
        )
    }

    /// Is a transient single-line/composer field open? Its presence means the
    /// prose no longer owns keyboard focus, so the flanks yield to it (LAW 1's
    /// no-transient-field conjunct — the C2 composer-occlusion fix). The link
    /// argument-field is EXCLUDED: it is the flank's own inner surface, and while
    /// it is up `render_selection_popover` paints it in the flank's place.
    fn transient_field_open(&self) -> bool {
        self.focus.composing_id().is_some()
            || self.doc_rename_input.is_some()
            || self.goal_input.is_some()
            || self.rename_input.is_some()
            || self.alt_input.is_some()
            || self.replace_input.is_some()
            || self.palette_input.is_some()
    }

    /// The single selection-change hook feeding LAW 1 (called from the caret
    /// funnels `set_cursor`/`extend_cursor` and the other genuine selection
    /// verbs). Clears the latch on a real change, drops the flanks when the
    /// selection collapses, and arms the settle beat for a fresh non-empty
    /// selection — while a risen flank tracks growth untouched.
    fn on_selection_moved(&mut self, cx: &mut Context<Self>) {
        if self.selected_range == self.flank_sel {
            return; // a restored/identical selection keeps the latch (LAW 1)
        }
        // A selection move leaves the ctrl-. flank navigation (the cells no
        // longer describe the same extent); focus returns to the prose naturally.
        self.flank_focused = false;
        self.flank_sel = self.selected_range.clone();
        self.flank_latched = false; // a genuine selection change clears the latch
        if self.selected_range.is_empty() {
            // Collapse lowers the flanks as a consequence (they are never their
            // own layer) — the empty selection alone suffices for the predicate.
            self.flank_risen = false;
            self.flank_settle = None;
            return;
        }
        if self.flank_risen {
            return; // growth: stay up, never re-gate mid-extension (no strobe)
        }
        // A mouse DRAG extends the selection on every mousemove — arming here
        // would spawn a settle timer per move (V8b). Mouse-up re-arms once the
        // drag settles; only keyboard selections (is_selecting == false) arm here.
        if !self.is_selecting {
            self.arm_flank_settle(cx);
        }
    }

    /// Arm the settle beat (LAW 1): after `FLANK_SETTLE_MS` of no further
    /// extension, a still-live, no-longer-dragging selection raises the flanks.
    /// The captured instant guards against a stale timer firing after a newer
    /// extension re-armed the beat.
    fn arm_flank_settle(&mut self, cx: &mut Context<Self>) {
        let at = Instant::now();
        self.flank_settle = Some(at);
        cx.spawn(async move |this, cx| {
            cx.background_executor()
                .timer(Duration::from_millis(FLANK_SETTLE_MS))
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                if editor.flank_settle == Some(at)
                    && !editor.selected_range.is_empty()
                    && !editor.is_selecting
                {
                    editor.flank_risen = true;
                    editor.flank_settle = None;
                    cx.notify();
                }
            })
            .ok();
        })
        .detach();
    }

    /// Start the cursor-blink heartbeat. GNOME-style: solid while typing,
    /// blinking when idle, solid again (and quiet — no repaints) after 10s.
    ///
    /// STROP_TEST_STILL (the visual harness, scripts/wflip.sh) suppresses
    /// the heartbeat entirely: captures are byte-compared, and a blinking
    /// cursor is nondeterminism. `cursor_visible` starts true and nothing
    /// ever toggles it, so the caret stays solid in every frame.
    pub fn start_blink(&self, cx: &mut Context<Self>) {
        if test_still() {
            return;
        }
        cx.spawn(async move |this, cx| {
            loop {
                cx.background_executor()
                    .timer(Duration::from_millis(530))
                    .await;
                let alive = this.update(cx, |editor: &mut Editor, cx| {
                    let idle = editor.last_input.elapsed();
                    let visible = if idle < Duration::from_millis(530)
                        || idle > Duration::from_secs(10)
                    {
                        true
                    } else {
                        !editor.cursor_visible
                    };
                    if visible != editor.cursor_visible {
                        editor.cursor_visible = visible;
                        cx.notify();
                    }
                });
                if alive.is_err() {
                    break;
                }
            }
        })
        .detach();
    }

    /// Any cursor-affecting input: reset blink and schedule scroll-to-cursor.
    fn bump_activity(&mut self) {
        self.last_input = Instant::now();
        self.cursor_visible = true;
        self.autoscroll_request = true;
    }

    fn cursor_offset(&self) -> usize {
        if self.selection_reversed {
            self.selected_range.start
        } else {
            self.selected_range.end
        }
    }

    /// Collapse the selection to `offset`. Keeps `goal_x`; non-vertical
    /// callers go through `move_to`, which clears it.
    fn set_cursor(&mut self, offset: usize, affinity_down: bool, cx: &mut Context<Self>) {
        // Any caret motion decays the picture selection without harm
        // (inline-images §4: click elsewhere, travel, jumps — everything
        // that isn't typing or the deletion key). The four plain arrows
        // apply their direction law BEFORE reaching this funnel. One
        // Option check: free for every ordinary caret move.
        if self.image_sel.is_some() {
            self.decay_image_sel();
        }
        // The caret never rests on the seam line (seam-mechanics 3): a landing
        // there snaps past it in the direction of travel (approximated by
        // where the caret came from; the click path maps by y before this).
        let offset = self.snap_off_seam(offset, offset >= self.cursor_offset());
        let prev_offset = self.cursor_offset();
        let was_in_pile = self.caret_in_scraps();
        self.selected_range = offset..offset;
        self.selection_reversed = false;
        self.cursor_affinity_down = affinity_down;
        self.caret_attrs.clear();
        // Remember the manuscript caret so Esc from a pile caret returns
        // exactly here (review B3). A seamless doc is all manuscript.
        let ch = self.doc.rope().byte_to_char(offset.min(self.doc.len_bytes()));
        if self.drafting && self.focus.active_id().is_some_and(|id| {
            self.doc.notes().get(id).is_some_and(|note| {
                note.kind == NoteKind::Diagnosis
                    && (ch < note.range.start || ch > note.range.end)
            })
        }) {
            self.focus = CardFocus::Idle;
        }
        if self.doc.region_of_char(ch) == strop_core::document::Region::Manuscript {
            self.last_manuscript_caret = offset;
        }
        // The provenance one-liner's caret gate (surfaces-attention 5): the
        // record under a RESTING caret shows after ~one caret-blink; leaving
        // hides it instantly, a 150ms departing ghost carrying the light out.
        let prov_now = self
            .doc
            .provenance()
            .at(ch)
            .filter(|_| self.caret_in_scraps())
            .map(|r| r.id);
        match (prov_now, self.prov_rest) {
            (Some(id), Some((cur, _))) if cur == id => {} // still resting here
            (Some(id), _) => {
                self.prov_rest = Some((id, Instant::now()));
                // One notify at the reveal moment (the appear fade starts
                // then); a fresh rest supersedes a stale timer by the id+time
                // check on arrival.
                cx.spawn(async move |this, cx| {
                    cx.background_executor().timer(PROV_REST_DELAY).await;
                    this.update(cx, |editor: &mut Editor, cx| {
                        if editor
                            .prov_rest
                            .is_some_and(|(cur, s)| cur == id && s.elapsed() >= PROV_REST_DELAY)
                        {
                            editor.appearing.insert(PROV_ID_FLAG | id);
                            cx.notify();
                            cx.spawn(async move |this, cx| {
                                cx.background_executor()
                                    .timer(CARD_APPEAR + Duration::from_millis(150))
                                    .await;
                                this.update(cx, |editor: &mut Editor, cx| {
                                    editor.appearing.remove(&(PROV_ID_FLAG | id));
                                    cx.notify();
                                })
                                .ok();
                            })
                            .detach();
                        }
                    })
                    .ok();
                })
                .detach();
            }
            (None, Some((id, since))) => {
                // Instant hide; the departing channel carries the echo.
                if since.elapsed() >= PROV_REST_DELAY
                    && let Some(card) = self
                        .margin_cards(true)
                        .cards
                        .into_iter()
                        .find(|c| c.provenance == Some(id))
                {
                    self.departing.push((card, Instant::now()));
                    self.schedule_departing_clear(cx);
                }
                self.prov_rest = None;
            }
            (None, None) => {}
        }
        if was_in_pile && !self.caret_in_scraps() {
            // The caret entering the manuscript by the writer's own act ends
            // the excursion (scopes-search 1, clear (b)): the latch drops and
            // `pile_end` remembers where the visit stopped, so the chip's
            // next press resumes there.
            self.excursion = None;
            self.pile_end = Some(prev_offset);
            // The retype-race guard's release (seam-mechanics 6): a textless
            // pile held its seam while the caret stayed inside; the caret
            // leaving is the evaporation moment — its own undoable step. The
            // dissolved pile takes its resume point with it.
            if self.doc.scraps_textless() && self.doc.evaporate_scraps() {
                self.pile_end = None;
                self.sync_mutations();
            }
        }
        self.bump_activity();
        self.on_selection_moved(cx); // LAW 1: a collapse/caret-move lowers the flanks
        cx.notify();
    }

    /// Is a byte offset inside the Scraps region?
    fn byte_in_scraps(&self, byte: usize) -> bool {
        let ch = self.doc.rope().byte_to_char(byte.min(self.doc.len_bytes()));
        self.doc.region_of_char(ch) == strop_core::document::Region::Scraps
    }

    /// Is the caret inside the Scraps region right now?
    fn caret_in_scraps(&self) -> bool {
        let len = self.doc.len_bytes();
        let ch = self.doc.rope().byte_to_char(self.cursor_offset().min(len));
        self.doc.region_of_char(ch) == strop_core::document::Region::Scraps
    }

    /// Extend the selection's moving end to `offset`. Keeps `goal_x`.
    fn extend_cursor(&mut self, offset: usize, affinity_down: bool, cx: &mut Context<Self>) {
        // A growing range selection replaces the picture selection (§4
        // decay; §5's range door takes over from here).
        if self.image_sel.is_some() {
            self.decay_image_sel();
        }
        // Never let a selection straddle the boundary (review B4): clamp the
        // moving end into the fixed anchor's region.
        let anchor = if self.selection_reversed {
            self.selected_range.end
        } else {
            self.selected_range.start
        };
        let offset = self.clamp_to_region(anchor, offset);
        if self.selection_reversed {
            self.selected_range.start = offset;
        } else {
            self.selected_range.end = offset;
        }
        if self.selected_range.end < self.selected_range.start {
            self.selection_reversed = !self.selection_reversed;
            self.selected_range = self.selected_range.end..self.selected_range.start;
        }
        self.cursor_affinity_down = affinity_down;
        self.caret_attrs.clear();
        self.bump_activity();
        self.publish_primary(cx);
        self.on_selection_moved(cx); // LAW 1: keyboard/drag extension feeds the flank predicate
        cx.notify();
    }

    /// A selection's clipboard text. A seam-spanning selection copies as the
    /// two fragments joined by ONE newline — the seam's own blank separator
    /// line is stripped (it never enters the clipboard, not even as its
    /// whitespace shadow; the pile's item-separating blank lines inside the
    /// selection stay — they are honest text). Seam-mechanics 2.
    fn selection_text(&self, range: &Range<usize>) -> String {
        if !self.selection_spans_seam(range) {
            return self.doc.slice_bytes(range.clone());
        }
        let m = self.doc.manuscript_char_range();
        let s = self
            .doc
            .scraps_char_range()
            .unwrap_or_else(|| m.clone());
        // Positional order (tail era: manuscript above; top era: pile above).
        let (above_end, below_start) = if s.start > m.end {
            (self.doc.char_to_byte(m.end), self.doc.char_to_byte(s.start))
        } else {
            (self.doc.char_to_byte(s.end), self.doc.char_to_byte(m.start))
        };
        let above = self
            .doc
            .slice_bytes(range.start.min(above_end)..above_end.min(range.end));
        let below = self
            .doc
            .slice_bytes(below_start.max(range.start)..range.end.max(below_start));
        format!("{above}\n{below}")
    }

    /// One fragment of `clipboard_text` (§9): the plain doc slice, with
    /// every image block the range covers WHOLE swapped for its Markdown
    /// line — the travelling form, so a range copy carries pictures. A
    /// partially covered caption stays the plain fragment the writer
    /// selected (only the whole block owns the Markdown form; a partial
    /// range is just text). Prose pays one kind scan over the spanned
    /// blocks and nothing more.
    fn clipboard_slice(&self, range: Range<usize>) -> String {
        let covered = self.covered_image_lines(&range);
        if covered.is_empty() {
            return self.doc.slice_bytes(range);
        }
        splice_image_markdown(&self.doc.slice_bytes(range.clone()), range.start, &covered)
    }

    /// Image blocks whose LINE TEXT `range` covers whole, with their §9
    /// Markdown forms — ascending, ranges within `range` by construction.
    fn covered_image_lines(&self, range: &Range<usize>) -> Vec<(Range<usize>, String)> {
        if range.is_empty() {
            return Vec::new();
        }
        let rope = self.doc.rope();
        let first = rope.byte_to_line(range.start);
        let last = rope.byte_to_line(range.end.min(self.doc.len_bytes()));
        let kinds = self.doc.blocks().kinds();
        let mut out = Vec::new();
        for block in first..=last.min(kinds.len().saturating_sub(1)) {
            if !matches!(kinds.get(block), Some(BlockKind::Image { .. })) {
                continue;
            }
            let (start, end) = self.image_block_bounds(block);
            if range.start <= start
                && end <= range.end
                && let Some(md) = self.image_block_markdown(block)
            {
                out.push((start..end, md));
            }
        }
        out
    }

    /// `selection_text`, dressed for the pasteboard (§9): the same seam
    /// law, with every fragment passing the image splice. The find seed
    /// and every other in-app reader keep `selection_text` — the Markdown
    /// form exists for travel only.
    fn clipboard_text(&self, range: &Range<usize>) -> String {
        if !self.selection_spans_seam(range) {
            return self.clipboard_slice(range.clone());
        }
        let m = self.doc.manuscript_char_range();
        let s = self
            .doc
            .scraps_char_range()
            .unwrap_or_else(|| m.clone());
        let (above_end, below_start) = if s.start > m.end {
            (self.doc.char_to_byte(m.end), self.doc.char_to_byte(s.start))
        } else {
            (self.doc.char_to_byte(s.end), self.doc.char_to_byte(m.start))
        };
        let above = self.clipboard_slice(range.start.min(above_end)..above_end.min(range.end));
        let below = self.clipboard_slice(below_start.max(range.start)..range.end.max(below_start));
        format!("{above}\n{below}")
    }

    /// The two clipboard flavors are born together. For ordinary live prose
    /// this records the exact source spans and block extents; seam rewriting
    /// still receives a valid guarded envelope but deliberately has no rich
    /// operation, because its visible text is not a contiguous document
    /// slice. Whole image assets are sibling bitmap entries in id order.
    fn clipboard_item(&self, range: &Range<usize>) -> ClipboardItem {
        let text = self.clipboard_text(range);
        let mut rich = RichPaste {
            spans: Vec::new(),
            blocks: Vec::new(),
            starts_at_boundary: false,
            ends_at_boundary: false,
        };
        let mut image_asset_ids = Vec::new();
        if !self.selection_spans_seam(range) && text == self.doc.slice_bytes(range.clone()) {
            let rope = self.doc.rope();
            let first = rope.byte_to_line(range.start);
            let last = rope.byte_to_line(range.end.min(self.doc.len_bytes()));
            rich.starts_at_boundary = range.start == rope.line_to_byte(first);
            rich.ends_at_boundary = range.end == rope.line_to_byte(last);
            for block in first..=last.min(self.doc.blocks().len().saturating_sub(1)) {
                let start = rope.line_to_byte(block);
                let end = if block + 1 < rope.len_lines() {
                    rope.line_to_byte(block + 1)
                } else {
                    self.doc.len_bytes()
                };
                let covered_start = start.max(range.start);
                let covered_end = end.min(range.end);
                if covered_start >= covered_end { continue; }
                let kind = self.doc.blocks().kind(block).clone();
                let complete = range.start <= start && end <= range.end;
                if complete && let BlockKind::Image { src, .. } = &kind {
                    image_asset_ids.push(src.clone());
                }
                rich.blocks.push(ClipboardBlock {
                    range: covered_start - range.start..covered_end - range.start,
                    kind,
                    complete,
                });
            }
            let char_start = rope.byte_to_char(range.start);
            let char_end = rope.byte_to_char(range.end);
            for source in self.doc.spans().spans() {
                let start = source.range.start.max(char_start);
                let end = source.range.end.min(char_end);
                if start < end && !matches!(source.attr, InlineAttr::FootnoteRef(_)) {
                    rich.spans.push(Span {
                        range: start - char_start..end - char_start,
                        attr: source.attr.clone(),
                    });
                }
            }
        }
        let envelope = RichClipboardEnvelope {
            v: RICH_CLIPBOARD_VERSION,
            text_len: text.len(),
            rich,
            image_asset_ids: image_asset_ids.clone(),
        };
        let metadata = serde_json::to_string(&envelope).expect("clipboard payload serializes");
        let mut item = ClipboardItem::new_string_with_metadata(text, metadata);
        for id in image_asset_ids {
            if let Some(bytes) = self.store.as_ref().and_then(|s| s.get_asset(&id)) {
                item.entries.push(ClipboardEntry::Image(gpui::Image::from_bytes(
                    image_format_for_src(&id),
                    bytes,
                )));
            }
        }
        item
    }

    /// Linux PRIMARY-selection contract: any selection (mouse or keyboard)
    /// is published; middle-click pastes it. With auto_copy_selection
    /// (config), the regular clipboard gets it too — Kirill's habit.
    fn publish_primary(&self, cx: &mut Context<Self>) {
        if !self.selected_range.is_empty() {
            let item = self.clipboard_item(&self.selected_range.clone());
            if self.config.auto_copy_selection {
                cx.write_to_clipboard(item.clone());
            }
            // The PRIMARY selection is an X11/Wayland concept; gpui exposes it
            // only on Linux/BSD. macOS and Windows have no PRIMARY — the
            // regular clipboard above is the only target there.
            #[cfg(any(target_os = "linux", target_os = "freebsd"))]
            cx.write_to_primary(item);
            #[cfg(not(any(target_os = "linux", target_os = "freebsd")))]
            let _ = item;
        }
    }

    fn move_to(&mut self, offset: usize, cx: &mut Context<Self>) {
        self.goal_x = None;
        self.set_cursor(offset, false, cx);
    }

    fn select_to(&mut self, offset: usize, cx: &mut Context<Self>) {
        self.goal_x = None;
        self.extend_cursor(offset, false, cx);
    }

    // -- Boundary helpers (byte offsets) ------------------------------------

    /// Start/end of the *paragraph* (rope line) containing `offset`.
    fn paragraph_bounds(&self, offset: usize) -> (usize, usize) {
        paragraph_bounds_in(&self.doc, offset)
    }

    /// Start/end of the *visual* line under the cursor, with the affinity
    /// that keeps the cursor on it. Falls back to paragraph bounds when no
    /// frame exists yet.
    fn visual_line_bounds(&self, offset: usize) -> ((usize, bool), (usize, bool)) {
        if let Some(frame) = self.last_frame.as_ref()
            && let Some((par_ix, line, _)) =
                frame.cursor_position(offset, self.cursor_affinity_down)
        {
            let par = &frame.paragraphs[par_ix];
            let start = par.range.start + par.line_start(line);
            let end = par.range.start + par.line_end(line);
            return ((start, line > 0), (end, false));
        }
        let (start, end) = self.paragraph_bounds(offset);
        ((start, false), (end, false))
    }

    fn previous_boundary(&self, offset: usize) -> usize {
        if offset == 0 {
            return 0;
        }
        let (start, _) = self.paragraph_bounds(offset);
        if offset == start {
            return offset - 1; // step over the newline
        }
        let line = self.doc.slice_bytes(start..offset);
        line.grapheme_indices(true)
            .next_back()
            .map_or(start, |(ix, _)| start + ix)
    }

    fn next_boundary(&self, offset: usize) -> usize {
        let len = self.doc.len_bytes();
        if offset >= len {
            return len;
        }
        let (_, end) = self.paragraph_bounds(offset);
        if offset == end {
            return offset + 1; // step over the newline
        }
        let line = self.doc.slice_bytes(offset..end);
        line.grapheme_indices(true)
            .nth(1)
            .map_or(end, |(ix, _)| offset + ix)
    }

    fn previous_word_boundary(&self, offset: usize) -> usize {
        previous_word_boundary(&self.doc, offset)
    }

    fn next_word_boundary(&self, offset: usize) -> usize {
        next_word_boundary(&self.doc, offset)
    }

    /// GTK/Windows paragraph motion: to start of current paragraph, or of
    /// the previous one when already at a start.
    fn previous_paragraph_boundary(&self, offset: usize) -> usize {
        previous_paragraph_boundary_in(&self.doc, offset)
    }

    /// To end of current paragraph, or of the next one when already at an end.
    fn next_paragraph_boundary(&self, offset: usize) -> usize {
        next_paragraph_boundary_in(&self.doc, offset)
    }

    /// Word-bound segment containing `offset` (for double-click selection).
    fn word_range_at(&self, offset: usize) -> Range<usize> {
        let (start, end) = self.paragraph_bounds(offset);
        if start == end {
            return start..end;
        }
        let local = (offset - start).min(end - start - 1);
        let line = self.doc.slice_bytes(start..end);
        for (ix, seg) in line.split_word_bound_indices() {
            if ix <= local && local < ix + seg.len() {
                return start + ix..start + ix + seg.len();
            }
        }
        start..end
    }

    // -- Vertical movement ----------------------------------------------------

    fn vertical_by(&mut self, direction: i64, select: bool, cx: &mut Context<Self>) {
        let cursor = self.cursor_offset();
        let Some(frame) = self.last_frame.as_ref() else {
            return;
        };
        let Some((par_ix, line_ix, x)) = frame.cursor_position(cursor, self.cursor_affinity_down)
        else {
            return;
        };
        let x = self.goal_x.unwrap_or(x);

        let par = &frame.paragraphs[par_ix];
        let target = if direction > 0 {
            if line_ix + 1 < par.line_count() {
                Some((par_ix, line_ix + 1))
            } else if par_ix + 1 < frame.paragraphs.len() {
                Some((par_ix + 1, 0))
            } else {
                None
            }
        } else if line_ix > 0 {
            Some((par_ix, line_ix - 1))
        } else if par_ix > 0 {
            let prev = &frame.paragraphs[par_ix - 1];
            Some((par_ix - 1, prev.line_count() - 1))
        } else {
            None
        };

        let (offset, affinity) = match target {
            Some((p, l)) => {
                let par = &frame.paragraphs[p];
                let (ix, aff) = par.index_at(l, x);
                (par.range.start + ix, aff)
            }
            // First line up -> document start; last line down -> document end.
            None if direction > 0 => (frame.doc_len(), false),
            None => (0, false),
        };

        self.goal_x = Some(x);
        if select {
            self.extend_cursor(offset, affinity, cx);
        } else {
            self.set_cursor(offset, affinity, cx);
        }
    }

    /// GTK/Windows page motion: move the caret by a viewport (minus one line
    /// of overlap), preserving goal-x.
    fn page_by(&mut self, direction: i64, select: bool, cx: &mut Context<Self>) {
        let Some(frame) = self.last_frame.as_ref() else {
            return;
        };
        let cursor = self.cursor_offset();
        let Some((par_ix, line_ix, x)) = frame.cursor_position(cursor, self.cursor_affinity_down)
        else {
            return;
        };
        let x = self.goal_x.unwrap_or(x);
        let page = (frame.viewport_height - frame.line_height).max(frame.line_height);
        let par = &frame.paragraphs[par_ix];
        let y = par.top + par.text_top + par.line_height * (line_ix as f32) + par.line_height / 2.;
        let target = point(x, y + page * (direction as f32));
        let (offset, affinity) = frame.index_for_point(target);

        self.goal_x = Some(x);
        if select {
            self.extend_cursor(offset, affinity, cx);
        } else {
            self.set_cursor(offset, affinity, cx);
        }
    }

    // -- The picture's standing (inline-images §4/§5) -------------------------

    /// The live picture selection, revision-checked (R3's decay guard): the
    /// positional block index is the identity, so `Some` only while no
    /// document mutation happened since the state was minted and no takeover
    /// (history, the reading room) owns the surface. A revision mismatch is
    /// an unseen splice — decay, never a guess.
    fn image_sel_live(&self) -> Option<ImageSel> {
        let sel = self.image_sel?;
        if self.history_view.is_some() || self.cold_read.is_some() || self.strip.is_parked() {
            return None;
        }
        if sel.revision != self.doc.revision() || sel.block >= self.doc.blocks().len() {
            return None;
        }
        debug_assert!(
            matches!(self.doc.blocks().kind(sel.block), BlockKind::Image { .. }),
            "ImageSel resolves to a non-image block under an unchanged revision"
        );
        Some(sel)
    }

    /// `image_sel_live`'s mutating twin — the one funnel every verb enters
    /// through: a stale state is PURGED here, so nothing downstream ever
    /// acts on a decayed selection.
    fn resolve_image_sel(&mut self) -> Option<ImageSel> {
        let live = self.image_sel_live();
        if live.is_none() && self.image_sel.is_some() {
            self.decay_image_sel();
        }
        live
    }

    /// Plain decay (§4/§5): click elsewhere, caret motion, focus change —
    /// the state drops without harm and without moving the caret (the
    /// parked `selected_range` — the door caret, or the caption start —
    /// simply becomes visible again).
    fn decay_image_sel(&mut self) {
        self.image_sel = None;
        self.image_stage_hold = None;
    }

    /// Re-stamp the revision guard after a legitimate in-state mutation —
    /// the alt commit today, Phase 5's replace-in-place tomorrow. The ONE
    /// funnel (R3): any mutation that doesn't pass here decays the state.
    fn restamp_image_sel(&mut self, block: usize) {
        if let Some(sel) = self.image_sel.as_mut().filter(|s| s.block == block) {
            sel.revision = self.doc.revision();
        }
    }

    /// Byte range of a block's own line (text start..text end, separator
    /// excluded) — the unit every whole-block verb below acts on.
    fn image_block_bounds(&self, block: usize) -> (usize, usize) {
        image_block_bounds_in(&self.doc, block)
    }

    /// Enter the picture-selected state (§4 click law / §5 stage).
    /// `door_caret: Some` iff keyboard-born; `stage_key` is the staging
    /// press's own key, whose autorepeat must not complete the exile (R5).
    /// Entering collapses `selected_range` (R3) and parks the suppressed
    /// caret where Esc will restore it: the door caret when keyboard-born,
    /// else the caption start (§4's Esc law).
    fn enter_image_sel(
        &mut self,
        block: usize,
        door_caret: Option<usize>,
        stage_key: Option<&'static str>,
        cx: &mut Context<Self>,
    ) {
        debug_assert!(
            matches!(self.doc.blocks().kind(block), BlockKind::Image { .. }),
            "picture selection can only enter on an image block"
        );
        let park = door_caret.unwrap_or_else(|| self.doc.rope().line_to_byte(block));
        self.selected_range = park..park;
        self.selection_reversed = false;
        self.marked_range = None;
        self.goal_x = None;
        self.image_sel = Some(ImageSel {
            block,
            door_caret,
            revision: self.doc.revision(),
        });
        self.image_stage_hold = stage_key;
        self.last_input = Instant::now();
        // A state whose still cannot be seen does not count as shown (§4):
        // scroll the WHOLE block into view — top wins when the picture is
        // taller than the viewport — and cancel any pending caret scroll,
        // which knows nothing of the pixels above the caption line.
        if let Some(frame) = self.last_frame.as_ref() {
            if let Some(par) = frame.paragraphs.get(block) {
                let viewport = frame.viewport_height;
                let mut scroll = self.scroll_top;
                if par.top + par.height > scroll + viewport {
                    scroll = par.top + par.height - viewport;
                }
                if par.top < scroll {
                    scroll = par.top;
                }
                self.scroll_top = scroll;
            }
            self.autoscroll_request = false;
        } else {
            self.autoscroll_request = true;
        }
        self.on_selection_moved(cx); // LAW 1: the collapse lowers the flanks
        cx.notify();
    }

    /// The §5 delete-key law, at the top of every Backspace/Delete variant
    /// (the word-delete forms share it): completes a staged exile on a
    /// FRESH press, stages at a boundary door, refuses at a wall — or
    /// passes to the caller's ordinary path. Returns true when the press
    /// was consumed. Cost far from images: one block lookup and one pair
    /// of paragraph bounds (both O(log n) rope walks, no document scans).
    fn image_delete_gate(&mut self, key: &'static str, forward: bool, cx: &mut Context<Self>) -> bool {
        if !self.selected_range.is_empty() {
            return false; // range deletes go by §5's range door (the model law)
        }
        // While the picture is selected: a fresh press exiles; the staging
        // key's own autorepeat is refused until its key-up (R5) — a refused
        // press mutates nothing, so its still is identical (P6).
        if let Some(sel) = self.resolve_image_sel() {
            if exile_press_is_fresh(self.image_stage_hold, key) {
                self.exile_image_block(sel.block, cx);
            }
            return true;
        }
        if self.history_view.is_some() || self.strip.is_parked() || self.cold_read.is_some() {
            return false; // read-only surfaces own their own refusals
        }
        let cursor = self.cursor_offset();
        let (par_start, par_end) = self.paragraph_bounds(cursor);
        let block = self.doc.block_of_byte(cursor);
        let kinds = self.doc.blocks().kinds();
        let door = if forward {
            image_delete_door(kinds, block, cursor == par_end)
        } else {
            image_backspace_door(kinds, block, cursor == par_start, par_start == par_end)
        };
        match door {
            ImageDoor::Stage(target) => {
                self.enter_image_sel(target, Some(cursor), Some(key), cx);
                true
            }
            // A wall (§5): pure no-op — no revision bump, no transaction,
            // before and after stills identical (the refusal contract).
            ImageDoor::Refuse => true,
            ImageDoor::Pass => false,
        }
    }

    /// Complete a staged exile (§5): the block — picture AND caption —
    /// leaves whole through the whole-block door (`exile_to_graveyard` via
    /// `file_cut`'s interpret-blocks arm; NEVER a byte-range cut, whose
    /// clamp would leave a surviving separator and a wrong graveyard
    /// entry). The asset GC keeps graveyard-referenced pixels alive, so
    /// Put back restores picture and caption whole (P13). Post-exile caret
    /// law rides `file_cut`'s collapse-to-range-start: the start of the
    /// block that now follows, or — when the exiled block was last, where
    /// the exile ate its LEADING separator — the end of the previous block.
    fn exile_image_block(&mut self, block: usize, cx: &mut Context<Self>) {
        self.decay_image_sel();
        let (start, end) = self.image_block_bounds(block);
        self.file_cut(start..end, false, true, cx);
    }

    /// Block index when `position` (window coords) lands ON a picture's
    /// pixels (§4's click law): above the caption line (`par.text_top`)
    /// and within the centered picture's painted width — the same
    /// centering as paint (indent + (column − indent − w)/2). Clicks in
    /// the margins beside the pixels stay text clicks (the caption door).
    fn image_pixel_hit(&self, position: Point<Pixels>) -> Option<usize> {
        let frame = self.last_frame.as_ref()?;
        if self.history_preview.is_some() {
            return None;
        }
        let p = frame.doc_point(position);
        let par_ix = frame
            .paragraphs
            .partition_point(|par| par.top + par.height <= p.y);
        let par = frame.paragraphs.get(par_ix)?;
        // Stale-frame guard: never trust geometry past the live rope.
        if par.range.end > self.doc.len_bytes() {
            return None;
        }
        if p.y < par.top || p.y >= par.top + par.text_top.min(par.height) {
            return None; // below the pixels: the caption's own ground
        }
        if !matches!(self.doc.blocks().kinds().get(par_ix), Some(BlockKind::Image { .. })) {
            return None;
        }
        let (_, sz) = par.image.as_ref()?; // still decoding: no pixels to hit
        let img_x = par.indent + ((frame.bounds.size.width - par.indent - sz.width) / 2.).max(px(0.));
        (p.x >= img_x && p.x < img_x + sz.width).then_some(par_ix)
    }

    /// §9 copy/cut: the selected picture's travelling Markdown form
    /// `![alt](src "caption")`, produced by the ONE exporter so quoting
    /// and span flattening can never fork.
    fn image_block_markdown(&self, block: usize) -> Option<String> {
        image_block_markdown_in(&self.doc, block)
    }

    /// §9's two-entry travelling form for a selected picture: the Markdown
    /// line as text (caption and alt survive everywhere) and the stored
    /// bytes as a bitmap (real pixels where the pasteboard carries them —
    /// on Linux cross-app only the text half survives, the recorded
    /// platform cost). Bytes leave the asset store exactly as imported,
    /// so the bitmap entry's format is the asset's own extension.
    fn image_clipboard_item(&self, block: usize) -> Option<ClipboardItem> {
        let md = self.image_block_markdown(block)?;
        let mut entries = vec![ClipboardEntry::String(gpui::ClipboardString::new(md))];
        if let BlockKind::Image { src, .. } = self.doc.blocks().kind(block)
            && let Some(bytes) = self.store.as_ref().and_then(|s| s.get_asset(src))
        {
            entries.push(ClipboardEntry::Image(gpui::Image::from_bytes(
                image_format_for_src(src),
                bytes,
            )));
        }
        Some(ClipboardItem { entries })
    }

    // -- Actions -------------------------------------------------------------

    fn backspace(&mut self, _: &Backspace, window: &mut Window, cx: &mut Context<Self>) {
        // The picture walls come first (inline-images §5): complete a staged
        // exile, stage at a door, refuse at a wall — before the legacy
        // strip-the-kind arm below can drain an Image kind (§0's bug).
        if self.image_delete_gate("backspace", false, cx) {
            return;
        }
        if self.selected_range.is_empty() {
            // The boundary line is removed only via the aside machinery:
            // backspace at manuscript start is a no-op, like backspace at 0.
            if self.at_manuscript_start(self.cursor_offset()) {
                return;
            }
            // At the start of a styled block, the first backspace strips
            // the block kind instead of merging (Notion/Docs convention).
            let cursor = self.cursor_offset();
            let (par_start, _) = self.paragraph_bounds(cursor);
            if cursor == par_start {
                let block = self.doc.block_of_byte(cursor);
                if *self.doc.blocks().kind(block) != BlockKind::Paragraph {
                    self.doc.set_block_kind(block, BlockKind::Paragraph);
                    self.mark_dirty();
                    self.bump_activity();
                    cx.notify();
                    return;
                }
            }
            let prev = self.previous_boundary(cursor);
            self.select_to(prev, cx);
        }
        self.replace_text_in_range(None, "", window, cx);
        self.migrate_orphaned_writer_notes(window, cx);
    }

    fn delete(&mut self, _: &Delete, window: &mut Window, cx: &mut Context<Self>) {
        // The picture walls (inline-images §5): see backspace.
        if self.image_delete_gate("delete", true, cx) {
            return;
        }
        if self.selected_range.is_empty() {
            // Forward-delete at the compost tail must not merge the boundary.
            if self.at_compost_tail(self.cursor_offset())
                || self.at_separator_start(self.cursor_offset())
            {
                return;
            }
            let next = self.next_boundary(self.cursor_offset());
            self.select_to(next, cx);
        }
        self.replace_text_in_range(None, "", window, cx);
        self.migrate_orphaned_writer_notes(window, cx);
    }

    fn delete_word_left(&mut self, _: &DeleteWordLeft, window: &mut Window, cx: &mut Context<Self>) {
        // The picture walls (§5) — the word form shares the doors: the word
        // boundary only crosses a block edge from the edge itself, exactly
        // where the gate stands.
        if self.image_delete_gate("backspace", false, cx) {
            return;
        }
        if self.selected_range.is_empty() {
            if self.at_manuscript_start(self.cursor_offset()) {
                return;
            }
            let cursor = self.cursor_offset();
            let block = self.doc.block_of_byte(cursor);
            let (par_start, _) = self.paragraph_bounds(cursor);
            let prev = image_word_left_boundary(
                self.doc.blocks().kinds(),
                block,
                par_start,
                self.previous_word_boundary(cursor),
            );
            self.select_to(prev, cx);
        }
        self.replace_text_in_range(None, "", window, cx);
        self.migrate_orphaned_writer_notes(window, cx);
    }

    fn delete_word_right(
        &mut self,
        _: &DeleteWordRight,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        // The picture walls (§5) — see delete_word_left.
        if self.image_delete_gate("delete", true, cx) {
            return;
        }
        if self.selected_range.is_empty() {
            if self.at_compost_tail(self.cursor_offset())
                || self.at_separator_start(self.cursor_offset())
            {
                return;
            }
            let next = self.next_word_boundary(self.cursor_offset());
            self.select_to(next, cx);
        }
        self.replace_text_in_range(None, "", window, cx);
        self.migrate_orphaned_writer_notes(window, cx);
    }

    fn left(&mut self, _: &Left, _: &mut Window, cx: &mut Context<Self>) {
        // Parked in the past, the arrows walk the strip's snap points —
        // stations and the shoulders of big cuts. The rescue ratchet: "just
        // before the damage" is one keypress. (At now the strip is passive
        // and the caret keeps its keys.)
        if self.strip.is_parked() {
            self.strip_step(-1, cx);
            return;
        }
        // §4 arrows on a selected picture: deselect toward the direction —
        // left/up land at the end of the block before, right/down at the
        // caption's start. Never ON the pixels: there is no fourth state.
        if let Some(sel) = self.resolve_image_sel() {
            self.decay_image_sel();
            let end = sel
                .block
                .checked_sub(1)
                .map_or(0, |block| line_text_end_bytes(self.doc.rope(), block));
            self.move_to(end, cx);
            return;
        }
        if self.selected_range.is_empty() {
            self.move_to(self.previous_boundary(self.cursor_offset()), cx);
        } else {
            self.move_to(self.selected_range.start, cx);
        }
    }

    fn right(&mut self, _: &Right, _: &mut Window, cx: &mut Context<Self>) {
        if self.strip.is_parked() {
            self.strip_step(1, cx);
            return;
        }
        if let Some(sel) = self.resolve_image_sel() {
            let (start, _) = self.image_block_bounds(sel.block);
            self.decay_image_sel();
            self.move_to(start, cx); // §4: right/down → the caption's start
            return;
        }
        if self.selected_range.is_empty() {
            self.move_to(self.next_boundary(self.cursor_offset()), cx);
        } else {
            self.move_to(self.selected_range.end, cx);
        }
    }

    fn up(&mut self, _: &Up, _: &mut Window, cx: &mut Context<Self>) {
        if let Some(hv) = &self.history_view {
            let ix = hv.selected.saturating_sub(1);
            self.history_select(ix, cx);
            return;
        }
        if let Some(sel) = self.resolve_image_sel() {
            self.decay_image_sel();
            let end = sel
                .block
                .checked_sub(1)
                .map_or(0, |block| line_text_end_bytes(self.doc.rope(), block));
            self.move_to(end, cx); // §4: left/up → end of block before
            return;
        }
        self.vertical_by(-1, false, cx);
    }

    fn down(&mut self, _: &Down, _: &mut Window, cx: &mut Context<Self>) {
        if let Some(hv) = &self.history_view {
            let ix = hv.selected + 1;
            self.history_select(ix, cx);
            return;
        }
        if let Some(sel) = self.resolve_image_sel() {
            let (start, _) = self.image_block_bounds(sel.block);
            self.decay_image_sel();
            self.move_to(start, cx); // §4: right/down → the caption's start
            return;
        }
        self.vertical_by(1, false, cx);
    }

    fn toggle_history(&mut self, _: &ToggleHistory, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.history_view.is_some() {
            self.exit_history(cx);
        } else {
            self.enter_history(cx);
        }
    }

    /// "Scraps" — the travel verb (ctrl-shift-o / the footer chip; the old
    /// rail toggle retargeted, adjudications "the rail dies"). Arms the
    /// excursion latch with home captured NOW, then lands: the first press of
    /// a session at the seam (caret at the pile's first character — the count
    /// control flips to "scraps · N", the mid-pile screenshot self-identifies);
    /// later presses resume `pile_end`, clamped into the current pile.
    pub(crate) fn scraps_travel(&mut self, _: &ScrapsTravel, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.strip.is_parked() {
            // Fix-in-passing (scopes 12): the parked swallow becomes the
            // one uniform refusal.
            self.pulse_strip(cx);
            return;
        }
        if self.history_view.is_some() {
            return; // the past is a preview — no live travel over it
        }
        let Some(pile) = self.doc.scraps_char_range() else {
            return; // no region, nothing to travel to (the chip doesn't exist)
        };
        if self.excursion.is_none() {
            let home = if self.caret_in_scraps() {
                self.last_manuscript_caret
            } else {
                self.cursor_offset()
            };
            self.excursion = Some((home, f32::from(self.scroll_top)));
        }
        let target = match self.pile_end {
            Some(byte) => {
                let ch = self
                    .doc
                    .rope()
                    .byte_to_char(byte.min(self.doc.len_bytes()))
                    .clamp(pile.start, pile.end);
                self.doc.char_to_byte(ch)
            }
            None => self.doc.char_to_byte(pile.start),
        };
        self.move_to(target, cx);
        // Land with the seam in frame (not pinned to a viewport edge): the
        // caret's line sits a beat below the bar so the scrap line above it
        // stays visible — the station the travel names.
        if let Some(frame) = self.last_frame.as_ref()
            && let Some(pos) = frame.position_of(target.min(self.doc.len_bytes()), false)
        {
            self.scroll_top = (pos.y - px(120.)).max(px(0.));
            self.autoscroll_request = false;
        } else {
            self.autoscroll_request = true;
        }
        cx.notify();
    }

    // -- Scraps: the pile at the tail, and the graveyard ---------------------

    /// `Set aside` — the park/jot verb (08 §2): move the selection — or,
    /// with an empty selection, the caret's paragraph plus ONE adjoining
    /// newline (the jot; seam-mechanics 6d) — to just under the scrap line.
    /// A MOVE, never a cut (review H41). The whole atom lives in
    /// `Document::set_aside`: spans/kinds travel, notes re-anchor inside the
    /// atom, diagnosis cards retire; here we journal the retirements
    /// (CardClosed), clear a retired card's focus, place the caret at the
    /// collapse point (the writer parked a thought, she did not travel), and
    /// blink the receipt. Seam-spanning selections are refused (region verbs
    /// are single-region; seam-mechanics 2).
    fn set_aside(&mut self, _: &SetAside, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.strip.is_parked() {
            // Fix-in-passing (scopes 12): pulse, never a silent swallow.
            self.pulse_strip(cx);
            return;
        }
        if self.history_view.is_some() {
            return;
        }
        let jot = self.selected_range.is_empty();
        let range = if jot {
            let (start, end) = self.paragraph_bounds(self.cursor_offset());
            // One adjoining newline travels with the paragraph so no empty
            // block strands at the join: the trailing one when it exists,
            // else the leading one (the last-paragraph case).
            if end < self.doc.len_bytes() {
                start..end + 1
            } else if start > 0 {
                start - 1..end
            } else {
                start..end
            }
        } else {
            let sel = self.selected_range.clone();
            // A selection covering WHOLE paragraphs takes its adjoining
            // separator too (the jot's rule, widened to the blank-line
            // grammar): the prose closes up beneath the departing ghost —
            // the mockup's after-still is "the paragraph closed", never a
            // stranded blank the writer must sweep herself. A partial
            // selection stays exact (the remnant is untouched). Mirrors the
            // model's own separator absorption in move_to_manuscript.
            let whole_blocks = !sel.is_empty()
                && sel.start == self.paragraph_bounds(sel.start).0
                && sel.end == self.paragraph_bounds(sel.end.max(sel.start)).1;
            if whole_blocks {
                let bytes = self.doc.rope();
                // Widen only WITHIN the manuscript: the join above the seam
                // belongs to the boundary, and a widened range crossing it
                // would be refused as seam-spanning (the second-park bug the
                // rig caught).
                let m = self.doc.manuscript_char_range();
                let m_end = self.doc.char_to_byte(m.end);
                let m_start = self.doc.char_to_byte(m.start);
                let at = |i: usize| (i < m_end).then(|| bytes.byte(i));
                if sel.end + 2 <= m_end
                    && at(sel.end) == Some(b'\n')
                    && at(sel.end + 1) == Some(b'\n')
                {
                    sel.start..sel.end + 2 // the trailing blank-line separator
                } else if sel.end < m_end && at(sel.end) == Some(b'\n') {
                    sel.start..sel.end + 1 // a plain block join
                } else if sel.start >= m_start + 2
                    && at(sel.start - 1) == Some(b'\n')
                    && at(sel.start - 2) == Some(b'\n')
                {
                    sel.start - 2..sel.end // the leading separator (tail case)
                } else if sel.start > m_start {
                    sel.start - 1..sel.end
                } else {
                    sel
                }
            } else {
                sel
            }
        };
        if self.selection_spans_seam(&range) {
            return; // never offered on a spanning selection
        }
        // Freeze the origin ghost + the about-to-retire cards BEFORE the
        // model commits (afterwards there is nothing left to snapshot). Both
        // ride writer-initiated receipt channels, exempt from the lane's
        // burst snap (surfaces-attention 3 — every park is "mid-burst").
        let ghost = self.freeze_park_ghost(&range);
        let doomed_cards: Vec<MarginCard> = self
            .margin_cards(true)
            .cards
            .into_iter()
            .filter(|c| c.kind == NoteKind::Diagnosis)
            .collect();
        let quote = self.origin_quote_before(range.start);
        let Some(outcome) = self.doc.set_aside(range, quote, now_unix(), jot) else {
            return; // empty, scraps-side, or a top-era doc (migration owns those)
        };
        // Card retirement happened inside the atom; journal each terminal,
        // release focus if the retired card was active, and let its light
        // leave through the exit-fade ghost (never the burst-gated slide).
        let mut ghosts_pushed = false;
        for id in &outcome.retired {
            self.doc
                .journal_mut()
                .record_event(strop_core::journal::JournalEvent::CardClosed {
                    t: strop_core::journal::now_ms(),
                    id: *id,
                    resolved: false,
                });
            if self.focus.active_id() == Some(*id) {
                self.focus = CardFocus::Idle;
            }
            if let Some(card) = doomed_cards.iter().find(|c| c.id == *id) {
                self.departing.push((card.clone(), Instant::now()));
                ghosts_pushed = true;
            }
        }
        if ghosts_pushed {
            self.schedule_departing_clear(cx);
        }
        if let Some(g) = ghost {
            self.park_ghost = Some((g, Instant::now()));
            cx.spawn(async move |this, cx| {
                cx.background_executor()
                    .timer(CARD_RESOLVE + Duration::from_millis(50))
                    .await;
                this.update(cx, |editor: &mut Editor, cx| {
                    if editor
                        .park_ghost
                        .as_ref()
                        .is_some_and(|(_, t)| t.elapsed() >= CARD_RESOLVE)
                    {
                        editor.park_ghost = None;
                        cx.notify();
                    }
                })
                .ok();
            })
            .detach();
        }
        // The destination receipt (surfaces-attention 4): the landed block
        // flashes when the seam is on screen; the Scraps chip pulses when it
        // is not — mutually exclusive by the chip-hiding law, so both signals
        // are set and visibility picks the honest one.
        self.arrival_flash = Some(Instant::now());
        self.pulse_chip(cx);
        self.sync_mutations();
        let caret = self
            .doc
            .char_to_byte(outcome.caret.min(self.doc.rope().len_chars()));
        self.set_cursor(caret, false, cx);
        self.flank_latched = true; // a text-moving verb latches the flanks (LAW 1)
        self.schedule_flash_clear(cx);
        self.mark_dirty();
        self.bump_activity();
        cx.notify();
    }

    /// Does a byte range cross the seam (its ends fall in different
    /// regions)? Region verbs are never offered on spanning selections
    /// (seam-mechanics 2); the editing verbs split at the seam instead.
    fn selection_spans_seam(&self, range: &Range<usize>) -> bool {
        if self.doc.boundary().is_none() || range.is_empty() {
            return false;
        }
        let rope = self.doc.rope();
        let s = self.doc.region_of_char(rope.byte_to_char(range.start));
        let e = self.doc.region_of_char(rope.byte_to_char(range.end));
        s != e
    }

    /// `Send to the graveyard` (selection menu / palette): file the selection
    /// as a cut, any size — on EITHER side of the seam (one capture law,
    /// graveyard-interplay 5; Exile works below the seam, 08 §2). Refused on
    /// a seam-spanning selection (region verbs are single-region).
    fn send_to_graveyard(&mut self, _: &SendToGraveyard, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.history_view.is_some() || self.selected_range.is_empty() {
            return;
        }
        if self.selection_spans_seam(&self.selected_range.clone()) {
            return;
        }
        let range = self.selected_range.clone();
        // The deliberate verb collapses an emptied pile in the same atom
        // (graveyard-interplay 4) AND interprets whole-block intent (§B1).
        self.file_cut(range, true, true, cx);
        self.flank_latched = true; // a text-moving verb latches the flanks (LAW 1)
    }

    /// `Move to the manuscript` — the retrieval verb's SURFACE half (08 §2):
    /// a Scraps selection lands at the writing position the latch remembers
    /// (else the last manuscript caret), ARRIVING SELECTED — the selection is
    /// the feedback and the immediate undo/move handle (verso graft). One
    /// model atom (`Document::move_to_manuscript`: spans/kinds/notes travel
    /// home, the provenance record dies with its text, an emptied pile
    /// evaporates). The writer's text came home, and so does she: the
    /// excursion ends, `pile_end` remembering the spot it left.
    fn move_to_manuscript(
        &mut self,
        _: &MoveToManuscript,
        _: &mut Window,
        cx: &mut Context<Self>,
    ) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.history_view.is_some() || self.selected_range.is_empty() {
            return;
        }
        let range = self.selected_range.clone();
        let dest_byte = self
            .excursion
            .map(|(home, _)| home)
            .unwrap_or(self.last_manuscript_caret);
        let dest_char = self
            .doc
            .rope()
            .byte_to_char(dest_byte.min(self.doc.len_bytes()));
        self.land_from_pile(range, dest_char, cx);
    }

    /// `Put back` — the parity verb for a parked scrap (08 §2): the
    /// caret-block's provenance text returns to its ORIGIN — the paragraph
    /// after its origin quote, found by content (provenance is a
    /// range-anchored side record; the origin lives on as a quote). Lives
    /// inside the provenance one-liner and as this palette verb (the
    /// narrow-width fallback). Degrades to the retrieval landing when the
    /// quote was edited away — loudly selected either way, never silent.
    fn put_back_scrap(&mut self, _: &PutBackScrap, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.history_view.is_some() {
            return;
        }
        let ch = self
            .doc
            .rope()
            .byte_to_char(self.cursor_offset().min(self.doc.len_bytes()));
        let Some(rec) = self.doc.provenance().at(ch).cloned() else {
            return;
        };
        self.put_back_scrap_record(rec.id, cx);
    }

    /// Put a provenance record's text back at its origin (shared by the
    /// one-liner's verb and the palette verb).
    fn put_back_scrap_record(&mut self, id: u64, cx: &mut Context<Self>) {
        let Some(rec) = self
            .doc
            .provenance()
            .records()
            .iter()
            .find(|r| r.id == id)
            .cloned()
        else {
            return;
        };
        let sb = self.doc.char_to_byte(rec.range.start);
        let eb = self
            .doc
            .char_to_byte(rec.range.end.min(self.doc.rope().len_chars()));
        let dest_char = self.scrap_origin_dest(&rec.origin_quote);
        self.land_from_pile(sb..eb, dest_char, cx);
    }

    /// Where a scrap's origin return lands: the start of the line after the
    /// paragraph holding its origin quote (the spot the park cut from —
    /// content-anchored, so it follows the paragraph through edits); the
    /// last manuscript caret when the quote no longer exists.
    fn scrap_origin_dest(&self, quote: &str) -> usize {
        let rope = self.doc.rope();
        let m = self.doc.manuscript_char_range();
        if !quote.is_empty() {
            let hay = rope.slice(m.clone()).to_string();
            if let Some(b) = hay.find(quote) {
                let q_end = m.start + hay[..b + quote.len()].chars().count();
                let line = rope.char_to_line(q_end.min(rope.len_chars()));
                if line + 1 < rope.len_lines() {
                    return rope.line_to_char(line + 1).min(m.end);
                }
                return m.end;
            }
        }
        rope.byte_to_char(self.last_manuscript_caret.min(self.doc.len_bytes()))
            .min(m.end)
    }

    /// The shared landing for both pile-return verbs: run the model atom,
    /// arrive SELECTED at the destination, end the excursion (the writer's
    /// own verb brought her home) and remember `pile_end`.
    fn land_from_pile(&mut self, byte_range: Range<usize>, dest_char: usize, cx: &mut Context<Self>) {
        let pile_pos = byte_range.start;
        let Some(landed) = self.doc.move_to_manuscript(byte_range, dest_char) else {
            return;
        };
        self.sync_mutations();
        let s = self.doc.char_to_byte(landed.start.min(self.doc.rope().len_chars()));
        let e = self.doc.char_to_byte(landed.end.min(self.doc.rope().len_chars()));
        self.selected_range = s..e;
        self.selection_reversed = false;
        self.marked_range = None;
        // The text arrives SELECTED as its own move handle — but the offer is a
        // text-moving verb's aftermath, so latch the flanks down (LAW 1); the
        // next genuine selection change lifts the latch.
        self.flank_latched = true;
        self.flank_risen = false;
        self.flank_settle = None;
        self.flank_sel = self.selected_range.clone();
        self.excursion = None;
        self.pile_end = self
            .doc
            .boundary()
            .is_some()
            .then(|| pile_pos.min(self.doc.len_bytes()));
        self.last_manuscript_caret = e;
        self.publish_primary(cx);
        self.mark_dirty();
        self.bump_activity();
        cx.notify();
    }

    /// Snapshot the departing block's window-space geometry + text for the
    /// park receipt's origin ghost. `None` when no frame exists yet (a park
    /// before first paint — the receipt degrades to the chip pulse alone).
    fn freeze_park_ghost(&self, range: &Range<usize>) -> Option<ParkGhost> {
        let frame = self.last_frame.as_ref()?;
        let par = frame
            .paragraphs
            .iter()
            .find(|p| range.start <= p.range.end && p.range.start <= range.end)?;
        let mut park_seq = 0usize;
        if let Some((g, _)) = &self.park_ghost {
            park_seq = g.seq + 1;
        }
        Some(ParkGhost {
            text: self
                .doc
                .slice_bytes(range.clone())
                .trim_matches('\n')
                .replace('\n', " "),
            left: f32::from(frame.bounds.origin.x + par.indent),
            top: f32::from(frame.bounds.origin.y) + f32::from(par.top)
                - f32::from(frame.scroll_top),
            width: f32::from(frame.bounds.size.width - par.indent),
            font_size: f32::from(par.font_size),
            line_height: f32::from(par.line_height),
            seq: park_seq,
        })
    }

    /// The origin ghost's overlay (see `ParkGhost`): non-interactive, fading
    /// over CARD_RESOLVE with a short downward drift — the motion vector that
    /// says *down*, toward the pile. reduce_motion drops the drift.
    fn render_park_ghost(&self) -> Option<gpui::AnyElement> {
        let (g, _) = self.park_ghost.as_ref()?;
        let reduce = self.config.reduce_motion;
        let (top, left) = (g.top, g.left);
        Some(
            div()
                .absolute()
                .left(px(left))
                .top(px(top))
                .w(px(g.width))
                .font_family("PT Serif")
                .text_size(px(g.font_size))
                .line_height(px(g.line_height))
                .text_color(rgb(TEXT_COLOR))
                .child(g.text.clone())
                .with_animation(
                    ("park-ghost", g.seq),
                    Animation::new(CARD_RESOLVE).with_easing(|t| t * t),
                    move |el, t| {
                        let el = el.opacity(1. - t);
                        if reduce {
                            el
                        } else {
                            el.top(px(top + 6. * t))
                        }
                    },
                )
                .into_any_element(),
        )
    }

    /// File `byte_range` in the graveyard and collapse the caret to the cut
    /// point. Shared by the auto-cut trigger and the explicit verb — the one
    /// site that ever files a corpse. `collapse_emptied` folds a last-scrap
    /// exile's seam evaporation into the same transaction (the auto-capture
    /// path passes false: the retype-race guard governs it instead).
    fn file_cut(
        &mut self,
        byte_range: Range<usize>,
        collapse_emptied: bool,
        interpret_blocks: bool,
        cx: &mut Context<Self>,
    ) {
        let quote = self.origin_quote_before(byte_range.start);
        // The explicit exile verb interprets intent (papercuts §B1): a
        // whole-block selection takes its bounding separator, leaving no empty
        // grave. The auto-cut path (a plain type-over/backspace deletion) stays
        // exact-bytes — two verbs, two contracts.
        if interpret_blocks {
            self.doc
                .exile_to_graveyard(byte_range.clone(), quote, now_unix(), collapse_emptied);
        } else {
            self.doc
                .cut_to_graveyard(byte_range.clone(), quote, now_unix(), collapse_emptied);
        }
        let caret = byte_range.start.min(self.doc.len_bytes());
        self.selected_range = caret..caret;
        self.selection_reversed = false;
        self.cursor_affinity_down = false;
        self.goal_x = None;
        self.marked_range = None;
        self.grave_flash = Some(Instant::now());
        self.sync_mutations();
        self.bump_activity();
        self.schedule_flash_clear(cx);
        cx.notify();
        // The cut passage may have carried a margin note / diagnosis; its anchor
        // just collapsed. Migrate the note to the pile, close a dead
        // diagnosis (Bug C) — the one site that ever files a corpse is also the
        // one that must tidy the anchors the corpse leaves behind.
        self.reconcile_dead_anchors(cx);
    }

    /// A trailing fragment of the paragraph immediately before `byte_pos` — the
    /// entry's origin quote (never the whole context). When the cut begins right
    /// at a block boundary (the common case — whole paragraphs are cut), step
    /// back over the boundary newline so the quote is the PRIOR paragraph's tail
    /// rather than empty (the graveyard whisper reads "cut from after …" —
    /// `GraveEntry::origin_quote`). Stops at the next line break above that.
    fn origin_quote_before(&self, byte_pos: usize) -> String {
        let rope = self.doc.rope();
        let mut at = rope.byte_to_char(byte_pos.min(self.doc.len_bytes()));
        // The quote never crosses the seam (graveyard-interplay 2: one law
        // with counts/export): a cut at the pile's top quotes nothing rather
        // than the manuscript's last paragraph — the entry's `region` field
        // carries the "from scraps" honesty instead.
        let floor = match self.doc.region_of_char(at) {
            strop_core::document::Region::Scraps => {
                self.doc.scraps_char_range().map(|r| r.start).unwrap_or(0)
            }
            _ => self.doc.manuscript_char_range().start,
        };
        if at > floor && rope.char(at - 1) == '\n' {
            at -= 1; // the cut sits at a line start: name the paragraph above it
        }
        let end = at.max(floor);
        let mut from = end;
        let mut taken = 0;
        while from > floor && taken < 48 {
            if rope.char(from - 1) == '\n' {
                break;
            }
            from -= 1;
            taken += 1;
        }
        rope.slice(from..end).to_string().trim().to_owned()
    }

    /// The graveyard verb (menu / key): scroll to the tail section (Bug B — the
    /// record lives in the scroll flow now, there is nothing to "open"). Same
    /// gesture as clicking the footer bar.
    fn toggle_graveyard(&mut self, _: &ToggleGraveyard, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        self.scroll_to_graveyard(cx);
    }

    /// Reveal the graveyard tail section by scrolling to the document end (the
    /// section sits at the tail). The footer bar "unsticks into the section
    /// header" once it is on screen (asides.md §3).
    fn scroll_to_graveyard(&mut self, cx: &mut Context<Self>) {
        if self.doc.graveyard().is_empty() {
            return;
        }
        if let Some(frame) = self.last_frame.as_ref() {
            self.scroll_top = frame.max_scroll();
            cx.notify();
        }
    }

    /// Everything that changes the graveyard tail section's GEOMETRY beyond the
    /// document `revision` (which already covers the entries themselves): which
    /// receded entries the writer expanded. Keyed into `LayoutKey` so an expand
    /// forces a rebuild (the section grows) rather than a stale reuse.
    fn grave_layout_fingerprint(&self) -> u64 {
        let mut h = 1469598103934665603u64; // FNV-1a offset basis
        for id in &self.grave_expanded {
            h = (h ^ *id).wrapping_mul(1099511628211);
        }
        h
    }

    /// Is the graveyard tail section's header on screen? The sticky footer bar
    /// hides when it is (it "unsticks into the section header" — asides.md §3).
    /// Reads the last painted frame's recorded section top (doc-space).
    fn grave_tail_on_screen(&self) -> bool {
        self.last_frame.as_ref().is_some_and(|f| {
            f.grave_section_top
                .is_some_and(|top| top - f.scroll_top < f.viewport_height)
        })
    }

    /// The graveyard verb whose painted hit rect contains a window point, if any
    /// (Bug B click routing). Doc-space rects were recorded on the last frame.
    fn grave_action_at(&self, pos: Point<Pixels>) -> Option<GraveAction> {
        let frame = self.last_frame.as_ref()?;
        if frame.grave_lines.is_empty() {
            return None;
        }
        let doc = frame.doc_point(pos);
        frame
            .grave_lines
            .iter()
            .flat_map(|gl| gl.hits.iter())
            .find(|(rect, _)| rect.contains(&doc))
            .map(|(_, action)| *action)
    }

    /// Put an entry back into the manuscript (one verb everywhere — the entry
    /// action and the post-cut footer affordance). Re-anchored and clamped into
    /// the manuscript by the core; here we place the caret, flash the returned
    /// paragraph, and drop the now-stale expanded flag.
    fn put_back_entry(&mut self, id: u64, cx: &mut Context<Self>) {
        // A whole-block entry returns the caret at the START of its rebuilt
        // block (§B2 reveal-the-landing); a fragment splice returns it after
        // the re-inserted text (unchanged).
        let whole = self
            .doc
            .graveyard()
            .get(id)
            .map(|e| e.whole_blocks)
            .unwrap_or(false);
        let Some(caret_char) = self.doc.put_back(id) else {
            return;
        };
        self.sync_mutations();
        let caret = self.doc.char_to_byte(caret_char.min(self.doc.rope().len_chars()));
        self.grave_expanded.retain(|e| *e != id);
        // Flash the paragraph the passage returned to (P13's visible inverse):
        // the block itself for a whole-block return, the merged-into line for a
        // fragment splice.
        let flash_at = if whole {
            caret_char
        } else {
            caret_char.saturating_sub(1)
        };
        self.para_flash = Some((flash_at, Instant::now()));
        self.autoscroll_request = true;
        self.set_cursor(caret, false, cx);
        self.schedule_flash_clear(cx);
    }

    /// Move the caret to an entry's re-anchored origin — clamped into the
    /// REGION the text was cut from (graveyard-interplay 1: one seam-aware
    /// region law with capture/exile/put-back) — and flash that line;
    /// "show origin" reveals where the cut came from without re-inserting.
    fn show_grave_origin(&mut self, id: u64, cx: &mut Context<Self>) {
        let Some(e) = self.doc.graveyard().get(id) else {
            return;
        };
        let region = match e.region {
            strop_core::document::GraveRegion::Scraps => self
                .doc
                .scraps_char_range()
                .unwrap_or_else(|| self.doc.manuscript_char_range()),
            strop_core::document::GraveRegion::Manuscript => self.doc.manuscript_char_range(),
        };
        let at = e.origin_pos.clamp(region.start, region.end);
        let byte = self.doc.char_to_byte(at);
        self.para_flash = Some((at, Instant::now()));
        self.autoscroll_request = true;
        self.set_cursor(byte, false, cx);
        self.schedule_flash_clear(cx);
    }

    /// Delete an entry (the journal still holds the record). Undoable in core.
    fn delete_grave_entry(&mut self, id: u64, cx: &mut Context<Self>) {
        self.doc.grave_delete(id);
        self.grave_expanded.retain(|e| *e != id);
        self.mark_dirty();
        self.bump_activity();
        cx.notify();
    }

    /// Toggle a receded graveyard entry between its one-line and full forms
    /// (Bug B — click expands in place; the newest entry is always full).
    fn toggle_grave_entry(&mut self, id: u64, cx: &mut Context<Self>) {
        if let Some(ix) = self.grave_expanded.iter().position(|e| *e == id) {
            self.grave_expanded.remove(ix);
        } else {
            self.grave_expanded.push(id);
        }
        cx.notify();
    }

    /// Has this WRITER note lost its anchor? Either `Annotations::reanchor`
    /// flagged it `orphaned` on a restore, or an ordinary edit collapsed the
    /// anchor to a zero-width point. Diagnoses never qualify — machine cards
    /// are not writer material and stay in the card lifecycle.
    fn note_is_doomed(&self, id: u64) -> bool {
        self.doc.notes().get(id).is_some_and(|n| {
            n.kind == NoteKind::Note
                && n.status == NoteStatus::Open
                && (n.orphaned || n.range.start == n.range.end)
        })
    }

    /// The ordinary-edit path (spec §3): after a deletion, migrate any writer
    /// note whose anchor collapsed. Has a Window, so an active doomed card is
    /// resolved-and-deselected properly first (review B5).
    fn migrate_orphaned_writer_notes(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        if self.focus.active_id().is_some_and(|id| self.note_is_doomed(id)) {
            self.deselect_card(window, cx);
        }
        self.perform_orphan_migrations(cx);
    }

    /// The restore path (spec §3): `reanchor` set `orphaned`. No Window here
    /// (history mode has no live composer), so a stray active card is simply
    /// cleared — there is no in-progress draft to commit.
    fn migrate_orphans_after_restore(&mut self, cx: &mut Context<Self>) {
        if self.focus.active_id().is_some_and(|id| self.note_is_doomed(id)) {
            self.focus = CardFocus::Idle;
        }
        self.perform_orphan_migrations(cx);
    }

    /// Move every doomed writer note's text to the compost tail. The caller has
    /// already resolved focus for any active doomed card.
    fn perform_orphan_migrations(&mut self, cx: &mut Context<Self>) {
        let doomed: Vec<u64> = self
            .doc
            .notes()
            .notes()
            .iter()
            .filter(|n| self.note_is_doomed(n.id))
            .map(|n| n.id)
            .collect();
        if doomed.is_empty() {
            return;
        }
        let mut migrated = false;
        for id in doomed {
            let anchor = self
                .doc
                .notes()
                .get(id)
                .map(|n| self.doc.char_to_byte(n.range.start.min(self.doc.rope().len_chars())))
                .unwrap_or(0);
            let quote = self.origin_quote_before(anchor);
            if self.doc.migrate_note_to_compost(id, &quote) {
                self.arrival_flash = Some(Instant::now());
                migrated = true;
            }
        }
        // The arrival receipt (the rail's first-birth auto-open died with
        // it): the landed block flashes when the seam is on screen; the
        // Scraps chip pulses when it is not.
        if migrated {
            self.pulse_chip(cx);
        }
        self.sync_mutations();
        self.schedule_flash_clear(cx);
        cx.notify();
    }

    /// Fire the Scraps chip's arrival pulse (the ring; reduce_motion renders
    /// the 420ms ARRIVAL_FLASH blink instead, gated at the chip's render).
    /// The seq keys each ring animation to its own arrival; the timer retires
    /// the pulse after the ring's two beats.
    fn pulse_chip(&mut self, cx: &mut Context<Self>) {
        self.chip_pulse = Some(Instant::now());
        self.chip_pulse_seq += 1;
        cx.spawn(async move |this, cx| {
            cx.background_executor()
                .timer(Duration::from_millis(CHIP_PULSE_MS + 60))
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                if editor
                    .chip_pulse
                    .is_some_and(|t| t.elapsed().as_millis() as u64 >= CHIP_PULSE_MS)
                {
                    editor.chip_pulse = None;
                    cx.notify();
                }
            })
            .ok();
        })
        .detach();
    }

    /// After a structural removal — a graveyard cut or a set-aside — reconcile
    /// the margin with the anchors that just died (Bug C). Both paths bypassed
    /// this before, so a cut annotated paragraph left the writer's own margin
    /// note floating, anchored to nothing.
    ///
    /// A WRITER note whose anchor is gone migrates to the compost tail wearing
    /// its anchor quote (spec §3, the designed provenance — the note simply
    /// changed address). A DIAGNOSIS whose anchor is gone is CLOSED instead — a
    /// machine card is never writer material and must not linger pointing at
    /// nothing: it is dismissed and the strip records its `CardClosed` terminal
    /// (the existing close idiom). Windowless, so it also serves the IME
    /// auto-cut path; it mirrors `migrate_orphans_after_restore`'s no-composer
    /// discipline (a cut is not a composer interaction — clear focus directly,
    /// commit no draft).
    fn reconcile_dead_anchors(&mut self, cx: &mut Context<Self>) {
        // Preserve the caret across any migration: an orphan-note migration
        // inserts at the compost tail, shifting every manuscript byte by the
        // same delta, so the caret's DISTANCE FROM THE DOCUMENT END is
        // invariant. The writer cut/parked a thought — she must not travel (P2).
        let len_before = self.doc.len_bytes();
        let tail = len_before.saturating_sub(self.cursor_offset().min(len_before));

        let doomed_diagnoses: Vec<u64> = self
            .doc
            .notes()
            .notes()
            .iter()
            .filter(|n| {
                n.kind == NoteKind::Diagnosis
                    && n.status == NoteStatus::Open
                    && (n.orphaned || n.range.start == n.range.end)
            })
            .map(|n| n.id)
            .collect();
        for id in &doomed_diagnoses {
            self.doc.set_note_status(*id, NoteStatus::Dismissed);
            self.doc
                .journal_mut()
                .record_event(strop_core::journal::JournalEvent::CardClosed {
                    t: strop_core::journal::now_ms(),
                    id: *id,
                    resolved: false,
                });
            if self.focus.active_id() == Some(*id) {
                self.focus = CardFocus::Idle;
            }
        }
        if !doomed_diagnoses.is_empty() {
            self.mark_dirty();
            self.bump_activity();
            cx.notify();
        }

        // Then the writer notes — their text migrates to the compost tail.
        if self.focus.active_id().is_some_and(|id| self.note_is_doomed(id)) {
            self.focus = CardFocus::Idle;
        }
        self.perform_orphan_migrations(cx);

        if self.doc.len_bytes() != len_before {
            let caret = self.doc.len_bytes().saturating_sub(tail);
            self.set_cursor(caret, false, cx);
        }
    }

    /// Clear the one-shot rail/graveyard arrival blinks after a beat.
    fn schedule_flash_clear(&self, cx: &mut Context<Self>) {
        cx.spawn(async move |this, cx| {
            cx.background_executor()
                .timer(Duration::from_millis(420))
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                editor.arrival_flash = None;
                editor.grave_flash = None;
                editor.para_flash = None;
                cx.notify();
            })
            .ok();
        })
        .detach();
    }

    // -- Region geometry (byte offsets) -------------------------------------

    /// Byte bounds of the region the caret is in: the manuscript, the pile,
    /// or the whole document when there is no seam. Ctrl+A scopes to this so a
    /// select-all in prose never sweeps up the pile (spec §1, review #110;
    /// era-aware via the core's one region source). A caret ON the seam
    /// (transiently possible mid-gesture) scopes to the manuscript.
    fn caret_region_bytes(&self) -> (usize, usize) {
        let len = self.doc.len_bytes();
        if self.doc.boundary().is_none() {
            return (0, len);
        }
        let cursor = self.doc.rope().byte_to_char(self.cursor_offset().min(len));
        let range = match self.doc.region_of_char(cursor) {
            strop_core::document::Region::Scraps => {
                self.doc.scraps_char_range().unwrap_or(0..0)
            }
            _ => self.doc.manuscript_char_range(),
        };
        (
            self.doc.char_to_byte(range.start),
            self.doc.char_to_byte(range.end),
        )
    }

    /// Selections SPAN the seam now (seam-mechanics 2 legalizes them; the
    /// old review-B4 clamp is gone) — but the moving end must never REST on
    /// the seam's own line: it snaps past it in the direction of travel, so
    /// a selection holds the seam only as an interior, never as an endpoint.
    fn clamp_to_region(&self, anchor: usize, target: usize) -> usize {
        self.snap_off_seam(target, target >= anchor)
    }

    /// Map a byte offset OFF the seam line (seam-mechanics 3: the caret
    /// never rests there; the position is zero-width for caret purposes).
    /// `down` picks the landing side when the offset is exactly on the seam:
    /// toward the pile (true) or back to the manuscript end (false).
    fn snap_off_seam(&self, byte: usize, down: bool) -> usize {
        let Some(_) = self.doc.boundary() else {
            return byte;
        };
        let ch = self.doc.rope().byte_to_char(byte.min(self.doc.len_bytes()));
        if self.doc.region_of_char(ch) != strop_core::document::Region::Seam {
            return byte;
        }
        let m = self.doc.manuscript_char_range();
        let s = self.doc.scraps_char_range().unwrap_or(m.clone());
        let target = if down {
            // Downward: the first position of the region below the seam
            // (tail era: the pile; top era: the manuscript).
            if s.start > m.end { s.start } else { m.start }
        } else {
            // Upward: the last position of the region above.
            if s.start > m.end { m.end } else { s.end }
        };
        self.doc.char_to_byte(target)
    }

    /// Is `byte` at the position just past the seam (the start of whichever
    /// region follows it)? Backspace there must be a no-op — the boundary is
    /// removed only via the park machinery (spec §1 guard), era-aware.
    fn at_manuscript_start(&self, byte: usize) -> bool {
        let Some(_) = self.doc.boundary() else {
            return false;
        };
        let m = self.doc.manuscript_char_range();
        let s = self.doc.scraps_char_range().unwrap_or(m.clone());
        let below_start = if s.start > m.end { s.start } else { m.start };
        byte == self.doc.char_to_byte(below_start)
    }

    /// Is `byte` at the end of the region ABOVE the seam (forward-delete
    /// there would merge the boundary away)? Era-aware.
    fn at_compost_tail(&self, byte: usize) -> bool {
        let Some(_) = self.doc.boundary() else {
            return false;
        };
        let m = self.doc.manuscript_char_range();
        let s = self.doc.scraps_char_range().unwrap_or(m.clone());
        let above_end = if s.start > m.end { m.end } else { s.end };
        byte == self.doc.char_to_byte(above_end)
    }

    /// Caret at the START of the boundary's own empty line. Forward-delete
    /// here would eat the separator's newline and merge the seam into the
    /// pile's first block — the boundary index stays pinned, so a block
    /// silently changes regions with no visible change to the text. Wave-1
    /// review, correctness/high: the separator's newline is removable only
    /// by the park machinery, like the other two edges.
    fn at_separator_start(&self, byte: usize) -> bool {
        match self.doc.boundary() {
            Some((_, b)) => byte == self.doc.rope().line_to_byte(b),
            None => false,
        }
    }

    /// "Set Session Goal…" (DESIGN §4.2): a number, a live delta in the
    /// titlebar, a quiet sage dot at the finish line. Session-only.
    /// The goal editor swaps INLINE into the count chip (the rename idiom —
    /// P8, one grammar for one meaning; the old bottom strip made the writer
    /// click top-left and type at the bottom edge, and needed a legend). The
    /// field opens prefilled with the current goal, selected: typing
    /// replaces the datum, erasing it erases the goal — the inverse lives in
    /// the same grammar as the verb (P13), so no "0 clears" caption exists.
    fn set_session_goal(&mut self, _: &SetSessionGoal, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.goal_input.is_some() {
            return;
        }
        let seed = self
            .session_goal
            .map(|(goal, _)| goal.to_string())
            .unwrap_or_default();
        let input = cx.new(|cx| TextField::single_selected(cx, seed));
        cx.subscribe_in(
            &input,
            window,
            |editor, _, event: &TextFieldEvent, window, cx| {
                match event {
                    TextFieldEvent::Commit(text) => {
                        // A number sets; an ERASED field (or 0) clears;
                        // garbage is ignored gracefully.
                        let text = text.trim().replace([',', ' '], "");
                        match (text.is_empty(), text.parse::<usize>()) {
                            (true, _) | (_, Ok(0)) => editor.session_goal = None,
                            (_, Ok(goal)) => {
                                editor.session_goal = Some((goal, editor.word_count));
                            }
                            (_, Err(_)) => {}
                        }
                    }
                    TextFieldEvent::Cancel => {}
                }
                editor.goal_input = None;
                window.focus(&editor.focus_handle, cx);
                cx.notify();
            },
        )
        .detach();
        cx.observe(&input, |_, _, cx| cx.notify()).detach();
        self.commit_field_on_blur(&input, window, cx, |e| e.goal_input.clone());
        let input_focus = input.read(cx).focus_handle.clone();
        window.focus(&input_focus, cx);
        self.goal_input = Some(input);
        cx.notify();
    }

    /// DESIGN §0.6 law 2: Esc dismisses exactly the TOPMOST layer, one per
    /// press, regardless of where keyboard focus sits. This is the Editor-
    /// context half; a focused field's own Esc goes through FieldCancel,
    /// which closes the same layer. Order: AI settings → palette →
    /// shortcuts → selection popover → find/replace → history takeover.
    fn escape_mode(&mut self, _: &EscapeMode, window: &mut Window, cx: &mut Context<Self>) {
        if matches!(self.quit_guard, QuitGuard::Failed(_)) {
            self.cancel_quit(window, cx);
            return;
        }
        // The cold read's belt for focus loss (F4): its own key context owns
        // Esc while focused; this branch catches an Esc that reached the
        // editor context while the takeover is somehow up.
        if self.cold_read.is_some() {
            self.cr_escape_impl(window, cx);
            return;
        }
        if self.ai_settings.is_some() {
            self.close_ai_settings(window, cx);
            return;
        }
        if self.palette_input.is_some() {
            // The known bug: palette open + focus on the editor + Esc
            // previously fell through to the (empty) fallback.
            self.close_palette(window, cx);
            return;
        }
        if self.editor_menu_open {
            self.editor_menu_open = false;
            cx.notify();
            return;
        }
        // The link argument-field is the innermost flank layer (finding 59's
        // two-level Esc): its own FieldCancel handles Esc while it holds focus;
        // this covers the edge case where the editor has focus with a field open.
        if self.link_input.is_some() {
            self.cancel_link(window, cx);
            return;
        }
        // A selected picture is its own dismissable layer (inline-images
        // §4/§5 decay): Esc deselects and returns the caret exactly whence
        // the state was entered — the door caret when keyboard-born, the
        // caption start when click-born. The parked `selected_range` IS
        // that caret (enter_image_sel), so dropping the state reveals it;
        // cancellation relocating the locus is itself harm.
        if self.resolve_image_sel().is_some() {
            self.decay_image_sel();
            self.bump_activity(); // the caret returns: blink solid, scroll to it
            cx.notify();
            return;
        }
        // The travel-home and history/strip layers run BEFORE the
        // collapse-selection fallback (finding 5): a find/@/chip jump often
        // leaves the matched text SELECTED under a latched excursion, and the
        // documented contract ("Esc closes find, Esc travels home", ~4947) must
        // cost two presses, not three. Field-cancel still comes first (spec §1
        // A1 — the field layers above already returned).
        //
        // Esc-home ends a LATCHED excursion (08 §2; scopes-search 1): only a
        // tail entered by travel — chip, ctrl-shift-o, a find/@ jump — travels
        // back; a caret the writer walked in herself (scroll-and-click) makes
        // the pile plain text and Esc falls through. Both caret and scroll
        // return to their travel-time values; `pile_end` is written by the
        // pile-leaving transition in `set_cursor`, so the next chip press
        // resumes exactly here.
        if self.caret_in_scraps() && let Some((home, home_scroll)) = self.excursion {
            let target = home.min(self.doc.len_bytes());
            self.move_to(target, cx);
            // Force-drop the latch even when "home" itself sits in the pile
            // (a find opened from a pile caret): the excursion is over either
            // way, and Esc must fall through on the next press.
            self.excursion = None;
            self.scroll_top = px(home_scroll);
            self.autoscroll_request = false;
            cx.notify();
            return;
        }
        // (No second palette check here: the one at the top of this fn already
        // returned — the duplicate was unreachable, extraction audit #24.)
        // The strip: parked → return to now (drop the preview); already at now →
        // close it (spec §2 / review mid — restores the app-wide Esc-closes rule).
        if self.strip.open {
            if self.strip.parked {
                if self.strip.pin_ms.is_some() {
                    self.strip_done_comparing(cx);
                } else {
                    self.strip_return_to_now(cx);
                }
            } else {
                self.close_strip(cx);
            }
            return;
        }
        if self.history_view.is_some() {
            self.exit_history(cx);
            return;
        }
        let glanced = self.focus.active_id().is_some_and(|id| {
            self.doc.notes().get(id).is_some_and(|n| n.kind == NoteKind::Diagnosis)
        });
        match door_escape_step(self.drafting, glanced, self.resting_diagnoses() > 0) {
            DoorEscape::Glance => {
                self.focus = CardFocus::Idle;
                cx.notify();
                return;
            }
            DoorEscape::Fan => {
                self.toggle_door(cx);
                return;
            }
            DoorEscape::None => {}
        }
        // The flanks are NEVER their own Escape layer (LAW 1): with nothing
        // bigger to dismiss, Escape collapses a live selection to a caret, which
        // lowers the flanks as a consequence. Latch so a restore can't re-raise
        // them. Last, so a match-selection never shadows travel-home above.
        if !self.selected_range.is_empty() {
            let caret = self.cursor_offset();
            self.set_cursor(caret, self.cursor_affinity_down, cx);
            self.flank_latched = true;
        }
    }

    /// ctrl-.: the deliberate keyboard summon (LAW 1 / A1 — the ARIA-toolbar
    /// requirement, no capability reachable by only one modality). Unlike the
    /// passive settle-gated raise, this forces the flanks up NOW (past the beat
    /// and any latch) and moves focus INTO the flank, where arrows navigate cells
    /// and Enter fires; Escape (`exit_flank`) returns to the prose caret.
    fn toggle_popover(&mut self, _: &TogglePopover, window: &mut Window, cx: &mut Context<Self>) {
        if self.selected_range.is_empty() {
            return;
        }
        self.flank_latched = false;
        self.flank_risen = true;
        self.flank_settle = None;
        self.flank_sel = self.selected_range.clone();
        // Only ENTER the flank when the grid form actually paints in a real
        // gutter (finding 2). The horizontal fallback is formatting-only display
        // with no cell navigation, and the link field owns the flank when open —
        // focusing `flank_focus_handle` in either case would strand the keyboard
        // on an unpainted target. Where there's no grid, raise the flank as pure
        // display and keep prose focus.
        let grid = self.link_input.is_none()
            && self
                .flank_layout(window)
                .is_some_and(|l| l.gate.left == FlankLeft::Grid);
        if grid {
            self.enter_flank(window, cx);
        } else {
            cx.notify();
        }
    }

    /// Move keyboard focus into the raised flank (the ctrl-. deliberate path).
    /// The saved caret is the selection's own live range, restored by
    /// `exit_flank`. Passive raise never calls this — it claims no focus.
    fn enter_flank(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        self.flank_focus_cell = 0;
        self.flank_focused = true;
        window.focus(&self.flank_focus_handle, cx);
        cx.notify();
    }

    /// Return focus to the prose at the live selection (Escape from a focused
    /// flank). The selection was never disturbed, so the caret lands where it
    /// left off.
    fn exit_flank(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        self.flank_focused = false;
        window.focus(&self.focus_handle, cx);
        cx.notify();
    }

    fn show_shortcuts(&mut self, _: &ShowShortcuts, window: &mut Window, cx: &mut Context<Self>) {
        if let Some(reference) = self.keymap_window {
            if reference.update(cx, |_, reference_window, _| {
                match crate::keymap_window::toggle_decision(true) {
                    crate::keymap_window::ToggleDecision::CloseAndRestore => {
                        reference_window.remove_window();
                    }
                    crate::keymap_window::ToggleDecision::Open => unreachable!(),
                }
            }).is_ok() {
                self.keymap_closed();
                window.activate_window();
                window.focus(&self.focus_handle, cx);
                return;
            }
            self.keymap_window = None;
        }
        let editor = cx.entity();
        if let Some(reference) = crate::keymap_window::open(
            editor,
            window.window_handle(),
            window.bounds(),
            cx,
        ) {
            self.keymap_window = Some(reference);
        }
    }

    fn show_about(&mut self, _: &crate::AboutStrop, window: &mut Window, cx: &mut Context<Self>) {
        if let Some(reference) = self.about_window {
            if reference.update(cx, |_, reference_window, _| {
                match crate::about::toggle_decision(true) {
                    crate::about::ToggleDecision::CloseAndRestore => {
                        reference_window.remove_window();
                    }
                    crate::about::ToggleDecision::Open => unreachable!(),
                }
            }).is_ok() {
                self.about_closed();
                window.activate_window();
                window.focus(&self.focus_handle, cx);
                return;
            }
            self.about_window = None;
        }
        self.about_window = crate::about::open(
            cx.entity(), window.window_handle(), window.bounds(), cx);
    }

    pub(crate) fn keymap_closed(&mut self) {
        self.aux_closed(AuxSlot::Keymap);
    }

    pub(crate) fn about_closed(&mut self) {
        self.aux_closed(AuxSlot::About);
    }

    fn aux_closed(&mut self, slot: AuxSlot) {
        match slot {
            AuxSlot::Keymap => self.keymap_window = None,
            AuxSlot::About => self.about_window = None,
        }
    }

    fn open_welcome(&mut self, _: &OpenWelcome, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        crate::files::open_welcome_window();
    }

    /// The AI settings panel (DESIGN §2-ai, F4): centered in-surface
    /// overlay like the keyboard map — backdrop, esc/click-out closes.
    /// Form + async test with inline states + pickable /models list; the
    /// config file stays the storage (Save writes through toml_edit).
    fn render_ai_settings(&self, cx: &mut Context<Self>) -> impl IntoElement {
        let panel = self.ai_settings.as_ref().expect("ai settings open");
        let key_from_env = env_key_set();
        let filtered = self.ai_settings_filtered(cx);
        let selected = panel.selected.min(filtered.len().saturating_sub(1));
        let has_models = !panel.models.is_empty();
        let models_note = panel.models_note.clone();

        let label = |text: &'static str| {
            div()
                .text_size(px(10.))
                .text_color(rgb(MUTED_COLOR))
                .child(text.to_uppercase())
        };
        let helper = |text: String| {
            div()
                .text_size(px(10.5))
                .text_color(rgb(MUTED_COLOR))
                .child(text)
        };
        let button = |id: &'static str, text: &'static str| {
            div()
                .id(id)
                .px(px(10.))
                .py(px(3.))
                .rounded(px(4.))
                .border_1()
                .border_color(rgb(RULE_COLOR))
                .cursor(CursorStyle::PointingHand)
                .hover(|d| d.bg(rgba(0x1A1A180Au32)))
                .text_size(px(12.))
                .child(text)
        };
        // Inline feedback, never a margin card while the panel is open.
        let status_line = match &panel.test {
            AiSettingsTest::Idle => None,
            AiSettingsTest::Running => Some(
                div()
                    .text_size(px(11.))
                    .text_color(rgb(MUTED_COLOR))
                    .child("testing…"),
            ),
            // ✓ / ✗ glyphs carry the pass/fail distinction without relying on
            // color (WCAG 1.4.1); failure wears the reserved ERROR red.
            AiSettingsTest::Ok { ms } => Some(
                div()
                    .text_size(px(11.))
                    .text_color(rgb(0x4F7A4A))
                    .child(format!("✓ OK · {ms}ms")),
            ),
            AiSettingsTest::Failed { message } => Some(
                div()
                    .text_size(px(11.))
                    .text_color(rgb(ERROR))
                    .child(format!("✗ {message}")),
            ),
        };
        let mut model_list = div()
            .id("ai-models-list")
            .max_h(px(170.))
            .overflow_y_scroll()
            .flex()
            .flex_col()
            .border_1()
            .border_color(rgb(RULE_COLOR))
            .rounded(px(4.));
        for (ix, m) in filtered.iter().enumerate() {
            let model_id = m.clone();
            model_list = model_list.child(
                div()
                    .id(("ai-model-row", ix))
                    .px(px(8.))
                    .py(px(3.))
                    .text_size(px(12.))
                    .cursor(CursorStyle::PointingHand)
                    .when(ix == selected, |d| d.bg(rgba(0x1A1A1812u32)))
                    .hover(|d| d.bg(rgba(0x1A1A180Au32)))
                    .on_mouse_down(
                        MouseButton::Left,
                        cx.listener(move |editor, _: &MouseDownEvent, _, cx| {
                            cx.stop_propagation();
                            if let Some(panel) = &editor.ai_settings {
                                let m = model_id.clone();
                                panel.model.update_checked(cx, |input, cx| {
                                    input.content = m;
                                    cx.notify();
                                });
                            }
                            cx.notify();
                        }),
                    )
                    .child(m.clone()),
            );
        }
        let focus_field = |which: usize| {
            cx.listener(move |editor: &mut Editor, _: &MouseDownEvent, window, cx| {
                cx.stop_propagation();
                if let Some(panel) = &editor.ai_settings {
                    let field = [&panel.base_url, &panel.api_key, &panel.model][which];
                    let handle = field.read(cx).focus_handle.clone();
                    window.focus(&handle, cx);
                }
            })
        };

        div()
            .absolute()
            .inset_0()
            .bg(rgba(0x1A1A1830u32))
            .flex()
            .items_center()
            .justify_center()
            .on_action(cx.listener(Self::settings_up))
            .on_action(cx.listener(Self::settings_down))
            .on_action(cx.listener(Self::save_ai_settings))
            .on_mouse_down(
                MouseButton::Left,
                cx.listener(|editor, _: &MouseDownEvent, window, cx| {
                    cx.stop_propagation();
                    editor.close_ai_settings(window, cx);
                }),
            )
            .child(
                div()
                    .id("ai-settings-panel")
                    .w(px(520.))
                    .max_h(px(600.))
                    .bg(rgb(0xFCFAF4))
                    .border_1()
                    .border_color(rgb(RULE_COLOR))
                    .rounded(px(8.))
                    .shadow_lg()
                    .p(px(18.))
                    .font_family("PT Serif")
                    .text_color(rgb(TEXT_COLOR))
                    .flex()
                    .flex_col()
                    .gap(px(10.))
                    .on_mouse_down(MouseButton::Left, |_, _, cx| cx.stop_propagation())
                    .on_scroll_wheel(|_, _, cx| cx.stop_propagation())
                    .child(
                        div()
                            .flex()
                            .justify_between()
                            .child(
                                div()
                                    .text_size(px(15.))
                                    .font_weight(FontWeight::BOLD)
                                    .child("AI provider"),
                            )
                            .child(
                                div()
                                    .text_size(px(11.))
                                    .text_color(rgb(MUTED_COLOR))
                                    .child("esc closes · tab moves between fields"),
                            ),
                    )
                    // Provider picker (DESIGN principle 9): one click prefills
                    // the endpoint and points at where to get a key. Local
                    // first — no account, no key, fully private.
                    .child({
                        let current = provider_for(&panel.base_url.read(cx).content);
                        let mut row = div().flex().flex_wrap().gap(px(5.));
                        for p in PROVIDERS {
                            let active = match current {
                                Some(c) => std::ptr::eq(c, p),
                                None => p.host_match.is_empty(), // Custom owns the unmatched state
                            };
                            let base = p.base_url;
                            let list = p.host_match == "11434";
                            row = row.child(
                                div()
                                    .id(("ai-provider", p.label.as_ptr() as usize))
                                    .px(px(9.))
                                    .py(px(3.))
                                    .rounded(px(12.))
                                    .border_1()
                                    .border_color(rgb(RULE_COLOR))
                                    .cursor(CursorStyle::PointingHand)
                                    .text_size(px(11.5))
                                    .when(active, |d| {
                                        d.bg(rgba(0x1A1A1812u32)).text_color(rgb(TEXT_COLOR))
                                    })
                                    .when(!active, |d| d.text_color(rgb(MUTED_COLOR)))
                                    .hover(|d| d.bg(rgba(0x1A1A180Au32)))
                                    .tooltip(tip(p.note, None))
                                    .on_mouse_down(
                                        MouseButton::Left,
                                        cx.listener(move |editor, _: &MouseDownEvent, _, cx| {
                                            cx.stop_propagation();
                                            editor.ai_settings_pick_provider(base, list, cx);
                                        }),
                                    )
                                    .child(p.label),
                            );
                        }
                        row
                    })
                    .child(
                        div()
                            .flex()
                            .flex_col()
                            .gap(px(3.))
                            .on_mouse_down(MouseButton::Left, focus_field(0))
                            .child(label("Base URL"))
                            .child(panel.base_url.clone())
                            .child({
                                let url = panel.base_url.read(cx).content.clone();
                                match provider_for(&url) {
                                    Some(p) => helper(p.note.into()),
                                    None => helper(
                                        "any OpenAI-compatible /chat/completions endpoint".into(),
                                    ),
                                }
                            }),
                    )
                    .child(
                        div()
                            .flex()
                            .flex_col()
                            .gap(px(3.))
                            .on_mouse_down(MouseButton::Left, focus_field(1))
                            .child({
                                // "Get a key →" jumps to the current provider's
                                // key page — the missing-account step, in one
                                // click, without leaving for a search engine.
                                let key_url = (!key_from_env)
                                    .then(|| provider_for(&panel.base_url.read(cx).content))
                                    .flatten()
                                    .and_then(|p| p.key_url);
                                div()
                                    .flex()
                                    .justify_between()
                                    .items_center()
                                    .child(label("API key"))
                                    .when_some(key_url, |d, url| {
                                        d.child(
                                            div()
                                                .id("ai-get-key")
                                                .text_size(px(10.5))
                                                .text_color(rgb(0x4F6F8A))
                                                .cursor(CursorStyle::PointingHand)
                                                .hover(|d| d.text_color(rgb(TEXT_COLOR)))
                                                .on_mouse_down(
                                                    MouseButton::Left,
                                                    move |_: &MouseDownEvent, _, _| {
                                                        crate::files::open_external(url);
                                                    },
                                                )
                                                .child("Get a key →"),
                                        )
                                    })
                            })
                            .child(panel.api_key.clone())
                            .child(helper(if key_from_env {
                                "key comes from STROP_API_KEY; this field is ignored \
                                 and never written"
                                    .into()
                            } else {
                                "stored as plain text in config.toml — or export \
                                 STROP_API_KEY and leave this empty"
                                    .into()
                            })),
                    )
                    .child(
                        div()
                            .flex()
                            .flex_col()
                            .gap(px(3.))
                            .on_mouse_down(MouseButton::Left, focus_field(2))
                            .child(label("Model"))
                            .child(panel.model.clone())
                            .child(helper(
                                "free text — typing filters the provider's list below".into(),
                            )),
                    )
                    .child(
                        div()
                            .flex()
                            .items_center()
                            .gap(px(8.))
                            .child(button("ai-settings-test", "Test").on_mouse_down(
                                MouseButton::Left,
                                cx.listener(|editor, _: &MouseDownEvent, _, cx| {
                                    cx.stop_propagation();
                                    editor.ai_settings_test(cx);
                                }),
                            ))
                            .child(button("ai-settings-models", "List models").on_mouse_down(
                                MouseButton::Left,
                                cx.listener(|editor, _: &MouseDownEvent, _, cx| {
                                    cx.stop_propagation();
                                    editor.ai_settings_list_models(cx);
                                }),
                            ))
                            .child(
                                button(
                                    "ai-settings-save",
                                    if self.pending_pass.is_some() { "Save & run" } else { "Save" },
                                )
                                .on_mouse_down(
                                    MouseButton::Left,
                                    cx.listener(|editor, _: &MouseDownEvent, window, cx| {
                                        cx.stop_propagation();
                                        editor.save_ai_settings(&SaveAiSettings, window, cx);
                                    }),
                                ),
                            ),
                    )
                    .when_some(status_line, |d, status| d.child(status))
                    .when_some(models_note, |d, note| {
                        d.child(
                            div()
                                .text_size(px(11.))
                                .text_color(rgb(MUTED_COLOR))
                                .child(note),
                        )
                    })
                    .when(has_models, |d| {
                        if filtered.is_empty() {
                            d.child(
                                div()
                                    .text_size(px(11.))
                                    .text_color(rgb(MUTED_COLOR))
                                    .child("no models match the filter"),
                            )
                        } else {
                            d.child(model_list)
                        }
                    })
                    .child(
                        div()
                            .flex()
                            .justify_between()
                            .items_center()
                            .pt(px(2.))
                            .child(
                                div()
                                    .id("ai-settings-edit-file")
                                    .text_size(px(11.))
                                    .text_color(rgb(MUTED_COLOR))
                                    .cursor(CursorStyle::PointingHand)
                                    .hover(|d| d.text_color(rgb(TEXT_COLOR)))
                                    .on_mouse_down(
                                        MouseButton::Left,
                                        cx.listener(|editor, _: &MouseDownEvent, window, cx| {
                                            cx.stop_propagation();
                                            editor.close_ai_settings(window, cx);
                                            editor.open_ai_config(&OpenAiConfig, window, cx);
                                        }),
                                    )
                                    .child("Edit config file…"),
                            )
                            .child(
                                div()
                                    .text_size(px(10.))
                                    .text_color(rgb(MUTED_COLOR))
                                    .child("enter tests · ctrl-enter saves"),
                            ),
                    ),
            )
    }

    fn word_left(&mut self, _: &WordLeft, _: &mut Window, cx: &mut Context<Self>) {
        self.move_to(self.previous_word_boundary(self.cursor_offset()), cx);
    }

    fn word_right(&mut self, _: &WordRight, _: &mut Window, cx: &mut Context<Self>) {
        self.move_to(self.next_word_boundary(self.cursor_offset()), cx);
    }

    fn paragraph_up(&mut self, _: &ParagraphUp, _: &mut Window, cx: &mut Context<Self>) {
        self.move_to(self.previous_paragraph_boundary(self.cursor_offset()), cx);
    }

    fn paragraph_down(&mut self, _: &ParagraphDown, _: &mut Window, cx: &mut Context<Self>) {
        self.move_to(self.next_paragraph_boundary(self.cursor_offset()), cx);
    }

    fn select_paragraph_up(&mut self, _: &SelectParagraphUp, _: &mut Window, cx: &mut Context<Self>) {
        self.select_to(self.previous_paragraph_boundary(self.cursor_offset()), cx);
    }

    fn select_paragraph_down(
        &mut self,
        _: &SelectParagraphDown,
        _: &mut Window,
        cx: &mut Context<Self>,
    ) {
        self.select_to(self.next_paragraph_boundary(self.cursor_offset()), cx);
    }

    fn select_left(&mut self, _: &SelectLeft, _: &mut Window, cx: &mut Context<Self>) {
        self.select_to(self.previous_boundary(self.cursor_offset()), cx);
    }

    fn select_right(&mut self, _: &SelectRight, _: &mut Window, cx: &mut Context<Self>) {
        self.select_to(self.next_boundary(self.cursor_offset()), cx);
    }

    fn select_up(&mut self, _: &SelectUp, _: &mut Window, cx: &mut Context<Self>) {
        self.vertical_by(-1, true, cx);
    }

    fn select_down(&mut self, _: &SelectDown, _: &mut Window, cx: &mut Context<Self>) {
        self.vertical_by(1, true, cx);
    }

    fn select_word_left(&mut self, _: &SelectWordLeft, _: &mut Window, cx: &mut Context<Self>) {
        self.select_to(self.previous_word_boundary(self.cursor_offset()), cx);
    }

    fn select_word_right(&mut self, _: &SelectWordRight, _: &mut Window, cx: &mut Context<Self>) {
        self.select_to(self.next_word_boundary(self.cursor_offset()), cx);
    }

    fn select_all(&mut self, _: &SelectAll, _: &mut Window, cx: &mut Context<Self>) {
        // Scope to the caret's REGION (spec §1; adjudicated seam-mechanics 8):
        // the writer selecting-all in the manuscript must not sweep up the
        // pile, and vice versa. A SECOND ctrl-A widens to the whole document
        // (the recorded exception: ctrl-A+ctrl-C is a de-facto export path —
        // an audience surface wearing a hand's glove).
        let (start, end) = self.caret_region_bytes();
        if self.selected_range == (start..end) && self.doc.boundary().is_some() {
            self.selected_range = 0..self.doc.len_bytes();
            self.selection_reversed = false;
            self.publish_primary(cx);
            cx.notify();
            return;
        }
        self.move_to(start, cx);
        self.select_to(end, cx);
    }

    fn home(&mut self, _: &Home, _: &mut Window, cx: &mut Context<Self>) {
        let ((start, affinity), _) = self.visual_line_bounds(self.cursor_offset());
        self.goal_x = None;
        self.set_cursor(start, affinity, cx);
    }

    fn end(&mut self, _: &End, _: &mut Window, cx: &mut Context<Self>) {
        let (_, (end, affinity)) = self.visual_line_bounds(self.cursor_offset());
        self.goal_x = None;
        self.set_cursor(end, affinity, cx);
    }

    fn select_to_home(&mut self, _: &SelectToHome, _: &mut Window, cx: &mut Context<Self>) {
        let ((start, affinity), _) = self.visual_line_bounds(self.cursor_offset());
        self.goal_x = None;
        self.extend_cursor(start, affinity, cx);
    }

    fn select_to_end(&mut self, _: &SelectToEnd, _: &mut Window, cx: &mut Context<Self>) {
        let (_, (end, affinity)) = self.visual_line_bounds(self.cursor_offset());
        self.goal_x = None;
        self.extend_cursor(end, affinity, cx);
    }

    fn doc_start(&mut self, _: &DocStart, _: &mut Window, cx: &mut Context<Self>) {
        self.move_to(0, cx);
    }

    fn doc_end(&mut self, _: &DocEnd, _: &mut Window, cx: &mut Context<Self>) {
        self.move_to(self.doc.len_bytes(), cx);
    }

    fn select_to_doc_start(
        &mut self,
        _: &SelectToDocStart,
        _: &mut Window,
        cx: &mut Context<Self>,
    ) {
        self.select_to(0, cx);
    }

    fn select_to_doc_end(&mut self, _: &SelectToDocEnd, _: &mut Window, cx: &mut Context<Self>) {
        self.select_to(self.doc.len_bytes(), cx);
    }

    fn page_up(&mut self, _: &PageUp, _: &mut Window, cx: &mut Context<Self>) {
        if self.compare_preview.is_some() {
            self.compare_page_by(-1., cx);
            return;
        }
        self.page_by(-1, false, cx);
    }

    fn page_down(&mut self, _: &PageDown, _: &mut Window, cx: &mut Context<Self>) {
        if self.compare_preview.is_some() {
            self.compare_page_by(1., cx);
            return;
        }
        self.page_by(1, false, cx);
    }

    fn compare_page_by(&mut self, direction: f32, cx: &mut Context<Self>) {
        let handle = if self.compare_active_b {
            &self.compare_scroll_b
        } else {
            &self.compare_scroll_a
        };
        let page = (handle.bounds().size.height - px(30.)).max(px(30.));
        let max = handle.max_offset().y;
        let y = (handle.offset().y - page * direction).clamp(-max, px(0.));
        handle.set_offset(point(px(0.), y));
        cx.notify();
    }

    fn select_page_up(&mut self, _: &SelectPageUp, _: &mut Window, cx: &mut Context<Self>) {
        self.page_by(-1, true, cx);
    }

    fn select_page_down(&mut self, _: &SelectPageDown, _: &mut Window, cx: &mut Context<Self>) {
        self.page_by(1, true, cx);
    }

    fn newline(&mut self, _: &Newline, window: &mut Window, cx: &mut Context<Self>) {
        if self.history_view.is_some() {
            self.restore_selected(cx);
            return;
        }
        // §4: Enter on a selected picture makes room on the side the
        // insertion point faces — a selected object faces past itself, so
        // a fresh paragraph opens BELOW and takes the caret; the picture
        // stays (Enter makes room, a key that makes room must not destroy
        // furniture — §12). The split runs at the caption's end, so the
        // model's split law births the tail a Paragraph on its own (R6).
        // (image_sel_live is None under every read-only takeover, so this
        // arm cannot fire where edits are refused.)
        if let Some(sel) = self.resolve_image_sel() {
            self.decay_image_sel();
            let (_, end) = self.image_block_bounds(sel.block);
            self.doc.edit_bytes(end..end, "\n");
            let caret = end + 1;
            self.selected_range = caret..caret;
            self.selection_reversed = false;
            self.cursor_affinity_down = false;
            self.goal_x = None;
            self.marked_range = None;
            self.caret_attrs.clear();
            self.sync_mutations();
            self.bump_activity();
            cx.notify();
            return;
        }
        // §6: Enter at the start of a NON-EMPTY caption opens room ABOVE —
        // picture and caption stay together, the caret stays at the caption
        // start (a caret at text start faces before it; without this the
        // split law would strand the caption below a captionless picture).
        // Mid/end/empty fall through to the ordinary split below, where the
        // model's split law makes the tail a Paragraph (R6: no kind stamps;
        // the empty-caption collision resolves to below — §6).
        let cursor = self.cursor_offset();
        // Plain read-only checks, not cr_guard: this branch edits the
        // document directly, but a refused Enter must pulse exactly once —
        // the fallthrough's apply_replace owns that refusal.
        if self.cold_read.is_none()
            && !self.strip.is_parked()
            && self.selected_range.is_empty()
        {
            let block = self.doc.block_of_byte(cursor.min(self.doc.len_bytes()));
            if let BlockKind::Image { src, alt } = self.doc.blocks().kind(block).clone() {
                let (par_start, par_end) = self.paragraph_bounds(cursor);
                if caption_enter_opens_above(cursor == par_start, par_start == par_end) {
                    if par_start > 0 {
                        // Split the block ABOVE at its end: the flowing
                        // split law births the fresh line between prose and
                        // picture; the image block is never the split
                        // source, so nothing here can clone it (§2). The
                        // fragment clones its source's kind (flowing law) —
                        // demote non-paragraph residue in the same tx, the
                        // Enter-at-heading-end convention.
                        self.doc.edit_bytes(par_start - 1..par_start - 1, "\n");
                        if *self.doc.blocks().kind(block) != BlockKind::Paragraph {
                            self.doc
                                .set_block_kind_in_current_tx(block, BlockKind::Paragraph);
                        }
                    } else {
                        // Document-leading image: the split source IS the
                        // image block, whose FIRST fragment keeps the
                        // furniture kind (§2) — pointing the wrong way for
                        // room-above. Correct both fragments inside the same
                        // transaction (one undo restores everything): the
                        // deliberate, narrow exception to R6's no-stamping,
                        // where the model's law cannot express "room above
                        // at the document's head".
                        self.doc.edit_bytes(0..0, "\n");
                        self.doc
                            .set_block_kind_in_current_tx(0, BlockKind::Paragraph);
                        self.doc
                            .set_block_kind_in_current_tx(1, BlockKind::Image { src, alt });
                    }
                    let caret = par_start + 1; // the caption start, shifted past the fresh line
                    self.selected_range = caret..caret;
                    self.selection_reversed = false;
                    self.cursor_affinity_down = false;
                    self.goal_x = None;
                    self.marked_range = None;
                    self.caret_attrs.clear();
                    self.sync_mutations();
                    self.bump_activity();
                    cx.notify();
                    return;
                }
            }
        }
        // Enter at the end of a heading/divider starts a paragraph, not
        // another heading (the split otherwise inherits the block kind).
        let cursor = self.cursor_offset();
        let (_, par_end) = self.paragraph_bounds(cursor);
        let block = self.doc.block_of_byte(cursor.min(self.doc.len_bytes()));
        let demote = self.selected_range.is_empty()
            && cursor == par_end
            && matches!(
                self.doc.blocks().kind(block),
                BlockKind::Heading(_) | BlockKind::Divider
            );
        // Inline momentum dies at the paragraph seam (papercuts §A2): a new
        // paragraph starts with clean inline state, exactly as it starts with a
        // clean block kind. The span-side seam (SpanSet stops right-edge
        // expansion across a newline) covers marks the caret sits at the edge
        // of; clearing the sticky caret arm here means the freshly opened
        // paragraph is not still-armed. But `replace_text_in_range` may REFUSE
        // the edit (cold read, parked past): clear only AFTER the seam actually
        // opened (V5a), gauged by the revision bump — a refused Enter keeps the
        // writer's unspent arm intact.
        let rev = self.doc.revision();
        self.replace_text_in_range(None, "\n", window, cx);
        if self.doc.revision() == rev {
            return; // the edit was refused — arm and block kind untouched
        }
        self.caret_attrs.clear();
        if demote {
            let new_block = self.doc.block_of_byte(self.cursor_offset());
            self.doc
                .set_block_kind_in_current_tx(new_block, BlockKind::Paragraph);
            cx.notify();
        }
    }

    /// Toggle a block kind over the selected block range, one transaction.
    /// Formatting spans the seam (the writer's hands, seam-mechanics 10) —
    /// but kinds NEVER stamp the seam line itself: it renders as the seam
    /// regardless, and a kinded seam was the "tiny grey heading" bug.
    fn toggle_block(&mut self, kind: BlockKind, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return;
        }
        if self.history_view.is_some() {
            return;
        }
        let seam = self.doc.boundary().map(|(_, b)| b);
        let start_block = self.doc.block_of_byte(self.selected_range.start);
        let end_block = self.doc.block_of_byte(self.selected_range.end);
        // §2: the picture changes only by whole-block verbs, and a format
        // verb is not one of them — stamping over BlockKind::Image drops
        // src/alt and the pixels with them. Anchored ON the furniture
        // (caret in the caption, or the picture selected — ImageSel parks
        // the caret at the caption start), the verb refuses whole; the
        // selection decays without harm (§4's plain decay, nothing moves).
        if self.doc.blocks().kind(start_block).is_furniture() {
            if self.image_sel.is_some() {
                self.decay_image_sel();
                cx.notify();
            }
            return;
        }
        let target = if *self.doc.blocks().kind(start_block) == kind {
            BlockKind::Paragraph
        } else {
            kind
        };
        if Some(start_block) != seam {
            self.doc.set_block_kind(start_block, target.clone());
        } else {
            // Open the transaction the loop below rides even when the first
            // block is the seam (skipped).
            self.doc.set_block_kind(start_block, BlockKind::Paragraph);
        }
        for block in start_block + 1..=end_block {
            // A range that merely CROSSES furniture skips it — the same
            // lane the seam line rides (§2: the wall law holds inside a
            // sweep too).
            if Some(block) == seam || self.doc.blocks().kind(block).is_furniture() {
                continue;
            }
            self.doc.set_block_kind_in_current_tx(block, target.clone());
        }
        self.mark_dirty();
        self.bump_activity();
        cx.notify();
    }

    fn heading1(&mut self, _: &Heading1, _: &mut Window, cx: &mut Context<Self>) {
        self.toggle_block(BlockKind::Heading(1), cx);
    }

