    fn copy(&mut self, _: &Copy, _: &mut Window, cx: &mut Context<Self>) {
        if let Some((side_b, range)) = self.compare_selection.clone() {
            let (Some(a), Some(b)) = (
                self.compare_preview.as_ref(), self.history_preview.as_ref()) else { return };
            let text = compare_selected_text(a, b, side_b, range);
            crate::smoke::mirror_clipboard(&text);
            cx.write_to_clipboard(ClipboardItem::new_string(text));
            return;
        }
        if self.selected_range.is_empty() {
            // §9: the selected picture travels as TWO entries — the
            // Markdown line (caption + alt, the honest text form) and the
            // pixels — so elsewhere never gets a dead asset: link alone.
            if let Some(sel) = self.image_sel_live()
                && let Some(item) = self.image_clipboard_item(sel.block)
            {
                crate::smoke::mirror_clipboard_item(&item);
                cx.write_to_clipboard(item);
            }
            return;
        }
        // Copy MUST work while parked (Bug B): the writer wants to lift text out
        // of a past revision. The selection's byte offsets index the laid-out
        // text — which IS the preview while previewing — so the slice comes from
        // the preview string, not the live doc (`index_for_mouse` clamps to the
        // same source). The selection RENDERS in preview too (the reassembly's
        // surgical-rescue law), so what ctrl-c carries is what the eye saw.
        let text = match &self.history_preview {
            Some(p) => {
                let r = self.selected_range.start.min(p.text.len())
                    ..self.selected_range.end.min(p.text.len());
                p.text.get(r).unwrap_or("").to_owned()
            }
            // Live copy strips the seam from a spanning selection
            // (seam-mechanics 2 — the fragments join with one newline) and
            // carries whole-covered pictures in their Markdown form (§9).
            None => {
                let item = self.clipboard_item(&self.selected_range.clone());
                crate::smoke::mirror_clipboard_item(&item);
                cx.write_to_clipboard(item);
                return;
            }
        };
        crate::smoke::mirror_clipboard(&text);
        cx.write_to_clipboard(ClipboardItem::new_string(text));
    }

    fn cut(&mut self, _: &Cut, window: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        // A cut is a mutation — refused (pulsed) while parked, not a silent
        // copy-then-nothing (Bug B). Use Copy to lift text out of the past.
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return;
        }
        if self.selected_range.is_empty() {
            // §9 cut = copy + leave-whole: the same two entries, then the
            // block exits by the §5 whole-block door — both halves of the
            // verb in one gesture, inverse intact (P13: Put back, or paste
            // it back — either door).
            if let Some(sel) = self.resolve_image_sel()
                && let Some(item) = self.image_clipboard_item(sel.block)
            {
                crate::smoke::mirror_clipboard_item(&item);
                cx.write_to_clipboard(item);
                self.exile_image_block(sel.block, cx);
            }
            return;
        }
        // Cut = copy + delete (seam-mechanics 2): the clipboard joins a
        // spanning selection's fragments (pictures in Markdown form, §9);
        // the delete path below splits at the seam and leaves it between
        // the remnants.
        let item = self.clipboard_item(&self.selected_range.clone());
        crate::smoke::mirror_clipboard_item(&item);
        cx.write_to_clipboard(item);
        self.replace_text_in_range(None, "", window, cx);
    }

    fn paste(&mut self, _: &Paste, _: &mut Window, cx: &mut Context<Self>) {
        self.paste_from_clipboard(false, cx);
    }

    fn paste_plain(&mut self, _: &PastePlain, _: &mut Window, cx: &mut Context<Self>) {
        self.paste_from_clipboard(true, cx);
    }

    fn paste_from_clipboard(&mut self, plain: bool, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        // The or_else is the headless-rig transport shim (see
        // smoke::clipboard_item_override) — never set outside smoke runs;
        // it now carries whole items so the rig can round-trip §9's
        // two-entry image form, not just text.
        let Some(item) = cx
            .read_from_clipboard()
            .or_else(crate::smoke::clipboard_item_override)
        else {
            return;
        };
        if plain {
            if let Some((text, _)) = clipboard_text_and_rich(&item, true) {
                self.apply_replace(None, &text, false, true, cx);
            }
            return;
        }
        // §9's gates, priced for prose: one reference pass over the
        // entries, and the image-line parse runs only when the text even
        // contains "![" — an ordinary paste pays two finds and a substring
        // scan, no allocation beyond what it always paid.
        let rich = clipboard_text_and_rich(&item, false).and_then(|(_, rich)| rich);
        let mut entries = item.entries;
        let text_entry: Option<String> = entries.iter().find_map(|e| match e {
            ClipboardEntry::String(s) => Some(s.text().replace("\r\n", "\n")),
            _ => None,
        });
        let bitmap_ix = entries
            .iter()
            .position(|e| matches!(e, ClipboardEntry::Image(_)));
        let take_bitmap = |entries: &mut Vec<ClipboardEntry>, ix: usize| -> Vec<u8> {
            match entries.swap_remove(ix) {
                ClipboardEntry::Image(img) => img.bytes,
                _ => unreachable!("bitmap_ix indexes an Image entry"),
            }
        };
        let strop_line = text_entry
            .as_deref()
            .filter(|t| t.contains("!["))
            .and_then(strop_core::markdown::parse_image_line);

        if let Some(sel) = self.image_sel_live() {
            // §4: a paste that MEANS a picture, aimed at the selected
            // picture, replaces in place — same block, caption and alt
            // untouched, one undo step. The §9 precedence still orders the
            // pixel sources: the text form's asset: hash when it resolves
            // here (no bytes touched at all), else the sibling bitmap
            // through the §5b import. Text that isn't a picture falls
            // through — apply_replace's §4 gate types it into the caption.
            if let Some(line) = &strop_line {
                if self.store.as_ref().is_some_and(|s| s.has_asset(&line.src)) {
                    self.doc.replace_image_src(sel.block, line.src.clone());
                    self.restamp_image_sel(sel.block);
                    self.mark_dirty();
                    self.sync_mutations();
                    self.bump_activity();
                    cx.notify();
                } else if let Some(ix) = bitmap_ix {
                    let bytes = take_bitmap(&mut entries, ix);
                    self.replace_selected_image_pixels(sel, bytes, cx);
                } else {
                    // A picture-shaped paste whose pixels resolve nowhere:
                    // refused, logged — a replace that cannot deliver
                    // pixels must not degrade into caption text.
                    eprintln!(
                        "strop: paste aimed at the selected picture, \
                         but its pixels resolve nowhere; nothing changed"
                    );
                }
                return;
            }
            if let Some(ix) = bitmap_ix {
                let bytes = take_bitmap(&mut entries, ix);
                self.replace_selected_image_pixels(sel, bytes, cx);
                return;
            }
        } else if let Some(line) = &strop_line {
            // §9's precedence ladder, single image line: the text form
            // wins — caption and alt come from it ALWAYS; pixels from the
            // asset store when the hash resolves in this document, else
            // from the sibling bitmap (blake3 dedupe keeps the re-import
            // byte-honest), else the paste degrades to the literal
            // Markdown line as visible text — the fall-through below.
            if self.strip.is_parked() {
                self.pulse_strip(cx);
                return;
            }
            if self.history_view.is_some() {
                return;
            }
            if self.store.as_ref().is_some_and(|s| s.has_asset(&line.src)) {
                if self.selected_range.is_empty() && self.marked_range.is_none() {
                    // The picture verb's shape (§7): its own block after
                    // the caret's, caret parked past it.
                    let (caption, spans) =
                        strop_core::markdown::caption_from_title(&line.caption);
                    let cursor = self.cursor_offset().min(self.doc.len_bytes());
                    let cursor = self.doc.insert_image_block_full(
                        cursor,
                        line.src.clone(),
                        line.alt.clone(),
                        &caption,
                        &spans,
                    );
                    self.selected_range = cursor..cursor;
                    self.selection_reversed = false;
                    self.mark_dirty();
                    self.sync_mutations();
                    self.bump_activity();
                    cx.notify();
                    return;
                }
                // Over a range selection the paste is the text verb: the
                // rebuild splice replaces the selection in one step. A
                // landing the splice can't honor (seam, wall) degrades to
                // the literal line below — visible, never silent.
                if self.paste_rebuild_lines(
                    text_entry.as_deref().unwrap_or_default(),
                    vec![(0, line.clone())],
                    cx,
                ) {
                    return;
                }
            } else if let Some(ix) = bitmap_ix {
                let bytes = take_bitmap(&mut entries, ix);
                self.import_image_with_meta(bytes, line.alt.clone(), line.caption.clone(), cx);
                return;
            }
        } else if let Some(text) = text_entry.as_deref().filter(|t| t.contains("![") && t.contains('\n')) {
            // §9's range-paste: each LINE that parses as a Strop image
            // line with a resolving asset rebuilds an image block; every
            // other line stays literal visible text (the boundary rule).
            let images = image_lines_in(text, &|src| {
                self.store.as_ref().is_some_and(|s| s.has_asset(src))
            });
            if !images.is_empty() && self.paste_rebuild_lines(text, images, cx) {
                return;
            }
        }
        if let (Some(text), Some(rich)) = (text_entry.as_deref(), rich.as_ref())
            && !rich.blocks.is_empty()
        {
            let range = self.marked_range.clone().unwrap_or(self.selected_range.clone());
            if !self.selection_spans_seam(&range) {
                let line = self.doc.rope().byte_to_line(range.start);
                let prefix = usize::from(rich.starts_at_boundary
                    && range.start > self.doc.rope().line_to_byte(line));
                let suffix = usize::from(rich.ends_at_boundary
                    && range.start < line_text_end_bytes(self.doc.rope(), line)
                    && !text.ends_with('\n'));
                self.doc.paste_rich(range.clone(), text, rich);
                let caret = (range.start + prefix + text.len() + suffix)
                    .min(self.doc.len_bytes());
                self.selected_range = caret..caret;
                self.selection_reversed = false;
                self.marked_range = None;
                self.goal_x = None;
                self.caret_attrs.clear();
                self.mark_dirty();
                self.sync_mutations();
                self.bump_activity();
                cx.notify();
                self.reconcile_dead_anchors(cx);
                return;
            }
        }
        // The ordinary path (§9, amended with ExternalPaths import): the
        // FIRST entry decides the paste's meaning — a foreign bitmap takes
        // the bare §5b import, text pastes as text (never typographed —
        // already authored), copied file paths go to the image importer.
        // Every arm is terminal, so this is an `if`, not a loop.
        if let Some(entry) = entries.into_iter().next() {
            match entry {
                ClipboardEntry::Image(image) => {
                    self.import_image_bytes(image.bytes, cx);
                }
                ClipboardEntry::String(text) => {
                    let text = text.text().replace("\r\n", "\n");
                    self.apply_replace(None, &text, false, true, cx);
                }
                ClipboardEntry::ExternalPaths(paths) => {
                    let mut files = Vec::new();
                    let mut refused = false;
                    for path in paths.paths() {
                        // Copied file paths arrive through the same portal
                        // door as drops — resolve before reading.
                        let path = crate::files::resolve_portal_path(path);
                        match std::fs::read(&path) {
                            Ok(bytes) => files.push(bytes),
                            Err(e) => {
                                refused = true;
                                eprintln!("strop: cannot read {}: {e}", path.display());
                            }
                        }
                    }
                    cx.spawn(async move |this, cx| {
                        let (imported, refused) = cx.background_executor().spawn(async move {
                            let mut imported = Vec::new();
                            let mut refused = refused;
                            for bytes in files {
                                match strop_core::images::import_image(bytes) {
                                    Ok(image) => imported.push(image),
                                    Err(e) => {
                                        refused = true;
                                        eprintln!("strop: {e}");
                                    }
                                }
                            }
                            (imported, refused)
                        }).await;
                        this.update(cx, |editor: &mut Editor, cx| {
                            for image in imported {
                                editor.insert_imported_image(image, "", "", cx);
                            }
                            if refused { editor.pulse_strip(cx); }
                        }).ok();
                    }).detach();
                }
            }
        }
    }

    /// §9's multi-line rebuild: ONE verbatim splice carries the whole
    /// paste — image lines travel as their caption text — and the image
    /// kinds, alt and caption spans stamp inside the same transaction, so
    /// undo takes the paste back in one step. Boundary separators are
    /// added by the plan so a rebuilt picture always owns its whole line
    /// (the §2 wall's insert-shape corollary: prose never fuses onto a
    /// picture). Returns false — nothing mutated — when the landing
    /// crosses a law this splice can't honor (a seam-spanning or
    /// furniture-touching selection): the caller degrades to the literal
    /// text paste, visible, never silent (recorded ruling).
    fn paste_rebuild_lines(
        &mut self,
        text: &str,
        images: Vec<(usize, strop_core::markdown::ImageLine)>,
        cx: &mut Context<Self>,
    ) -> bool {
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return true; // consumed: the past is read-only
        }
        if self.history_view.is_some() {
            return true;
        }
        let range = self
            .marked_range
            .clone()
            .unwrap_or(self.selected_range.clone());
        if self.selection_spans_seam(&range) {
            return false;
        }
        if !range.is_empty() {
            // The wall-clamped replace decomposes at furniture and lands
            // the insert elsewhere than range.start — the stamp math below
            // would misdress blocks. Degrade instead of guessing.
            let rope = self.doc.rope();
            let first = rope.byte_to_line(range.start);
            let last = rope.byte_to_line(range.end.min(self.doc.len_bytes()));
            let kinds = self.doc.blocks().kinds();
            if kinds[first..=last.min(kinds.len().saturating_sub(1))]
                .iter()
                .any(BlockKind::is_furniture)
            {
                return false;
            }
        }
        let rope = self.doc.rope();
        let at_line_start = range.start == 0
            || rope.char(rope.byte_to_char(range.start) - 1) == '\n';
        let at_line_end = range.end < self.doc.len_bytes()
            && rope.char(rope.byte_to_char(range.end)) == '\n';
        let (final_text, stamps) =
            plan_image_line_rebuild(text, images, at_line_start, at_line_end);
        self.doc.edit_bytes_verbatim(range.clone(), &final_text);
        let base_line = self.doc.rope().byte_to_line(range.start);
        for (line_ix, line, spans) in &stamps {
            let block = base_line + line_ix;
            self.doc.set_block_kind_in_current_tx(
                block,
                BlockKind::Image {
                    src: line.src.clone(),
                    alt: line.alt.clone(),
                },
            );
            let cap_start = self.doc.rope().line_to_char(block);
            for s in spans.spans() {
                self.doc.format_in_current_tx(
                    cap_start + s.range.start..cap_start + s.range.end,
                    s.attr.clone(),
                    true,
                );
            }
        }
        let caret = (range.start + final_text.len()).min(self.doc.len_bytes());
        self.selected_range = caret..caret;
        self.selection_reversed = false;
        self.marked_range = None;
        self.goal_x = None;
        self.mark_dirty();
        self.sync_mutations();
        self.bump_activity();
        cx.notify();
        // A replaced range may have carried margin anchors, exactly like
        // any other structural removal.
        self.reconcile_dead_anchors(cx);
        true
    }

    /// Run the §5b import pipeline off the UI thread, then insert a block.
    fn import_image_bytes(&mut self, bytes: Vec<u8>, cx: &mut Context<Self>) {
        self.import_image_with_meta(bytes, String::new(), String::new(), cx);
    }

    /// §9's middle rung shares the §5b pipeline: the pixels re-import
    /// (blake3 dedupe keeps it byte-honest) and the block lands wearing
    /// the text form's caption and alt — empty for a bare bitmap.
    fn import_image_with_meta(
        &mut self,
        bytes: Vec<u8>,
        alt: String,
        caption_md: String,
        cx: &mut Context<Self>,
    ) {
        cx.spawn(async move |this, cx| {
            let result = cx
                .background_executor()
                .spawn(async move { strop_core::images::import_image(bytes) })
                .await;
            this.update(cx, |editor: &mut Editor, cx| match result {
                Ok(imported) => editor.insert_imported_image(imported, &alt, &caption_md, cx),
                Err(e) => eprintln!("strop: {e}"),
            })
            .ok();
        })
        .detach();
    }

    fn insert_imported_image(
        &mut self,
        imported: strop_core::images::Imported,
        alt: &str,
        caption_md: &str,
        cx: &mut Context<Self>,
    ) {
        let Some(store) = &self.store else {
            eprintln!("strop: image pasted, but no document store to keep it in");
            return;
        };
        let src = store.put_asset(imported.bytes, imported.ext);
        self.mark_dirty();
        let cursor = self.cursor_offset().min(self.doc.len_bytes());
        // The image stands as its OWN block and the caret lands at the START
        // of the block after it (report 4) — never ON the image, where typing
        // would write invisible text into the image block. The document owns
        // the shape (separators, trailing paragraph, kind stamp, one tx).
        let (caption, spans) = strop_core::markdown::caption_from_title(caption_md);
        let cursor =
            self.doc
                .insert_image_block_full(cursor, src, alt.to_owned(), &caption, &spans);
        self.selected_range = cursor..cursor;
        self.selection_reversed = false;
        self.sync_mutations();
        self.bump_activity();
        cx.notify();
    }

    /// §4 replace-in-place, the async half: the §5b import runs
    /// off-thread, and the SELECTION is re-checked on the UI thread after
    /// it lands — block AND revision — because the writer may have
    /// deselected or edited meanwhile. A decayed aim DROPS the operation
    /// (recorded ruling): a replace is aimed at a selection; when the aim
    /// is gone, materializing the picture at some caret the writer never
    /// aimed would be a silent insertion elsewhere — §4's exact forbidden
    /// outcome. Nothing destructive happened; one stderr line records the
    /// drop.
    fn replace_selected_image_pixels(
        &mut self,
        sel: ImageSel,
        bytes: Vec<u8>,
        cx: &mut Context<Self>,
    ) {
        cx.spawn(async move |this, cx| {
            let result = cx
                .background_executor()
                .spawn(async move { strop_core::images::import_image(bytes) })
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                let imported = match result {
                    Ok(i) => i,
                    Err(e) => {
                        eprintln!("strop: {e}");
                        return;
                    }
                };
                if editor
                    .image_sel_live()
                    .is_none_or(|l| (l.block, l.revision) != (sel.block, sel.revision))
                {
                    eprintln!(
                        "strop: replace-in-place aimed at a picture that is \
                         no longer selected; dropped (nothing changed)"
                    );
                    return;
                }
                let Some(store) = &editor.store else { return };
                let src = store.put_asset(imported.bytes, imported.ext);
                // Same block, caption + alt untouched, ONE undo step (§4;
                // the snapshot path inside replace_image_src) — then the
                // legitimate in-state mutation re-stamps the revision
                // guard through the one funnel (R3).
                editor.doc.replace_image_src(sel.block, src);
                editor.restamp_image_sel(sel.block);
                editor.mark_dirty();
                editor.sync_mutations();
                editor.bump_activity();
                cx.notify();
            })
            .ok();
        })
        .detach();
    }

    /// §7: the drop lands at the GAP between blocks nearest the pointer,
    /// and the caret never moves — the hand aimed the drop; the caret
    /// wasn't involved (the old caret-relative landing is the recorded
    /// Norman gulf-of-evaluation failure). The pointer-targeted landing
    /// is unconditional: it reads the drop's own position (Submit carries
    /// it; `window.mouse_position()` holds it here), never the drag-over
    /// rule, so a platform that withheld Pending still lands right.
    /// Multi-file: each file in order at the same gap. ONE file dropped
    /// onto the selected picture's pixels replaces in place (§4); a
    /// multi-file drop always lands at the gap — spraying N pictures into
    /// one replace slot has no honest meaning (recorded ruling).
    fn on_file_drop(&mut self, paths: &ExternalPaths, window: &mut Window, cx: &mut Context<Self>) {
        self.drop_gap = None;
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse
        }
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return; // the past is read-only
        }
        if self.history_view.is_some() {
            return;
        }
        let position = window.mouse_position();
        if let [path] = paths.paths()
            && let Some(sel) = self.image_sel_live()
            && self.image_pixel_hit(position) == Some(sel.block)
        {
            let path = crate::files::resolve_portal_path(path);
            match std::fs::read(&path) {
                Ok(bytes) => self.replace_selected_image_pixels(sel, bytes, cx),
                Err(e) => eprintln!("strop: cannot read {}: {e}", path.display()),
            }
            return;
        }
        let Some(frame) = self.last_frame.as_ref() else {
            return;
        };
        let p = frame.doc_point(position);
        let Some((gap, _)) = self.drop_gap_at(p) else {
            return;
        };
        let mut files = Vec::new();
        for path in paths.paths() {
            let path = crate::files::resolve_portal_path(path);
            match std::fs::read(&path) {
                Ok(bytes) => files.push(bytes),
                Err(e) => eprintln!("strop: cannot read {}: {e}", path.display()),
            }
        }
        if files.is_empty() {
            return;
        }
        // Anchor the gap as a byte and revision: gap g > 0 means "after
        // block g-1" (its end names the gap). Gap 0 — before the first
        // block — is the one splice `insert_image_block` can't express
        // (None).
        let anchor = (gap > 0).then(|| DropAnchor {
            byte: self.image_block_bounds(gap - 1).1,
            revision: self.doc.revision(),
        });
        cx.spawn(async move |this, cx| {
            let imported = cx
                .background_executor()
                .spawn(async move {
                    files
                        .into_iter()
                        .filter_map(|b| {
                            strop_core::images::import_image(b)
                                .map_err(|e| eprintln!("strop: {e}"))
                                .ok()
                        })
                        .collect::<Vec<_>>()
                })
                .await;
            this.update(cx, |editor: &mut Editor, cx| {
                editor.land_dropped_images(imported, anchor, cx);
            })
            .ok();
        })
        .detach();
    }

    /// The UI-thread half of a §7 drop: stand each picture at the gap, in
    /// order, and leave the caret exactly where it stood — its offsets
    /// shift with the insertion when it sits below the gap (same text
    /// position, never a new one), and NO autoscroll fires: the writer is
    /// looking at the drop, not the caret.
    fn land_dropped_images(
        &mut self,
        imported: Vec<strop_core::images::Imported>,
        anchor: Option<DropAnchor>,
        cx: &mut Context<Self>,
    ) {
        if imported.is_empty() {
            return;
        }
        let Some(store) = &self.store else {
            eprintln!("strop: image dropped, but no document store to keep it in");
            return;
        };
        let srcs: Vec<String> = imported
            .into_iter()
            .map(|i| store.put_asset(i.bytes, i.ext))
            .collect();
        self.mark_dirty();
        let caret = self.selected_range.clone();
        let before_len = self.doc.len_bytes();
        // The drop aimed at a spatial gap. After an intervening edit, the
        // nearest surviving block end is the honest landing: clamp the old
        // byte, then snap to the containing line's text end. With no edit,
        // retain the exact captured byte as before.
        let anchor = resolve_drop_anchor(&self.doc, anchor);
        let mut at = anchor;
        for src in srcs {
            let after = match at {
                Some(a) => self.doc.insert_image_block(a, src),
                None => self.doc.insert_image_block_before_first(src),
            };
            // The next file lands below this one: the new block's own
            // line end names the gap under it. `insert_image_block` opens
            // that following line with its recorded synthesized `\n`.
            at = Some(after.saturating_sub(1));
        }
        let delta = self.doc.len_bytes() - before_len;
        let len = self.doc.len_bytes();
        // A caret byte at the anchor itself is the end of the block ABOVE
        // the gap — it stays; gap 0 has no block above, so everything
        // shifts.
        let shift = |o: usize| shift_drop_caret(o, anchor, delta, len);
        self.selected_range = shift(caret.start)..shift(caret.end);
        self.sync_mutations();
        self.bump_activity();
        cx.notify();
    }

    /// §7's drag-over layer: while an external file drag crosses the
    /// window, park the insertion rule at the gap nearest the pointer.
    /// gpui synthesizes FileDropEvent::Pending into MouseMove with the
    /// paths riding `cx.active_drag` (fork window.rs:4602), which is
    /// exactly what `on_drag_move::<ExternalPaths>` keys on; a platform
    /// that withholds Pending simply never paints the rule — the landing
    /// law in `on_file_drop` does not depend on it.
    fn on_external_drag_move(
        &mut self,
        ev: &DragMoveEvent<ExternalPaths>,
        window: &mut Window,
        cx: &mut Context<Self>,
    ) {
        // gpui's drop dispatch gates on `hitbox.is_hovered`, which reads
        // the input-modality flag — and FileDropEvent never updates it
        // (fork window.rs:4529 maps only KeyDown/MouseDown/MouseMove), so
        // a drop right after TYPING would be silently refused: during a
        // drag the pointer is grabbed and no real MouseMove ever arrives
        // to flip the flag. Nudge it with exactly the event the platform
        // would have sent — deferred, never re-entering dispatch mid-event.
        // Rig-proven (dragenter after ctrl-end); the fork-side modality
        // fix is a named follow-up on the pending fork-push ceremony.
        if window.last_input_was_keyboard() {
            let position = ev.event.position;
            window.defer(cx, move |window, cx| {
                window.dispatch_event(
                    gpui::PlatformInput::MouseMove(MouseMoveEvent {
                        position,
                        pressed_button: None,
                        modifiers: gpui::Modifiers::default(),
                    }),
                    cx,
                );
            });
        }
        if self.history_view.is_some() || self.strip.is_parked() || self.cold_read.is_some() {
            if self.drop_gap.take().is_some() {
                cx.notify();
            }
            return; // surfaces where the drop would be refused show no rule
        }
        // A one-file drop ON the selected pixels replaces in place (§4),
        // so §7's insertion rule would lie about the landing. The paths
        // ride active_drag during Pending; keep the still honest.
        if matches!(ev.drag(cx).paths(), [_])
            && let Some(sel) = self.image_sel_live()
            && self.image_pixel_hit(ev.event.position) == Some(sel.block)
        {
            if self.drop_gap.take().is_some() {
                cx.notify();
            }
            return;
        }
        let Some(frame) = self.last_frame.as_ref() else {
            return;
        };
        let gap = self.drop_gap_at(frame.doc_point(ev.event.position));
        if gap != self.drop_gap {
            self.drop_gap = gap;
            cx.notify();
        }
    }

    /// The gap between blocks nearest a doc-space point, with the
    /// insertion rule's doc-space y (`drop_gap_for_y` owns the math).
    /// None on a stale frame — never trust geometry past the live rope.
    fn drop_gap_at(&self, p: Point<Pixels>) -> Option<(usize, Pixels)> {
        let frame = self.last_frame.as_ref()?;
        let last = frame.paragraphs.last()?;
        if last.range.end > self.doc.len_bytes() {
            return None;
        }
        let rows: Vec<(f32, f32)> = frame
            .paragraphs
            .iter()
            .map(|par| (f32::from(par.top), f32::from(par.height)))
            .collect();
        let (gap, y) = drop_gap_for_y(&rows, f32::from(p.y));
        Some((gap, px(y)))
    }

    fn undo(&mut self, _: &Undo, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return;
        }
        if self.history_view.is_some() {
            return;
        }
        if let Some(cursor_char) = self.doc.undo() {
            if let Some(cursor_char) = cursor_char {
                let cursor = self.doc.char_to_byte(cursor_char);
                self.selected_range = cursor..cursor;
            }
            self.selection_reversed = false;
            self.cursor_affinity_down = false;
            self.goal_x = None;
            self.marked_range = None;
            self.caret_attrs.clear();
            self.sync_mutations();
            self.bump_activity();
            cx.notify();
        }
    }

    fn redo(&mut self, _: &Redo, _: &mut Window, cx: &mut Context<Self>) {
        if self.cr_guard(cx) {
            return; // the reading room refuses with the pulse (F4 belt 2)
        }
        if self.strip.is_parked() {
            self.pulse_strip(cx);
            return;
        }
        if self.history_view.is_some() {
            return;
        }
        if let Some(cursor_char) = self.doc.redo() {
            if let Some(cursor_char) = cursor_char {
                let cursor = self.doc.char_to_byte(cursor_char);
                self.selected_range = cursor..cursor;
            }
            self.selection_reversed = false;
            self.cursor_affinity_down = false;
            self.goal_x = None;
            self.marked_range = None;
            self.caret_attrs.clear();
            self.sync_mutations();
            self.bump_activity();
            cx.notify();
        }
    }

    // -- Scrolling ------------------------------------------------------------

    fn on_scroll_wheel(&mut self, ev: &ScrollWheelEvent, _: &mut Window, cx: &mut Context<Self>) {
        // F6: the wheel is eaten while the reading room is up — BEFORE the
        // deferred-pass flush below (nothing inside the read flushes, F7)
        // and before any scroll. The takeover also stops propagation; this
        // is the second belt.
        if self.cold_read.is_some() {
            return;
        }
        // §0.6 law 1, second line of defense: while a blocking overlay is
        // up, the document never scrolls — even if a wheel event slips
        // past the overlay's own stop_propagation.
        if self.palette_input.is_some() || self.ai_settings.is_some() {
            return;
        }
        // Scrolling may end the typing reveal clock only while the fan is
        // already out. A closed fan continues to park until an explicit open.
        if !self.drafting {
            self.flush_deferred_pass(cx);
        }
        // Exit-fade ghosts are viewport-frozen snapshots: once the text
        // moves under them they'd hang mid-air, so a scroll just drops them.
        self.departing.clear();
        let Some(frame) = self.last_frame.as_ref() else {
            return;
        };
        let delta = ev.delta.pixel_delta(frame.line_height);
        let target = (self.scroll_top - delta.y).clamp(px(0.), frame.max_scroll());
        if target != self.scroll_top {
            self.scroll_top = target;
            // §5's decay table: looking elsewhere abandons both a clicked
            // picture selection and a staged exile before it can complete
            // destructively against furniture now off-screen.
            self.decay_image_sel();
            // The flanks FOLLOW the selection (LAW 1): `flank_layout` recomputes
            // geometry each frame and its off-screen gate hides them when the
            // selection scrolls out of view — so scrolling no longer dismisses.
            cx.notify();
        }
    }

    /// Clicking an off-screen pill ("N above" / "N below") reveals the NEAREST
    /// hidden card in that direction. It reads the SAME `MarginLayout` the pill
    /// counted — one source of truth, so the count and what the click can reach
    /// can never diverge (the bug class that left pills dead, or scrolling to a
    /// door-suppressed non-card). Two reveals, per how the card hid: an anchor
    /// that scrolled off-screen → scroll JUST enough to bring it to the near edge
    /// (one more card into view, never a full page); a card packing pushed out
    /// while its anchor stays on-screen → SELECT it, so the packer's Pass 3
    /// forces it fully into the lane (scrolling can't help — its anchor already
    /// shows). Either way, the pill always does something.
    fn reveal_offscreen(&mut self, below: bool, window: &mut Window, cx: &mut Context<Self>) {
        let Some(frame) = self.last_frame.as_ref() else {
            return;
        };
        let vp_h = f32::from(frame.viewport_height);
        let max_scroll = f32::from(frame.max_scroll());
        let layout = self.margin_cards(true);
        let refs = if below { layout.below } else { layout.above };
        // Nearest in the direction: smallest anchor_y for "below" (closest to the
        // bottom edge), largest for "above" (closest to the top edge).
        let target = if below {
            refs.into_iter().min_by(|a, b| a.anchor_y.total_cmp(&b.anchor_y))
        } else {
            refs.into_iter().max_by(|a, b| a.anchor_y.total_cmp(&b.anchor_y))
        };
        let Some(target) = target else { return };
        if target.anchor_culled {
            let t = px(reveal_scroll(target.anchor_y, vp_h, max_scroll, below));
            if t != self.scroll_top {
                self.scroll_top = t;
                cx.notify();
            }
        } else {
            // Anchor on-screen but packed off: select it so Pass 3 brings the
            // (now active) card fully into the lane next frame.
            self.select_card(target.id, window, cx);
            cx.notify();
        }
    }

    /// Opening must visibly reveal a referent even when every diagnosis anchor
    /// starts outside the viewport. Reuse the edge-pill reveal path so the
    /// nearest anchor lands at the near edge.
    fn reveal_after_open(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let layout = self.margin_cards(true);
        if !layout.cards.is_empty() {
            return;
        }
        let above = layout.above.last().copied();
        let below = layout.below.first().copied();
        let choose_below = match (above, below) {
            (None, Some(_)) => true,
            (Some(_), None) => false,
            (Some(a), Some(b)) => {
                let Some(frame) = self.last_frame.as_ref() else { return };
                let top = f32::from(frame.scroll_top);
                let bottom = top + f32::from(frame.viewport_height);
                (b.anchor_y - bottom).abs() <= (top - a.anchor_y).abs()
            }
            (None, None) => return,
        };
        self.reveal_offscreen(choose_below, window, cx);
    }

    /// One tick of drag-edge autoscroll: while the pointer is held beyond
    /// the viewport edge, keep scrolling (speed ∝ overshoot) and extending.
    fn autoscroll_tick(&mut self, cx: &mut Context<Self>) -> bool {
        if !self.is_selecting {
            self.autoscroll_active = false;
            return false;
        }
        let (Some(frame), Some(pos)) = (self.last_frame.as_ref(), self.drag_point) else {
            return true;
        };
        let bounds = frame.bounds;
        let overshoot = if pos.y < bounds.top() {
            pos.y - bounds.top()
        } else if pos.y > bounds.bottom() {
            pos.y - bounds.bottom()
        } else {
            return true;
        };
        let step = f32::from(overshoot).clamp(-48., 48.) * 0.4;
        self.scroll_top = (self.scroll_top + px(step)).clamp(px(0.), frame.max_scroll());
        self.drag_extend_to(pos, cx);
        cx.notify();
        true
    }

    // -- Mouse ----------------------------------------------------------------

    fn index_for_mouse(&self, position: Point<Pixels>) -> (usize, bool) {
        let Some(frame) = self.last_frame.as_ref() else {
            return (0, false);
        };
        let doc_pt = frame.doc_point(position);
        let (ix, aff) = frame.index_for_point(doc_pt);
        // Stale-frame guard: never hand out offsets beyond the text the frame
        // laid out. While parked that text is the PREVIEW (a past revision that
        // may be longer or shorter than the live doc), so the selection clamps
        // to the preview's length — that's what Copy slices from (Bug B).
        let max = self
            .history_preview
            .as_ref()
            .map_or_else(|| self.doc.len_bytes(), |p| p.text.len());
        let ix = ix.min(max);
        // A click landing ON the seam line maps BY Y (seam-mechanics 3): the
        // row's upper half places the caret at the manuscript end, the lower
        // half at the first scrap — insertion into the seam is impossible by
        // construction. (Live doc only; a preview places no caret.)
        if self.history_preview.is_none()
            && let Some((_, b)) = self.doc.boundary()
            && self.doc.block_of_byte(ix) == b
            && ix == self.doc.rope().line_to_byte(b)
        {
            let down = frame
                .paragraphs
                .get(b)
                .map(|par| doc_pt.y >= par.top + par.height / 2.)
                .unwrap_or(true);
            return (self.snap_off_seam(ix, down), aff);
        }
        (ix, aff)
    }

    /// Footnote click routing (DESIGN §2-footnotes): a point on an in-text
    /// ref resolves to the start of its def's text; a point in a footnote
    /// def's marker gutter (the painted "N.") resolves to just after the
    /// in-text ref. None = not a footnote target, place the caret normally.
    fn footnote_jump_target(&self, position: Point<Pixels>) -> Option<usize> {
        let frame = self.last_frame.as_ref()?;
        let p = frame.doc_point(position);
        let par_ix = frame
            .paragraphs
            .iter()
            .position(|par| p.y >= par.top && p.y < par.top + par.height)?;
        let par = &frame.paragraphs[par_ix];
        // Stale-frame guard (compositor throttling): offsets beyond the
        // live rope never leave this function.
        if par.range.end > self.doc.len_bytes() {
            return None;
        }
        // An image's pixels are not its caption text (§4). This router runs
        // before image_pixel_hit, so refusing the picture band here lets the
        // click reach the picture-selection door below.
        if !footnote_text_band_contains(par.top, par.text_top, p.y) {
            return None;
        }
        let rope = self.doc.rope();
        if p.x < par.indent {
            // The def's marker gutter: jump back to the in-text ref.
            if let Some(BlockKind::FootnoteDef { id }) = self.doc.blocks().kinds().get(par_ix) {
                let span = self
                    .doc
                    .spans()
                    .spans()
                    .iter()
                    .filter(|s| matches!(&s.attr, InlineAttr::FootnoteRef(d) if d == id))
                    .min_by_key(|s| s.range.start)?;
                return Some(rope.char_to_byte(span.range.end));
            }
            return None;
        }
        // A ref's carrier: jump forward to the def. Hit-test the span's
        // glyph band — a caret landing *next to* the ref must not teleport.
        let line_ix = (((p.y - par.top - par.text_top).max(px(0.)) / par.line_height) as usize)
            .min(par.line_count() - 1);
        for s in self.doc.spans().spans() {
            let InlineAttr::FootnoteRef(id) = &s.attr else {
                continue;
            };
            let (bs, be) = (
                rope.char_to_byte(s.range.start),
                rope.char_to_byte(s.range.end),
            );
            if bs < par.range.start || be > par.range.end {
                continue;
            }
            let line = par.line_of(bs - par.range.start, true);
            if line != line_ix {
                continue;
            }
            let x0 = par.x_for(bs - par.range.start, line);
            let x1 = par.x_for(be - par.range.start, line);
            if p.x < x0 || p.x >= x1 {
                continue;
            }
            let def = self
                .doc
                .blocks()
                .kinds()
                .iter()
                .position(|k| matches!(k, BlockKind::FootnoteDef { id: d } if d == id))?;
            // The def line's start — the painted "N." lives in the gutter,
            // so this IS "after the marker".
            return Some(rope.line_to_byte(def));
        }
        None
    }

    /// Extend the drag selection toward a window point, clamped to the
    /// viewport so dragging past an edge selects to the edge (the autoscroll
    /// tick brings the rest into reach).
    fn drag_extend_to(&mut self, pos: Point<Pixels>, cx: &mut Context<Self>) {
        let Some(frame) = self.last_frame.as_ref() else {
            return;
        };
        let bounds = frame.bounds;
        let clamped = point(
            pos.x,
            pos.y.clamp(bounds.top(), bounds.bottom() - px(1.)),
        );
        // Use the *current* scroll offset, which the autoscroll tick may have
        // moved past the painted frame's.
        let doc =
            clamped - bounds.origin + point(px(0.), self.scroll_top);
        let (ix, affinity) = frame.index_for_point(doc);
        match self.select_granularity {
            SelectGranularity::Char => self.extend_cursor(ix, affinity, cx),
            _ => self.extend_by_unit(ix, cx),
        }
    }

    /// The selection unit at `offset` for the current drag granularity.
    fn unit_at(&self, offset: usize) -> Range<usize> {
        match self.select_granularity {
            SelectGranularity::Char => offset..offset,
            SelectGranularity::Word => self.word_range_at(offset),
            SelectGranularity::Paragraph => {
                let (start, end) = self.paragraph_bounds(offset);
                start..end
            }
        }
    }

    /// Union the unit under the pointer with the origin unit (GTK/Word
    /// drag-by-word/paragraph behavior).
    fn extend_by_unit(&mut self, offset: usize, cx: &mut Context<Self>) {
        let Some(origin) = self.selection_origin.clone() else {
            return;
        };
        let unit = self.unit_at(offset);
        self.selection_reversed = unit.start < origin.start;
        self.selected_range = origin.start.min(unit.start)..origin.end.max(unit.end);
        self.cursor_affinity_down = false;
        self.bump_activity();
        self.publish_primary(cx);
        cx.notify();
    }

    /// DESIGN §0.6 law 3: any mouse-down outside a light-dismiss layer
    /// (palette, shortcuts, selection popover) closes it. Registered on
    /// the window root — the layers themselves stop propagation, so only
    /// genuinely-outside clicks arrive here.
    fn light_dismiss(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        if self.strip_name_input.is_some() {
            self.resolve_strip_name(window, cx);
        }
        // LAW 2 / C4 — no dead zones ANYWHERE: the margin lane, the titlebar
        // blank and the gutters all live OUTSIDE the editor column's hitbox,
        // so the column's own `on_mouse_down` (which resolves fields for
        // prose clicks) never fires out there — the report-1 bug: a click
        // right beside a composing card closed nothing. The root handler is
        // the one listener every unclaimed click reaches, so the field family
        // resolves HERE with the dead-zone exit: commit (an empty composer
        // discards) and restore the caret saved at open. A prose click
        // already resolved everything in the column handler, and every
        // field's own chrome stops propagation — both paths make this a
        // no-op, never a double-commit.
        let composer_return = self.composer_return.clone();
        if self.commit_or_discard_composer(window, cx) {
            self.apply_composer_return(composer_return, cx);
        }
        self.commit_transient_fields_on_gesture(cx);
        if self.palette_input.is_some() {
            self.close_palette(window, cx);
        }
        // A click outside the flank commits its open link argument-field before
        // the popover itself is dismissed, so the URL lands (spec §0.1).
        if let Some(url) = self.link_input.as_ref().map(|(_, f)| f.read(cx).content.clone()) {
            self.commit_link(url, window, cx);
        }
        // A light-dismiss click is a gesture on chrome outside the flank; latch
        // the offer down (LAW 1) — a later selection change lifts the latch.
        if self.flank_risen && !self.flank_latched {
            self.flank_latched = true;
            cx.notify();
        }
        if self.narrow_notes_open {
            self.narrow_notes_open = false;
            cx.notify();
        }
        if self.editor_menu_open {
            self.editor_menu_open = false;
            cx.notify();
        }
    }

    fn on_mouse_down(&mut self, ev: &MouseDownEvent, window: &mut Window, cx: &mut Context<Self>) {
        // A live link argument-field commits like every other single-line field
        // when the writer clicks away into the document (spec §0.1). Done up
        // front so even the early-return paths below (lane click, footnote jump)
        // don't strand it; the flank's own chrome stops propagation, so a click
        // that reaches here is genuinely outside it.
        if let Some(url) = self.link_input.as_ref().map(|(_, f)| f.read(cx).content.clone()) {
            self.commit_link(url, window, cx);
        }
        // LAW 2 / C4 — no dead zones: a mouse-down is a GESTURE, so it resolves
        // any open transient field at once (never waiting on a blur the dead-zone
        // click would never deliver). Capture the saved caret first: a dead-zone
        // landing restores it (land where thought left off); a prose landing
        // overrides it with the caret at the click point. Empty ⇒ discard.
        let composer_return = self.composer_return.clone();
        let resolved_composer = self.commit_or_discard_composer(window, cx);
        self.commit_transient_fields_on_gesture(cx);
        // A click in the right note lane is NOT a document click — the lane's
        // own cards and pills handle it. The lane is a sibling element painted
        // over this (full-width) column, so a card/pill's stop_propagation
        // doesn't reach this handler; without this guard, clicking any margin
        // card or off-screen pill also jumped the text caret.
        if f32::from(ev.position.x) > self.column_right(window) + MARGIN_GAP {
            // A true dead zone (the margin blank): the click resolved the field;
            // restore the saved caret so the exit lands where thought left off.
            if resolved_composer {
                self.apply_composer_return(composer_return, cx);
            }
            // Click elsewhere is plain decay (inline-images §4) even when
            // the click never becomes a caret.
            if self.image_sel.is_some() {
                self.decay_image_sel();
                cx.notify();
            }
            return;
        }
        // A click in the graveyard tail section (Bug B). The section is painted
        // inside this element, so its verbs' hit rects (doc-space) are tested
        // here. It is a read-only RECORD: a click anywhere in it dispatches a
        // verb if one is hit and is otherwise swallowed — never a manuscript
        // caret (the normal logic would snap it to the last paragraph).
        if ev.click_count == 1
            && self.history_view.is_none()
            && self
                .last_frame
                .as_ref()
                // No slop band above the header (retuned, seam-mechanics 9):
                // after the flip the LAST SCRAP's final line abuts the slab
                // directly, and a 22px band stole its clicks.
                .and_then(|f| f.grave_section_top.map(|t| f.doc_point(ev.position).y >= t))
                .unwrap_or(false)
        {
            cx.stop_propagation();
            // A record click is a click elsewhere: plain decay (§4).
            if self.image_sel.is_some() {
                self.decay_image_sel();
                cx.notify();
            }
            if let Some(action) = self.grave_action_at(ev.position) {
                match action {
                    GraveAction::ShowOrigin(id) => self.show_grave_origin(id, cx),
                    GraveAction::PutBack(id) => self.put_back_entry(id, cx),
                    GraveAction::Delete(id) => self.delete_grave_entry(id, cx),
                    GraveAction::Expand(id) => self.toggle_grave_entry(id, cx),
                }
            }
            return;
        }
        // Footnote jumps (DESIGN §2-footnotes): a plain click on a ref's
        // mark goes to its def; a click on a def's "N." gutter goes back
        // to the ref. Never starts a drag selection.
        if ev.click_count == 1
            && !ev.modifiers.shift
            && self.history_view.is_none()
            && let Some(target) = self.footnote_jump_target(ev.position)
        {
            self.goal_x = None;
            self.set_cursor(target, false, cx); // collapses → LAW 1 lowers the flanks
            return;
        }
        // Click on the pixels selects the picture whole (inline-images §4),
        // claimed BEFORE the caret funnel — index_for_point resolves these
        // very pixels to caption line 0 (the Phase-3 note), which would
        // plant a caret instead. Click-born: no door caret. Shift-click
        // stays a range gesture (§5's range door wants the sweep), and
        // double/triple clicks fall through — the alt editor on
        // click_count == 2 keeps working and now coexists with
        // single-click selection. No drag begins: furniture doesn't sweep.
        if ev.click_count == 1
            && !ev.modifiers.shift
            && self.history_view.is_none()
            && let Some(block) = self.image_pixel_hit(ev.position)
        {
            self.enter_image_sel(block, None, None, cx);
            return;
        }
        self.goal_x = None;
        self.is_selecting = true;
        // The click's own set_cursor/extend below feeds LAW 1 (`on_selection_moved`);
        // and `is_selecting` keeps the flanks down for the whole drag regardless.
        self.drag_point = Some(ev.position);
        if !self.autoscroll_active {
            self.autoscroll_active = true;
            cx.spawn(async move |this, cx| {
                loop {
                    cx.background_executor()
                        .timer(Duration::from_millis(50))
                        .await;
                    let go_on = this
                        .update(cx, |editor: &mut Editor, cx| editor.autoscroll_tick(cx))
                        .unwrap_or(false);
                    if !go_on {
                        break;
                    }
                }
            })
            .detach();
        }
        let (ix, affinity) = self.index_for_mouse(ev.position);
        match ev.click_count {
            1 => {
                self.select_granularity = SelectGranularity::Char;
                if ev.modifiers.shift {
                    self.selection_origin = None;
                    self.extend_cursor(ix, affinity, cx);
                } else {
                    self.selection_origin = Some(ix..ix);
                    self.set_cursor(ix, affinity, cx);
                }
                // Bidirectional activation: clicking inside an anchor activates
                // its margin card. The click snaps to the nearest caret boundary,
                // so a click on the trailing half of an anchor's last glyph lands
                // at `c == end` — still on the visible mark; `note_at_char`
                // accepts that trailing boundary (without double-claiming when
                // another anchor starts there), so the whole highlight is live.
                let c = self.doc.rope().byte_to_char(ix.min(self.doc.len_bytes()));
                let ranges: Vec<(u64, usize, usize)> = self
                    .doc
                    .notes()
                    .open()
                    .map(|n| (n.id, n.range.start, n.range.end))
                    .collect();
                let hit_id = note_at_char(&ranges, c);
                // Reaching for a diagnosis is a glance, not a stance change.
                // The selected-card exemption paints it without opening the
                // rest of the fan or landing a parked pass.
                // Clicking the text selects the hit card (or clears selection);
                // either way it commits and closes any composer first, so a
                // click into the document never strands an open note editor.
                match hit_id {
                    Some(id) => self.select_card(id, window, cx),
                    None => self.deselect_card(window, cx),
                }
            }
            2 => {
                // Double-click on an image block edits its alt text. The
                // gesture is CLAIMED: without the stop it would bubble on to
                // the root's no-dead-zones resolver (C4) and commit the very
                // field it just opened.
                let block = self.doc.block_of_byte(ix.min(self.doc.len_bytes()));
                if matches!(self.doc.blocks().kind(block), BlockKind::Image { .. }) {
                    cx.stop_propagation();
                    self.edit_image_alt(block, window, cx);
                    return;
                }
                self.select_granularity = SelectGranularity::Word;
                self.selection_origin = Some(self.word_range_at(ix));
                self.extend_by_unit(ix, cx);
            }
            _ => {
                self.select_granularity = SelectGranularity::Paragraph;
                let (start, end) = self.paragraph_bounds(ix);
                self.selection_origin = Some(start..end);
                self.extend_by_unit(ix, cx);
            }
        }
    }

    fn on_middle_click(&mut self, ev: &MouseDownEvent, _: &mut Window, cx: &mut Context<Self>) {
        // freedesktop PRIMARY contract: middle button pastes the primary
        // selection (never the clipboard) at the click position. PRIMARY is
        // X11/Wayland-only (gpui exposes read_from_primary on Linux/BSD); on
        // macOS/Windows middle-click carries no paste, so this is a no-op.
        #[cfg(any(target_os = "linux", target_os = "freebsd"))]
        {
            let Some(text) = cx.read_from_primary().and_then(|item| item.text()) else {
                return;
            };
            let (ix, _) = self.index_for_mouse(ev.position);
            // A middle-click is a click elsewhere: plain decay (§4), BEFORE
            // the caret lands — with the state left live, apply_replace's
            // §4 typing gate re-aimed the paste at the caption's end / the
            // door caret instead of the click point ("dropped, never
            // re-aimed", §5).
            if self.image_sel.is_some() {
                self.decay_image_sel();
            }
            self.selected_range = ix..ix;
            self.selection_reversed = false;
            let text = text.replace("\r\n", "\n");
            // PRIMARY is text-only, but a Strop image-spanning selection
            // published its Markdown form (§9) — the same rebuild law as
            // ctrl-v applies, so the two paste doors agree; anything that
            // doesn't resolve stays literal visible text as ever.
            if text.contains("![") {
                let images = image_lines_in(&text, &|src| {
                    self.store.as_ref().is_some_and(|s| s.has_asset(src))
                });
                if !images.is_empty() && self.paste_rebuild_lines(&text, images, cx) {
                    return;
                }
            }
            self.apply_replace(None, &text, false, true, cx);
        }
        #[cfg(not(any(target_os = "linux", target_os = "freebsd")))]
        let _ = (ev, cx);
    }

    fn on_mouse_up(&mut self, _: &MouseUpEvent, _: &mut Window, cx: &mut Context<Self>) {
        // The release ends the drag; LAW 1's settle beat now runs from HERE (the
        // last extension), the same 250 ms a keyboard selection waits — no
        // mouse-up-only flag any more. `arm_flank_settle` gates the first rise;
        // once risen, further extension never lowers.
        let settled_selection = self.is_selecting && !self.selected_range.is_empty();
        self.is_selecting = false;
        self.drag_point = None;
        if settled_selection && !self.flank_risen && !self.flank_latched {
            self.arm_flank_settle(cx);
        }
    }

    fn on_mouse_move(&mut self, ev: &MouseMoveEvent, _: &mut Window, cx: &mut Context<Self>) {
        // A drag that left the window (FileDropEvent::Exited) never tells
        // the view — the first ordinary move sweeps the stale §7 rule.
        // One is_some + one App read; prose motion pays nothing more.
        if self.drop_gap.is_some() && !cx.has_active_drag() {
            self.drop_gap = None;
            cx.notify();
        }
        if !self.is_selecting {
            return;
        }
        self.drag_point = Some(ev.position);
        self.drag_extend_to(ev.position, cx);
    }

    /// Footnote click targets for the smoke harness, in window coordinates:
    /// every in-text ref mark, every def-marker gutter, every zone row's
    /// text origin (marker sits 24px left of it).
    pub fn debug_footnotes(&self) -> String {
        let Some(frame) = self.last_frame.as_ref() else {
            return "no-frame".into();
        };
        let rope = self.doc.rope();
        let origin = frame.bounds.origin;
        let mut out = String::new();
        for s in self.doc.spans().spans() {
            let InlineAttr::FootnoteRef(id) = &s.attr else {
                continue;
            };
            let (bs, be) = (
                rope.char_to_byte(s.range.start),
                rope.char_to_byte(s.range.end),
            );
            let Some(par) = frame
                .paragraphs
                .iter()
                .find(|p| p.range.start <= bs && be <= p.range.end)
            else {
                continue;
            };
            let line = par.line_of(bs - par.range.start, true);
            let x0 = par.x_for(bs - par.range.start, line);
            let x1 = par.x_for(be - par.range.start, line);
            let y = par.top + par.text_top + par.line_height * (line as f32)
                + par.line_height / 2.
                - frame.scroll_top;
            out += &format!(
                "ref {id} @{:.0},{:.0}\n",
                f32::from(origin.x + (x0 + x1) / 2.),
                f32::from(origin.y + y)
            );
        }
        for (ix, kind) in self.doc.blocks().kinds().iter().enumerate() {
            let BlockKind::FootnoteDef { id } = kind else {
                continue;
            };
            let Some(par) = frame.paragraphs.get(ix) else {
                continue;
            };
            let y = par.top + par.line_height / 2. - frame.scroll_top;
            out += &format!(
                "def {id} @{:.0},{:.0}\n",
                f32::from(origin.x + par.indent / 2.),
                f32::from(origin.y + y)
            );
        }
        let bounds_map = self.zone_row_bounds.borrow();
        let mut rows: Vec<_> = bounds_map.iter().collect();
        rows.sort_by_key(|(ix, _)| **ix);
        for (ix, b) in rows {
            out += &format!(
                "zone {ix} @{:.0},{:.0} w={:.0}\n",
                f32::from(b.origin.x),
                f32::from(b.center().y),
                f32::from(b.size.width)
            );
        }
        out
    }

    /// One-line JSON snapshot of the layer stack for the smoke harness
    /// (H1, `dump:ui`). Overlays list topmost first — the §0.6 Esc order.
    pub fn debug_ui_dump(&self, window: &Window, cx: &App) -> String {
        let mut overlays: Vec<&str> = Vec::new();
        if self.ai_settings.is_some() {
            overlays.push("ai_settings");
        }
        if self.palette_input.is_some() {
            overlays.push("palette");
        }
        // Key on the RENDER gate, not the bare predicate (V9b): a settled
        // selection scrolled off-screen passes `flanks_visible` but paints
        // nothing, so `flank_layout` (which folds in the geometry) is the honest
        // signal — matching what `render_selection_popover` actually draws.
        if self.flank_layout(window).is_some() {
            overlays.push("popover");
        }
        if self.replace_input.is_some() {
            overlays.push("replace");
        }
        if self.history_view.is_some() {
            overlays.push("history");
        }
        if self.strip.open {
            overlays.push("strip");
        }
        // Every live single-line field, so "focused" can name its context.
        let mut fields: Vec<Entity<TextField>> = Vec::new();
        if let Some(panel) = &self.ai_settings {
            fields.extend([
                panel.base_url.clone(),
                panel.api_key.clone(),
                panel.model.clone(),
            ]);
        }
        fields.extend(self.palette_input.clone());
        fields.extend(self.replace_input.clone());
        fields.extend(self.doc_rename_input.clone());
        fields.extend(self.focus.input().cloned());
        fields.extend(self.rename_input.as_ref().map(|(_, i)| i.clone()));
        fields.extend(self.alt_input.as_ref().map(|(_, i)| i.clone()));
        fields.extend(self.link_input.as_ref().map(|(_, i)| i.clone()));
        fields.extend(self.goal_input.clone());
        fields.extend(self.cold_read.as_ref().and_then(|cr| cr.input.clone()));
        let focused_field = fields
            .iter()
            .find(|f| f.read(cx).focus_handle.is_focused(window));
        let focused = focused_field.map_or_else(
            || {
                // The reading room's desk holds its own focus (F8's rig bit).
                if self
                    .cold_read
                    .as_ref()
                    .is_some_and(|cr| cr.focus_handle.is_focused(window))
                {
                    "ColdRead"
                } else {
                    "Editor"
                }
            },
            |f| f.read(cx).debug_caret().0,
        );
        let focused_input_text = focused_field.map(|f| f.read(cx).content.clone());
        // The focused field's caret + selection as CHAR indices, so the smoke
        // rig can assert mouse/keyboard selection behavior (not just eyeball it).
        let (field_cursor, field_sel) = focused_field
            .map(|f| {
                let (_, cursor, sel) = f.read(cx).debug_caret();
                (Some(cursor), Some(sel))
            })
            .unwrap_or((None, None));
        let doc_hash = {
            use std::hash::{Hash, Hasher};
            let mut hasher = std::collections::hash_map::DefaultHasher::new();
            self.doc.text().hash(&mut hasher);
            format!("{:016x}", hasher.finish())
        };
        // Margin layout, so the rig can assert the invariants the proptests cover
        // only in the pure layer — at the integration level, against a real frame:
        // no two VISIBLE cards overlap (the never-overlap rule); a selected card
        // is actually in the visible set (the displacement fix); and the pill
        // counts are what the lane reports. `null` when there is no frame yet.
        // Scraps latch/chip/count bits, hoisted out of the json! call below
        // (the macro's recursion budget is finite and the dump is large).
        let latched = self.excursion.is_some();
        let caret_scraps = self.caret_in_scraps();
        let scraps_words = self.scraps_word_count();
        let scraps_chip_exists = matches!(
            self.doc.boundary(),
            Some((strop_core::document::BoundaryEra::Tail, _))
        );
        let scraps_chip_hidden = self.scraps_region_on_screen();
        let chip_pulse = self.chip_pulse.is_some();
        let count_label = self.count_label();
        let prov_visible = self
            .prov_rest
            .is_some_and(|(_, since)| since.elapsed() >= PROV_REST_DELAY);
        let park_ghost = self.park_ghost.is_some();
        // The reading room, hoisted into a `let` like `margin` (the json!
        // macro's recursion budget is finite and the dump is large).
        let coldread = self.cold_read.as_ref().map(|cr| {
            let page_hyphens = cr
                .book
                .pages
                .get(cr.page)
                .map(|p| {
                    p.items
                        .iter()
                        .filter(|i| {
                            matches!(i, crate::bookpage::PageItem::Line(l) if l.ends_hyphen)
                        })
                        .count()
                })
                .unwrap_or(0);
            let lane = self
                .doc
                .notes()
                .notes()
                .iter()
                .filter(|n| n.status == NoteStatus::Open && cr.reactions.contains(&n.id))
                .count();
            let last_body = cr.reactions.last().and_then(|id| {
                self.doc.notes().notes().iter().find(|n| n.id == *id).map(|n| n.body.clone())
            });
            let p1: String = cr.text.chars().take(24).collect();
            serde_json::json!({
                "open": true,
                "pages": cr.book.pages.len(),
                "page": cr.page,
                "source": match &cr.source {
                    ColdReadSource::Live => "live",
                    ColdReadSource::Past { .. } => "past",
                },
                "pulse": cr.pulse.is_some_and(|t| {
                    t.elapsed() < Duration::from_millis(STRIP_PULSE_MS)
                }),
                "words": cr.words,
                "lane": lane,
                "last_body": last_body,
                "sel": cr.selection.as_ref().map(|s| [s.start, s.end]),
                "input": cr.input.is_some(),
                "hyphens": page_hyphens,
                "p1": p1,
                // "The most recent flip entered WITH a fade" — stable
                // against the rig racing the 120ms window; reduce_motion
                // and rapid flips never set flip_at at all.
                "fading": cr.flip_at.is_some(),
                "lane_shown": cr.geom.lane,
            })
        });
        let checkpoints = self.store.as_ref().map_or(0, |s| s.checkpoints().len());
        let margin = self.last_frame.as_ref().map(|_| {
            let layout = self.margin_cards(true);
            let mut spans: Vec<(f32, f32)> =
                layout.cards.iter().map(|c| (c.top, c.height)).collect();
            spans.sort_by(|a, b| a.0.total_cmp(&b.0));
            let overlap = spans.windows(2).any(|w| w[0].0 + w[0].1 > w[1].0 + 0.5);
            serde_json::json!({
                "visible": layout.cards.len(),
                "above": layout.above.len(),
                "below": layout.below.len(),
                "overlap": overlap,
                "has_active": self.focus.active_id().is_some(),
                "active_visible": layout.cards.iter().any(|c| c.active),
                "min_top": layout.cards.iter().map(|c| c.top)
                    .min_by(|a, b| a.total_cmp(b)),
                "floor": self.margin_card_floor(),
                // Receded one-line cards (over the full-size budget) — visible
                // counts them too: they are IN the lane, just smaller.
                "collapsed": layout.cards.iter().filter(|c| c.collapsed).count(),
            })
        });
        serde_json::json!({
            "overlays": overlays,
            "focused": focused,
            "scroll_y": f32::from(self.scroll_top),
            "doc_chars": self.doc.rope().len_chars(),
            "doc_hash": doc_hash,
            "focused_input_text": focused_input_text,
            "field_cursor": field_cursor,
            "field_sel": field_sel,
            "margin": margin,
            // The omnibox results list (palette-scroll): `selected` is the
            // highlighted row, `rows` the list length, `scroll_y`/`max_scroll_y`
            // the list's own scroll (not the document's) — the rig asserts
            // keyboard nav past the fold actually moves this, and that mouse
            // wheel still does too. `null` when the omnibox is closed.
            "omni": self.palette_input.as_ref().map(|_| {
                // The find split (scopes-search 2): the announced
                // "N in the piece · M in scraps" halves, as data.
                let (piece, scraps, capped) = self.find_split(&self.omni_match_ranges());
                serde_json::json!({
                    "selected": self.palette_selected,
                    "rows": self.omni_rows(&self.palette_query).len(),
                    "scroll_y": f32::from(self.omni_scroll.offset().y),
                    "max_scroll_y": f32::from(self.omni_scroll.max_offset().y),
                    "find_piece": piece,
                    "find_scraps": scraps,
                    "find_capped": capped,
                })
            }),
            // A completed pass parked behind the reveal clock (mid-burst
            // arrival) — the rig asserts park-then-land timing against this.
            "ai_deferred": self.deferred_pass.is_some(),
            // Cards still inside their entrance fade — the rig asserts the
            // fade lifecycle (marked at landing, cleared right after).
            "appearing": self.appearing.len(),
            // Exit-fade ghosts of just-resolved cards (same lifecycle checks).
            "departing": self.departing.len(),
            // Re-pack slides in flight — the rig asserts a resolve in a
            // crowded lane MOVES the survivors (then settles), and that a
            // scroll clears all motion instantly. `moves_started` is the
            // session-monotonic total, immune to the dump racing the 200ms
            // flight on a cold launch.
            "moving": self.moving.len(),
            "moves_started": self.moves_started,
            "reduce_motion": self.config.reduce_motion,
            // The editor button's face + the state it's a priority over, so the
            // rig can assert the transitions (seed:deliver → cooking → ready →
            // reading) and the door law (open menu while drafting rests cards).
            "editor_btn": {
                "face": self.editor_face().token(),
                "open": !self.drafting,
                "cooking": matches!(self.ai_status, Some(AiStatus::Running { .. })),
                "ready": self.deferred_pass.is_some(),
                "empty_unack": self.ai_empty_result.as_ref()
                    .is_some_and(|result| result.unacknowledged),
                "last_result": self.ai_empty_result.as_ref()
                    .map(|result| format!("{}/0", result.kind.mode_str())),
                "menu_cancel": self.editor_menu_open
                    && matches!(self.ai_status, Some(AiStatus::Running { .. })),
                "recovery": self.ai_recovery_visible(),
                "margin_floor": self.margin_floor(),
                "open_count": self.open_query_count(),
            },
            // The history strip (P1). `bakes` is session-monotonic — the
            // stability-law assertion: scrubbing must NEVER bump it (only open
            // and Restore do). Everything else is scrub state the rig checks.
            "strip": self.strip.bake.as_ref().map(|b| serde_json::json!({
                "open": self.strip.open,
                "pos_ms": self.strip.pos_ms,
                "parked": self.strip.parked,
                "runs": self.doc.journal().runs.len(),
                "events": self.doc.journal().events.len(),
                "stations": b.stations.len(),
                "threads": b.threads.len(),
                "thread_pts": b.threads.iter().flat_map(|thread| &thread.segments)
                    .map(Vec::len).sum::<usize>(),
                "diamonds": b.threads.iter().filter(|thread| thread.uncertain_start).count(),
                "past_cards": if self.strip.parked { self.strip.past_margin().len() } else { 0 },
                "station_hits": self.strip_station_hits.borrow().len(),
                "blue_oar_ms": b.stations.iter().find(|s| s.label == "Blue oar")
                    .map(|s| s.at_ms),
                "labels": b.stations.iter().filter(|s| s.show)
                    .map(|s| s.label.clone()).collect::<Vec<_>>(),
                "well_durations": b.well_data.iter()
                    .map(|w| w.label.clone()).collect::<Vec<_>>(),
                "saved_scroll": self.strip.saved_scroll,
                "live_scroll": f32::from(self.scroll_top),
                "max_scroll": self.last_frame.as_ref().map(|f| f32::from(f.max_scroll())),
                "focused_past_card": self.past_card_focus.map(|(id, _)| id),
                "past_card_y": self.strip.parked.then(|| {
                    let frame = self.last_frame.as_ref()?;
                    let preview = self.history_preview.as_ref()?;
                    let card = self.past_cards_at(self.strip.pos_ms).into_iter()
                        .find(|c| c.anchor.is_some())?;
                    let rope = ropey::Rope::from_str(&preview.text);
                    let byte = rope.char_to_byte(card.anchor?.start.min(rope.len_chars()));
                    frame.position_of(byte, false)
                        .map(|p| f32::from(p.y - frame.scroll_top))
                }).flatten(),
                "compare_a_offset": -f32::from(self.compare_scroll_a.offset().y),
                "compare_b_offset": -f32::from(self.compare_scroll_b.offset().y),
                "compare_a_max": f32::from(self.compare_scroll_a.max_offset().y),
                "compare_b_max": f32::from(self.compare_scroll_b.max_offset().y),
                "gutter_regions": self.compare_alignment.borrow().as_ref()
                    .map_or(0, |(_, _, marks)| marks.len()),
                // Coverage witnesses: marks must single out paragraphs, not
                // wash the column — the rig asserts marked_b < b_paras (a
                // quiet middle survives the diff).
                "gutter_marked_b": self.compare_alignment.borrow().as_ref()
                    .map_or(0, |(_, _, marks)| marks.iter()
                        .filter(|m| m.new_par.is_some()).count()),
                "gutter_b_paras": self.history_preview.as_ref()
                    .map(|p| p.text.split('\n').count()),
                "past_stamps": self.past_stamps.get(),
                "words_at": self.strip.words_at,
                "bakes": self.strip.bakes,
                // Axis width in working px — non-zero even for a LEGACY era
                // (checkpoints only), the merged-axis assertion (Bug A).
                "work": b.timeline.total_work,
                // The parked banner is up (mode indicator) and, when a refused
                // edit is mid-flash, the pulse is live — both MODEL bits (Bug B).
                "banner": self.strip.parked,
                "pulse": self.strip_pulse.is_some(),
            })),
            // What is ON GLASS, not what the document holds: the painted
            // frame's paragraph count. The stale-preview regression
            // (2026-07-16, field report) had a closed strip keep painting
            // the past — the reuse cache lacked preview identity, so the
            // preview frame answered for the live key. The rig asserts the
            // count round-trips across park → close.
            "frame_paras": self.last_frame.as_ref().map(|f| f.paragraphs.len()),
            // Floor-law witnesses: at max scroll the clearance below the
            // painted content is line_h (breathing) + 24 (the floor's own
            // clearance); the rig asserts floor_gap - line_h >= 24, which
            // dies with the `+ px(24.)` in TextFrame::max_scroll.
            "floor_gap": self.last_frame.as_ref().map(|f|
                f32::from(f.viewport_height - f.content_height + f.scroll_top)),
            "line_h": self.last_frame.as_ref().map(|f| f32::from(f.line_height)),
            // Presentation gate: the margin lane + rail render only when no
            // history surface is previewing (review H36) and the reading
            // room is down — the model above is ungated, so the rig asserts
            // THIS bit for hide/show.
            "margin_hidden": self.history_view.is_some() || self.strip.is_parked()
                || self.cold_read.is_some(),
            // The reading room (impl 05 Wave B) + the checkpoint census the
            // entry/exit round-trip asserts against.
            "coldread": coldread,
            "checkpoints": checkpoints,
            // Scraps: the pile's block count (0 = no seam; era-aware — the
            // key keeps its name so rig assertions carry), the seam's block
            // index, the graveyard entry count, and the MANUSCRIPT-only word
            // count (the pile excluded — one scope law).
            "compost_blocks": match self.doc.boundary() {
                Some((strop_core::document::BoundaryEra::Tail, b)) =>
                    self.doc.blocks().len().saturating_sub(b + 1),
                Some((strop_core::document::BoundaryEra::Top, b)) => b,
                None => 0,
            },
            "seam": self.doc.scrap_line(),
            "grave_entries": self.doc.graveyard().len(),
            // Arrival/exile blinks (one-shot), and the open-card census so the
            // rig can watch a dangling note migrate (writer notes drop, the
            // compost gains an item) or a dead diagnosis close (Bug C).
            "compost_flash": self.arrival_flash.is_some(),
            "grave_flash": self.grave_flash.is_some(),
            "open_notes": self.doc.notes().open().filter(|n| n.kind == NoteKind::Note).count(),
            "open_diagnoses": self.doc.notes().open().filter(|n| n.kind == NoteKind::Diagnosis).count(),
            // Presentation gate: the sticky footer bar "unsticks into the section
            // header" once the tail section is on screen (asides.md §3) — the rig
            // asserts THIS bit for the bar's hide/show, like `margin_hidden`.
            "grave_bar_hidden": self.grave_tail_on_screen(),
            "manuscript_words": self.manuscript_word_count(),
            // The excursion latch + both-ends memory (scopes-search 1), the
            // caret's region, the footer chips' existence/hide bits, and the
            // caret-scoped count label — the rig's latch/chip assertions
            // read these (hoisted above: the json! macro has a depth budget).
            "latched": latched,
            "pile_end": self.pile_end,
            "caret_scraps": caret_scraps,
            "scraps_words": scraps_words,
            "scraps_chip_exists": scraps_chip_exists,
            "scraps_chip_hidden": scraps_chip_hidden,
            "chip_pulse": chip_pulse,
            "count_label": count_label,
            "prov_visible": prov_visible,
            "park_ghost": park_ghost,
            "sel": [self.selected_range.start, self.selected_range.end],
            // The selection flanks (docs/impl/03-flanks.md §3): presence of each
            // (`left` false only under a history surface; `right` false for a
            // compost-rail selection or a narrow lane) and the lane `y` the right
            // menu pins to. `null` when there's no live selection to flank.
            "flanks": self.flank_layout(window).map(|l| serde_json::json!({
                "left": !matches!(l.gate.left, FlankLeft::None),
                "right": l.gate.right,
                "link": self.link_input.is_some(),
                "y": l.right_top,
            })),
        })
        .to_string()
    }

    /// Cursor geometry for the smoke harness: byte offset, paragraph index,
    /// wrapped-line index within the paragraph, and x position.
    /// Rig-only: inject a dense cluster of demo diagnosis cards so the visual
    /// rig can exercise the margin lane (overlap packing, z-order, active-pin)
    /// without a live AI pass. Quotes are written to match the seed fixture's
    /// text; the middle card is activated. Driven by the `seed:diag` smoke
    /// token — never reached outside a STROP_SMOKE run.
    pub fn debug_seed_notes(&mut self, cx: &mut Context<Self>) {
        use strop_core::diagnose::to_annotations;
        let anns =
            to_annotations(&self.doc.text(), Self::demo_diagnoses(), self.doc.notes(), 0, 0);
        self.doc.add_diagnoses(anns);
        self.drafting = false; // reviewing: the editor's cards are shown
        if let Some(n) = self.doc.notes().open().nth(2) {
            self.focus = CardFocus::Selected(n.id);
        }
        self.mark_dirty();
        cx.notify();
    }

    /// The four demo diagnoses the rig seeds deliver (anchored to the
    /// tutorial/fixture quotes) — shared so every seed path flags the same
    /// passages.
    fn demo_diagnoses() -> Vec<strop_core::diagnose::Diagnosis> {
        use strop_core::diagnose::Diagnosis;
        [
            ("sold his shadow", "buried lede",
             "The strongest image of the piece opens it — do you want it spent in the first clause, or held?"),
            ("quiet thing", "ambiguous shorthand",
             "'quiet' reads as calm here, not silent — are you sure the reader lands where you mean?"),
            ("dogs had begun to growl", "vague mechanism",
             "the four 'There was' sentences are doing the work of the 'but also' — do you want the reader to feel that strain, or is it leaking?"),
            ("children, who notice everything", "telling not showing",
             "'not only' promises a 'but also' the list never grammatically completes — is the incompletion intentional?"),
        ]
        .into_iter()
        .map(|(q, p, query)| Diagnosis {
            quote: q.into(),
            problem: p.into(),
            query: query.into(),
            level: "line".into(),
        })
        .collect()
    }

    /// Rig hook (`resolve:first`): resolve the first open note through the
    /// real `set_note_status` path — instant model commit, exit-fade ghost —
    /// without depending on the done-button's pixel position (the button's
    /// hit-test is ordinary gpui listener machinery the click checks already
    /// cover; the class under test here is the ghost lifecycle).
    pub fn debug_resolve_first(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let first = self.doc.notes().open().next().map(|n| n.id);
        if let Some(id) = first {
            self.set_note_status(id, NoteStatus::Done, window, cx);
        }
    }

    /// Rig hook (`resolve:last`): resolve the NEWEST open note. In a crowded
    /// seeded lane that is the bottom full-size card — resolving it frees a
    /// budget slot, a receded card expands, and the run below shifts: the
    /// deterministic re-pack the motion checks need. (resolve:first hits the
    /// oldest card, already receded to a one-liner at its own anchor — its
    /// departure legitimately moves nothing.)
    pub fn debug_resolve_last(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let last = self.doc.notes().open().last().map(|n| n.id);
        if let Some(id) = last {
            self.set_note_status(id, NoteStatus::Done, window, cx);
        }
    }

    /// Rig hook (`seed:aside`): a fixture with BOTH piles — Scraps (one
    /// parked item, at the TAIL now) and a graveyard (one filed cut).
    /// Replaces the doc so the geometry is deterministic, then drives the
    /// real verbs.
    pub fn debug_seed_aside(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let len = self.doc.len_bytes();
        self.doc.edit_bytes(
            0..len,
            "A scrap note to keep for later.\nThe manuscript opens here with its real first line.\nAnd a second manuscript sentence long enough — comfortably over the eighty-character graveyard cut threshold — to file automatically.",
        );
        self.sync_mutations();
        self.word_count = self.manuscript_word_count();
        // Park the first paragraph → births the seam at the tail.
        let end0 = self.doc.rope().line_to_byte(1).saturating_sub(1);
        self.selected_range = 0..end0;
        self.set_aside(&SetAside, window, cx);
        // Send the LAST MANUSCRIPT paragraph (well over the threshold) → a
        // graveyard entry. After the flip the pile trails the manuscript, so
        // the exile target is the manuscript's last block, not the doc's.
        let m = self.doc.manuscript_char_range();
        let end = self.doc.char_to_byte(m.end);
        let last_line = self.doc.rope().byte_to_line(end.saturating_sub(1));
        let start = self.doc.rope().line_to_byte(last_line);
        self.selected_range = start..end;
        self.send_to_graveyard(&SendToGraveyard, window, cx);
        cx.notify();
    }

    /// Rig hook (`seed:demo`): a rich Scraps fixture for the visual rig —
    /// the manuscript FIRST, then three scraps at the tail (separators +
    /// seam mark), and two graveyard entries: an older short one (receded)
    /// and a newest multi-paragraph one (rendered full).
    pub fn debug_seed_demo(&mut self, cx: &mut Context<Self>) {
        let len = self.doc.len_bytes();
        // The manuscript (blocks 0..4), the seam (block 4), then three
        // scraps separated by blank lines. Building it directly keeps the
        // fixture deterministic.
        self.doc.edit_bytes(
            0..len,
            "Mara took the night crossing because the day boats were full of people who still believed the far shore existed.\nThe stowaway appeared on the third night, casting two shadows in the single running light.\nThe dockmaster's daughter kept a ledger of everything the river had taken.\nThe customs officer had a theory about the fog, and he told it to anyone who would listen: that it was the river forgetting its banks, one memory at a time.\n\nPremise B (dead): generation ship, mutiny in cold storage.\n\nENDING \u{2014} she stays; the ferry leaves without her, and the light on the water is the last line.\n\n\u{201C}Salt on the railing like the river had been chewing it.\u{201D}\n\nHe had charts. He had dates. Nobody would ever listen to a word of it.",
        );
        self.doc.set_scrap_line(Some(4)); // blocks 5.. = the Scraps pile
        self.sync_mutations();
        // File two cuts from the manuscript: an older short one (recedes
        // once a newer arrives), then the newest one (renders full).
        self.debug_cut_substring("The dockmaster's daughter kept a ledger of everything the river had taken.", cx);
        self.debug_cut_substring(
            "The customs officer had a theory about the fog, and he told it to anyone who would listen: that it was the river forgetting its banks, one memory at a time.",
            cx,
        );
        self.word_count = self.manuscript_word_count();
        cx.notify();
    }

    /// Rig fixtures for the space rail: a long structured document with a
    /// real Scraps seam, a long markless document, or a short markless page.
    pub fn debug_seed_scrollbar(&mut self, mode: &str, cx: &mut Context<Self>) {
        let count = if mode == "short" { 3 } else { 90 };
        let mut lines = Vec::with_capacity(count);
        let mut kinds = vec![BlockKind::Paragraph; count];
        for ix in 0..count {
            lines.push(format!("Rail fixture paragraph {ix}: rendered lines make position honest."));
        }
        if mode == "long" {
            for (ix, kind, label) in [
                (0, BlockKind::Heading(1), "The first crossing"),
                (12, BlockKind::Heading(2), "Soundings"),
                (25, BlockKind::Divider, "⁂"),
                (42, BlockKind::Heading(1), "The far bank"),
                (55, BlockKind::Heading(2), "Night water"),
                (72, BlockKind::Heading(2), "Unplaced ending"),
                (80, BlockKind::Divider, "⁂"),
            ] {
                kinds[ix] = kind;
                lines[ix] = label.into();
            }
        }
        let text = lines.join("\n");
        self.doc.restore_state(&text, SpanSet::default(), BlockMap::from_kinds(kinds));
        if mode == "long" {
            self.doc.set_scrap_line(Some(68));
        }
        self.selected_range = 0..0;
        self.scroll_top = px(0.);
        self.sync_mutations();
        self.word_count = self.manuscript_word_count();
        cx.notify();
    }

    pub fn debug_space_drag(&mut self, fraction: f32, cx: &mut Context<Self>) {
        let Some(frame) = self.last_frame.as_ref() else { return };
        self.scroll_top = frame.max_scroll() * fraction.clamp(0., 1.);
        self.space_readout_fade = None;
        self.space_drag_offset = Some(SPACE_THUMB_MIN_H / 2.);
        cx.notify();
    }

    /// Rig hook (`seed:topera`): rebuild the LIVE doc in the SHIPPED
    /// compost-at-top shape and save — so the NEXT launch of this same file
    /// exercises the one-time migration against a real store. The direct
    /// boundary install mimics what an old build persisted; migration ran
    /// at open (before smoke keys), so the live doc is boundary-less here.
    pub fn debug_seed_top_era(&mut self, cx: &mut Context<Self>) {
        let len = self.doc.len_bytes();
        self.doc.edit_bytes(
            0..len,
            "an old compost thought kept at the top\n\nthe manuscript proper begins here",
        );
        self.doc.set_aside_boundary(Some(1));
        self.sync_mutations();
        self.word_count = self.manuscript_word_count();
        let _ = self.save_now();
        cx.notify();
    }

    /// Cut the first occurrence of `needle` into the graveyard (rig helper;
    /// the deliberate form — collapses an emptied pile like the verb does).
    fn debug_cut_substring(&mut self, needle: &str, cx: &mut Context<Self>) {
        let text = self.doc.text();
        if let Some(byte) = text.find(needle) {
            self.file_cut(byte..byte + needle.len(), true, false, cx);
        }
    }

    /// Rig hook (`seed:image`, inline-images §11): the rig's first way to
    /// SEE pictures. Built through the real verbs — `put_asset`,
    /// `insert_image_block`, then TYPING into the block's own line (§10:
    /// the line IS the caption) — never by hand-assembling block state.
    /// Three stills in one document: a captioned picture (the caption
    /// wraps, so the centered multi-line face shows), a tall portrait
    /// (the two-thirds-viewport cap), and its EMPTY caption slot (no
    /// chrome, but the click band under the pixels answers).
    pub fn debug_seed_image(&mut self, cx: &mut Context<Self>) {
        let Some(store) = &self.store else {
            eprintln!("strop: seed:image needs a store-backed document");
            return;
        };
        // Deterministic gradients — no assets on disk, no decoder deps.
        let wide = store.put_asset(
            debug_png(640, 360, |x, y| {
                [(x / 3) as u8, 96u8.saturating_add((y / 3) as u8), 140]
            }),
            "png",
        );
        let tall = store.put_asset(
            debug_png(300, 1800, |x, y| {
                [180, (y / 8) as u8, 80u8.saturating_add((x / 2) as u8)]
            }),
            "png",
        );
        let len = self.doc.len_bytes();
        self.doc.edit_bytes(
            0..len,
            "A paragraph of ordinary prose stands above the picture, so the wall between text and furniture is visible in one frame.",
        );
        // The captioned picture: insert, then type the caption into the
        // image block's line — long enough to wrap at the measure.
        let caret = self.doc.len_bytes();
        let after_wide = self.doc.insert_image_block(caret, wide);
        let img_block = self.doc.rope().byte_to_line(after_wide) - 1;
        let cap_at = self.doc.rope().line_to_byte(img_block);
        self.doc.edit_bytes(
            cap_at..cap_at,
            "The night crossing, seen from the pier \u{2014} the caption is the block's own line, quieter than body, and it wraps like any prose when it runs long.",
        );
        // Prose between the pictures, then the tall one — caption left
        // EMPTY on purpose (the birth state of every inserted image).
        let end = self.doc.len_bytes();
        self.doc.edit_bytes(
            end..end,
            "Between the pictures the manuscript keeps its voice; the tall portrait below must cap at two-thirds of the viewport instead of swallowing the page.",
        );
        let caret2 = self.doc.len_bytes();
        let _ = self.doc.insert_image_block(caret2, tall);
        self.sync_mutations();
        self.word_count = self.manuscript_word_count();
        cx.notify();
    }

    /// Rig hook (`seed:imgrepro`): the FIELD REPRO of the round's origin
    /// bug, exactly — an EMPTY paragraph, a captioned picture, a prose
    /// paragraph below (inline-images §11's acceptance shape). From here
    /// the script drives the doors: Delete at the empty block above must
    /// STAGE (never fuse), a held Backspace from the prose below must stop
    /// at the stage, Enter in the caption must never duplicate the picture.
    pub fn debug_seed_image_repro(&mut self, cx: &mut Context<Self>) {
        let Some(store) = &self.store else {
            eprintln!("strop: seed:imgrepro needs a store-backed document");
            return;
        };
        let src = store.put_asset(
            debug_png(640, 360, |x, y| {
                [200u8.saturating_sub((y / 4) as u8), (x / 4) as u8, 96]
            }),
            "png",
        );
        let len = self.doc.len_bytes();
        self.doc.edit_bytes(
            0..len,
            "\nAfter the picture the prose paragraph carries on with enough words for a held backspace to walk through before it reaches the wall.",
        );
        // Insert after the empty block 0, then type the caption into the
        // image block's own line — the real verbs, as ever.
        let after = self.doc.insert_image_block(0, src);
        let img_block = self.doc.rope().byte_to_line(after) - 1;
        let cap_at = self.doc.rope().line_to_byte(img_block);
        self.doc.edit_bytes(cap_at..cap_at, "Down to the pier at dusk");
        self.sync_mutations();
        self.word_count = self.manuscript_word_count();
        // Caret parked in the prose below, the repro's starting stance.
        let caret = self.doc.len_bytes();
        self.selected_range = caret..caret;
        self.selection_reversed = false;
        cx.notify();
    }

    /// Rig hook (`img-geo`): every image block's pixel rect and caption
    /// line, WINDOW coords, so the script can aim clicks at the pixels
    /// (`click:X,Y`) and at the caption without guessing geometry.
    pub fn debug_images(&self) -> String {
        let Some(frame) = self.last_frame.as_ref() else {
            return "no-frame".into();
        };
        let origin = frame.bounds.origin;
        let mut out = String::new();
        for (ix, kind) in self.doc.blocks().kinds().iter().enumerate() {
            let BlockKind::Image { src, .. } = kind else { continue };
            let Some(par) = frame.paragraphs.get(ix) else { continue };
            let (w, h) = par
                .image
                .as_ref()
                .map(|(_, sz)| (f32::from(sz.width), f32::from(sz.height)))
                .unwrap_or((0., 0.));
            let img_x = f32::from(par.indent)
                + ((f32::from(frame.bounds.size.width) - f32::from(par.indent) - w) / 2.)
                    .max(0.);
            let top = f32::from(par.top - frame.scroll_top);
            // `src` rides along so the rig can assert content addressing:
            // a pasted copy resolves to the SAME asset id, never a twin.
            out += &format!(
                "img {ix} @{:.0},{:.0} w={w:.0} h={h:.0} cap@{:.0},{:.0} src={src}\n",
                f32::from(origin.x) + img_x + w / 2.,
                f32::from(origin.y) + top + h / 2.,
                f32::from(origin.x) + f32::from(par.indent)
                    + f32::from(frame.bounds.size.width - par.indent) / 2.,
                f32::from(origin.y) + top + f32::from(par.text_top)
                    + f32::from(par.line_height) / 2.,
            );
        }
        out
    }

    /// Rig hook (`seed:annotated`): a manuscript whose SECOND paragraph carries
    /// BOTH a writer note and a machine diagnosis, anchored inside it, and is
    /// selected — ready for `exile:selection`. After the cut the writer note
    /// must migrate to the compost (open_notes drops, compost_blocks rises) and
    /// the diagnosis must close (open_diagnoses drops) — Bug C, the dangling
    /// note the user hit on a real document.
    pub fn debug_seed_annotated(&mut self, cx: &mut Context<Self>) {
        let len = self.doc.len_bytes();
        self.doc.edit_bytes(
            0..len,
            "Keep this opening paragraph as the manuscript's real first line.\nThis whole annotated paragraph runs comfortably past the eighty-character graveyard threshold and carries the writer's own margin note plus a machine diagnosis, each anchored inside it.",
        );
        self.sync_mutations();
        let para_start = self.doc.rope().line_to_byte(1);
        let s = self.doc.rope().byte_to_char(para_start);
        // The writer's own note (migrates to the compost when its anchor dies).
        self.doc
            .add_note(s..s + 4, "does this paragraph earn its keep?".into(), now_unix());
        // A machine diagnosis on a different slice of the same paragraph (closes
        // — a machine card never lingers pointing at nothing).
        self.doc.add_diagnoses(vec![Annotation {
            id: 0,
            range: (s + 6)..(s + 11),
            body: "flabby line".into(),
            status: NoteStatus::Open,
            created_unix: now_unix(),
            kind: NoteKind::Diagnosis,
            title: "flabby".into(),
            level: "line".into(),
            orphaned: false,
            pass_id: 1,
            unverified: false,
        }]);
        // Select the annotated paragraph, ready for exile.
        self.selected_range = para_start..self.doc.len_bytes();
        self.selection_reversed = false;
        self.word_count = self.manuscript_word_count();
        self.mark_dirty();
        cx.notify();
    }

    /// Rig hook (`seed:mockup1|2|3`): the Gate-2 fidelity fixture — the
    /// mockup's Sourdough scenes (docs/mockups/scraps-tail-2026-07.html)
    /// built through the REAL verbs: one selection park (so the first scrap
    /// carries provenance), typed scraps appended into the pile, one exile.
    /// Scene 1 rests the caret inside the parked scrap (the provenance
    /// one-liner after its delay); scene 2 parks the caret at the
    /// "grandmother" paragraph for the selection-menu still; scene 3 grows
    /// the pile (so the graveyard drops below the fold) and rests the caret
    /// at the title-candidates scrap, typing-in-the-pile style.
    pub fn debug_seed_mockup(&mut self, scene: u8, window: &mut Window, cx: &mut Context<Self>) {
        let len = self.doc.len_bytes();
        self.doc.edit_bytes(
            0..len,
            "The starter is older than my marriage and considerably more reliable. It has crossed two borders in a jam jar, wrapped in a sock, declared to no customs officer.\nMy grandmother would have said that bread rises on grief, which is the kind of sentence that sounds wise until you try to bake with it.\nFlour, water, salt, patience \u{2014} everyone recites the litany, and everyone lies about the fourth.\n\u{2026}and that is the whole secret: the loaf was never the point. The kitchen at six in the morning, the windows still black, the radio murmuring to itself \u{2014} that was the point, and the bread merely proved I had been there.\nThe neighbour's dog knows the smell of the starter and sits by my door on Fridays. Cut this, but the dog might open the next essay.\nThere was a longer version of this morning, with the neighbour, the dog, and a whole paragraph about the milkman that never earned its keep.",
        );
        self.sync_mutations();
        if scene == 2 {
            // Scene 2's piece runs long (the mockup's 1,842-word essay): the
            // tail drops below the fold, so BOTH chips stand at the foot.
            let after_c = self.doc.text().find("\u{2026}and that is").expect("fixture text");
            self.doc.edit_bytes(
                after_c..after_c,
                "The first loaf of the week is a rehearsal, and we both know it; the oven forgives on Mondays what it will not forgive on Sundays.\nI have read that sourdough cultures carry the fingerprint of their kitchen, which would make mine a biography I never agreed to write.\nThe scale broke in March and the bread got better, which is either a lesson about instruments or a lesson about me, and I am not ready to know which.\nA neighbour once asked for a cup of the starter the way you would ask for a cup of sugar, and I have never felt so surveilled in my life.\nThere is a version of this essay that is only about the window above the sink, and some mornings I am writing that one instead.\n",
            );
            self.sync_mutations();
        }
        // Park the dog paragraph through the real verb (provenance + receipt).
        let text = self.doc.text();
        let dog = text.find("The neighbour's dog").expect("fixture text");
        let (ds, de) = self.paragraph_bounds(dog);
        self.selected_range = ds..de;
        self.selection_reversed = false;
        self.set_aside(&SetAside, window, cx);
        // Two idea scraps, as typed-into-the-pile text (blank-line items).
        let tail = self.doc.len_bytes();
        self.doc.edit_bytes(
            tail..tail,
            "\n\nwhat if the middle section runs backwards \u{2014} start with the burnt loaf, end with the flour bag unopened\n\ntitle candidates: Proof. / Crumb. / What the Oven Keeps.",
        );
        self.sync_mutations();
        if scene == 3 {
            // Scene 3's pile is deep enough that the record drops below the
            // fold — the drained Graveyard chip is the frame's one chip.
            let tail = self.doc.len_bytes();
            self.doc.edit_bytes(
                tail..tail,
                "\n\nthe milkman detour could be its own piece \u{2014} three hundred words about the glass bottles nobody collects any more\n\nthe oven door hinge squeals in the same key as the gate; find out if that is a paragraph or a coincidence\n\ndoes the reader need the recipe at all, or is the recipe the part the piece exists to refuse\n\nbread as a clock: the whole essay told in rise times, nothing else allowed to mark the hours",
            );
            self.sync_mutations();
        }
        // Exile the milkman paragraph (the record's one entry).
        let text = self.doc.text();
        let milk = text.find("There was a longer version").expect("fixture text");
        let (ms, me) = self.paragraph_bounds(milk);
        // Take the leading newline so no empty block strands above the seam.
        self.file_cut(ms.saturating_sub(1)..me, true, false, cx);
        self.word_count = self.manuscript_word_count();
        // Scene carets.
        let text = self.doc.text();
        match scene {
            2 => {
                let b = text.find("My grandmother").expect("fixture text");
                self.set_cursor(b, false, cx);
            }
            3 => {
                let t = text.find("What the Oven Keeps.").expect("fixture text");
                self.set_cursor(t + "What the Oven Keeps.".len(), false, cx);
            }
            _ => {
                let c = text.find("Cut this").expect("fixture text");
                self.set_cursor(c, false, cx);
            }
        }
        cx.notify();
    }

    /// Rig hook (`move:manuscript`): select the caret's paragraph in the
    /// pile and run the retrieval verb — the flank row's path without pixel
    /// coordinates. The landed range arrives SELECTED (the rig asserts sel).
    pub fn debug_move_to_manuscript(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        let (start, end) = self.paragraph_bounds(self.cursor_offset());
        if start >= end {
            return;
        }
        self.selected_range = start..end;
        self.selection_reversed = false;
        self.move_to_manuscript(&MoveToManuscript, window, cx);
    }

    /// Rig hook (`putback:scrap`): the provenance line's Put back at the
    /// caret's record, without pixel coordinates.
    pub fn debug_put_back_scrap(&mut self, window: &mut Window, cx: &mut Context<Self>) {
        self.put_back_scrap(&PutBackScrap, window, cx);
    }

    /// Rig hook (`select:para`, docs/impl/03-flanks.md §3): select the caret's
    /// paragraph deterministically AND force it PAST the settle beat, so the dump
    /// observes a settled selection without waiting out the 250 ms timer. Under
    /// LAW 1 the flanks are DERIVED (`flanks_visible`): a settled non-empty
    /// selection with prose focus, no field open, and no latch — which is exactly
    /// the state this leaves. (Was: a mouse-up-only `selection_popover` flag.)
    pub fn debug_select_para(&mut self, cx: &mut Context<Self>) {
        let (start, end) = self.paragraph_bounds(self.cursor_offset());
        if start >= end {
            return;
        }
        self.selected_range = start..end;
        self.selection_reversed = false;
        self.is_selecting = false;
        self.flank_latched = false;
        self.flank_settle = None;
        self.flank_sel = self.selected_range.clone();
        self.flank_risen = true;
        cx.notify();
    }

    /// Rig hook (`select:kbd`): a KEYBOARD selection (shift+right ×n over the
    /// caret's paragraph) driven through the real `extend_cursor` path, then
    /// forced past the settle beat — the proof that keyboard selections raise the
    /// flanks exactly like mouse ones (LAW 1 / A1).
    pub fn debug_select_kbd(&mut self, cx: &mut Context<Self>) {
        let (start, end) = self.paragraph_bounds(self.cursor_offset());
        if start >= end {
            return;
        }
        self.set_cursor(start, false, cx); // collapse to the paragraph start
        while self.cursor_offset() < end {
            let next = self.next_boundary(self.cursor_offset());
            if next <= self.cursor_offset() {
                break;
            }
            self.select_to(next, cx); // extend_cursor → on_selection_moved (the keyboard path)
        }
        // The settle beat is async; force it here so the headless dump can see
        // the post-settle state the timer would have produced.
        if !self.selected_range.is_empty() {
            self.flank_risen = true;
            self.flank_settle = None;
        }
        cx.notify();
    }

