    #[test]
    fn stale_cuts_snap_to_char_boundaries() {
        // The history-preview hazard: an offset from ANOTHER text (the live
        // caret, a stale selection) injected as a run cut into multibyte
        // text. Every cut must snap back to a char boundary of THIS text —
        // the runs partition the paragraph and shaping never sees a torn
        // char. "привет" is 6 chars × 2 bytes; 3 and 7 are mid-char.
        let text = "привет";
        let par = 0..text.len();
        let check = |runs: &[TextRun]| {
            let mut at = 0usize;
            for run in runs {
                assert!(text.is_char_boundary(at), "run cut mid-char at {at}");
                at += run.len;
            }
            assert_eq!(at, text.len(), "runs must cover the paragraph");
        };
        // A collapsed caret off-boundary (the parked live caret's shape).
        check(&runs_for_paragraph(&par, text, &(3..3), None, &[], &[], &[], &[], &base()));
        // A non-empty stale selection, both ends mid-char.
        check(&runs_for_paragraph(&par, text, &(3..7), None, &[], &[], &[], &[], &base()));
        // Beyond the paragraph entirely.
        check(&runs_for_paragraph(&par, text, &(15..40), None, &[], &[], &[], &[], &base()));
    }

    #[test]
    fn word_motion_survives_long_blank_run() {
        // A pathological run of empty paragraphs must not blow the stack: word
        // motion has to iterate, not recurse one frame per line. (Recursive,
        // this overflows the 2 MB test-thread stack and aborts the binary.)
        let n = 200_000;

        let mut text = String::with_capacity(n + 4);
        for _ in 0..n {
            text.push('\n');
        }
        text.push_str("word");
        let doc = Document::new(&text, SpanSet::default(), BlockMap::default());
        assert_eq!(previous_word_boundary(&doc, n), 0);

        let mut text2 = String::with_capacity(n + 4);
        text2.push_str("word");
        for _ in 0..n {
            text2.push('\n');
        }
        let doc2 = Document::new(&text2, SpanSet::default(), BlockMap::default());
        let len = doc2.len_bytes();
        assert_eq!(next_word_boundary(&doc2, 0), 4); // selects "word"
        assert_eq!(next_word_boundary(&doc2, 4), len); // blank run -> doc end
    }

